-- Poems batch 175
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('7a1f2063-7da5-42bd-90be-b5253c39a5b6','送客至無相蘭若歸過慈雲嶺小憩崇壽寺書所見十首  其二','張鎡','宋','宋诗','song-poetry','','[]','野香別是一般風，驀直平岡好翠松。',32,'全唐诗/poet.song.171000.json','["野香別是一般風，驀直平岡好翠松。", "更許虛空畫山水，細鋪霞浪襯雲峰。"]'),
('c3cec474-621c-4da1-8a9a-9eabb81972dc','送客至無相蘭若歸過慈雲嶺小憩崇壽寺書所見十首  其三','張鎡','宋','宋诗','song-poetry','','[]','山腰路轉湧蒼蛇，山下修筠媚白沙。',32,'全唐诗/poet.song.171000.json','["山腰路轉湧蒼蛇，山下修筠媚白沙。", "正要澄江舒倦眼，莫教緣岸有人家。"]'),
('d5f3e678-a1cf-4a5e-8f2f-87c79794f148','送客至無相蘭若歸過慈雲嶺小憩崇壽寺書所見十首  其四','張鎡','宋','宋诗','song-poetry','','[]','嶺度慈雲境累凉，前看湖面後看江。',32,'全唐诗/poet.song.171000.json','["嶺度慈雲境累凉，前看湖面後看江。", "詩魔半餉難調伏，除是休來却易降。"]'),
('ab7b571a-e2c9-4122-97ff-9ab369491dea','送客至無相蘭若歸過慈雲嶺小憩崇壽寺書所見十首  其五','張鎡','宋','宋诗','song-poetry','','[]','南山好處劉家寺，門裏松篁一逕衝。',32,'全唐诗/poet.song.171000.json','["南山好處劉家寺，門裏松篁一逕衝。", "自有禽聲喜迎客，不須知事更鳴鐘。"]'),
('d4b5c052-3700-4632-85d6-3b604948ecb3','送客至無相蘭若歸過慈雲嶺小憩崇壽寺書所見十首  其六','張鎡','宋','宋诗','song-poetry','','[]','老僧分袂倏三年，猶訪芳池躍翠泉。',32,'全唐诗/poet.song.171000.json','["老僧分袂倏三年，猶訪芳池躍翠泉。", "新疊兩山都未識，北堂引看更東偏。"]'),
('0d325ef6-cf4d-4441-ba1b-a1c86313022b','送客至無相蘭若歸過慈雲嶺小憩崇壽寺書所見十首  其七','張鎡','宋','宋诗','song-poetry','','[]','支徑坡陀竹最多，籜龍纔起更成窠。',32,'全唐诗/poet.song.171000.json','["支徑坡陀竹最多，籜龍纔起更成窠。", "穿嵐觸翠坳塘出，一片香來得嫩荷。"]'),
('50fe144c-931c-4ed3-922d-b396f7ec8205','送客至無相蘭若歸過慈雲嶺小憩崇壽寺書所見十首  其八','張鎡','宋','宋诗','song-poetry','','[]','井分泉脈透巉巖，誰道飛流是假山。',32,'全唐诗/poet.song.171000.json','["井分泉脈透巉巖，誰道飛流是假山。", "水鳥樹林皆作供，可憐居士只偷閒。"]'),
('cb5f58a6-b778-4956-bdd2-b791997dabe0','送客至無相蘭若歸過慈雲嶺小憩崇壽寺書所見十首  其九','張鎡','宋','宋诗','song-poetry','','[]','亭橋兩面看芙蕖，靜數波間小隊魚。',32,'全唐诗/poet.song.171000.json','["亭橋兩面看芙蕖，靜數波間小隊魚。", "碧幛彎環遮去路，凈天終待此同居。"]'),
('a9fafdc6-4fcb-4bd2-b76c-9a474cf192b9','送客至無相蘭若歸過慈雲嶺小憩崇壽寺書所見十首  其一○','張鎡','宋','宋诗','song-poetry','','[]','欲歸停馭重徘徊，破費林間雪一杯。',32,'全唐诗/poet.song.171000.json','["欲歸停馭重徘徊，破費林間雪一杯。", "留取半山看未了，火雲時節約重來。"]'),
('1a5d3d89-4b76-40be-9998-0cb02eea4a81','過楓橋寺','張鎡','宋','宋诗','song-poetry','','[]','妙絕吾宗有舊題，趁晴逕過敢留詩。',32,'全唐诗/poet.song.171000.json','["妙絕吾宗有舊題，趁晴逕過敢留詩。", "只消記取今朝景，不是烏啼月落時。"]'),
('4eb9c873-e918-4e05-9cea-623abc0dc624','聽琵琶','張鎡','宋','宋诗','song-poetry','','[]','四絃么鳳雜雛鶑，不作商船塞路聲。',32,'全唐诗/poet.song.171000.json','["四絃么鳳雜雛鶑，不作商船塞路聲。", "花影透簾清晝夜，細將攏撚說多情。"]'),
('877bea20-ce51-42a7-82ef-9c95a4237905','紹興間國工胡偉琵琶擅稱一時其徒豪興得胡心傳之妙今年七十二清健伎益精從容話故都事使人感歎因書小詩與之','張鎡','宋','宋诗','song-poetry','','[]','半生繁會想梨園，醒耳秋風鳳語絃。',32,'全唐诗/poet.song.171000.json','["半生繁會想梨園，醒耳秋風鳳語絃。", "我亦秦關歸未暇，故都休說汴河邊。"]'),
('6463b2ba-3d1b-4b39-bad3-187ddd698d45','許道士房','張鎡','宋','宋诗','song-poetry','','[]','凉蟬亂叫朝暮雨，獨鶴不迷前後山。',32,'全唐诗/poet.song.171000.json','["凉蟬亂叫朝暮雨，獨鶴不迷前後山。", "芎葉煮湯勝茗椀，栗花然火稱松關。"]'),
('c813fddf-48a6-4a0a-9d32-e76945fc0342','得家書  其一','張鎡','宋','宋诗','song-poetry','','[]','北堂萱獨雁行疎，旅夢通宵只敝廬。',32,'全唐诗/poet.song.171000.json','["北堂萱獨雁行疎，旅夢通宵只敝廬。", "未暇拆封忙喚僕，先將安否問何如。"]'),
('46fcee06-9a3f-40bb-81f3-6f9b3f3ba8b3','得家書  其二','張鎡','宋','宋诗','song-poetry','','[]','玉塞金河阻去程，醉中嘗夢賦西征。',32,'全唐诗/poet.song.171000.json','["玉塞金河阻去程，醉中嘗夢賦西征。", "天時不與人心合，獨守寒窗數鴈聲。"]'),
('807d7ff0-e406-4379-991e-390b06abcd51','得家書  其三','張鎡','宋','宋诗','song-poetry','','[]','風沙來往稻粱謀，江北江南一歲遒。',32,'全唐诗/poet.song.171000.json','["風沙來往稻粱謀，江北江南一歲遒。", "非爲紅樓斷消息，待梅暗候自清愁。"]'),
('9c08ddd6-8118-4de2-8325-bb0048fe8f14','雨中聞雁','張鎡','宋','宋诗','song-poetry','','[]','小雨終朝濕翠霏，渚蒲汀樹白瀰瀰。',32,'全唐诗/poet.song.171000.json','["小雨終朝濕翠霏，渚蒲汀樹白瀰瀰。", "若嫌鳴雁無厭足，回到潮州又索詩。"]'),
('ddb552fe-95e5-4755-882d-7d5757220b7c','看鴈','張鎡','宋','宋诗','song-poetry','','[]','曉晴羣鴈欲何之，正是青天似紙時。',32,'全唐诗/poet.song.171000.json','["曉晴羣鴈欲何之，正是青天似紙時。", "橫斜數行有聲字，服殺虛空解作詩。"]'),
('3b765f2f-acc9-485e-b034-c532f0dc157f','張以道歸自甬東先餉土物兩詩爲謝  其一','張鎡','宋','宋诗','song-poetry','','[]','梨柿魚鹽來海上，殷勤持送與閒官。',32,'全唐诗/poet.song.171000.json','["梨柿魚鹽來海上，殷勤持送與閒官。", "緣何似得千金贈，明日重親語笑歡。"]'),
('aa0e828a-b219-46d4-9e9a-b1546151bc86','張以道歸自甬東先餉土物兩詩爲謝  其二','張鎡','宋','宋诗','song-poetry','','[]','紅滿芙蓉菊滿黄，連朝衰病負秋光。',32,'全唐诗/poet.song.171000.json','["紅滿芙蓉菊滿黄，連朝衰病負秋光。", "乘除自此無憂惱，醉賞家園一萬場。"]'),
('c98f7ca6-459b-4b29-9de3-66d81c4b8806','夜坐因觀楊伯虎和春字韵詩偶成五絕再寄  其一','張鎡','宋','宋诗','song-poetry','','[]','挑盡燈花夜未眠，清寒渾忘是春天。',32,'全唐诗/poet.song.171000.json','["挑盡燈花夜未眠，清寒渾忘是春天。", "霜侵綠鬢張居士，空坐書幃三十年。"]'),
('58373bc8-aefd-4c37-8a0d-a72f9e2418ab','夜坐因觀楊伯虎和春字韵詩偶成五絕再寄  其二','張鎡','宋','宋诗','song-poetry','','[]','案上因翻簡鐵堆，親朋何日和詩回。',32,'全唐诗/poet.song.171000.json','["案上因翻簡鐵堆，親朋何日和詩回。", "高懷剩得清閒力，滿紙溪山秀色開。"]'),
('20e56db3-6d15-4afa-b804-89a1db2bceaa','夜坐因觀楊伯虎和春字韵詩偶成五絕再寄  其三','張鎡','宋','宋诗','song-poetry','','[]','往事追思重慘傷，相從常醉德勳堂。',32,'全唐诗/poet.song.171000.json','["往事追思重慘傷，相從常醉德勳堂。", "每登屺岵數鴻鴈，老淚風前必數行。"]'),
('4d22e84e-9216-46dc-8ed5-3cde313ec59c','夜坐因觀楊伯虎和春字韵詩偶成五絕再寄  其四','張鎡','宋','宋诗','song-poetry','','[]','宦情儂自本來無，君亦琳宮暫逸居。',32,'全唐诗/poet.song.171000.json','["宦情儂自本來無，君亦琳宮暫逸居。", "西華武夷俱絕勝，可教詩卷此時疎。"]'),
('c8466c7e-13dc-456b-882e-08650539f604','夜坐因觀楊伯虎和春字韵詩偶成五絕再寄  其五','張鎡','宋','宋诗','song-poetry','','[]','苕霅從來著志和，子雲寧久占煙波。',32,'全唐诗/poet.song.171000.json','["苕霅從來著志和，子雲寧久占煙波。", "速歸逕上清班好，時過南湖伴浩歌。"]'),
('dbc8f2c1-89a0-4594-b805-2fbcfdc43630','春日','張鎡','宋','宋诗','song-poetry','','[]','銀葉煎香細雨聲，竹陰行處藥花明。',32,'全唐诗/poet.song.171000.json','["銀葉煎香細雨聲，竹陰行處藥花明。", "麥光小楷臨唐帖，更有人間第一清。"]'),
('cdb3c163-41d7-4f8b-9f3a-622a659803d7','寒食前一日西湖閒泛三首  其一','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','艷紅香白徧遊人，花柳酣歌識太平。',32,'全唐诗/poet.song.171000.json','["艷紅香白徧遊人，花柳酣歌識太平。", "野客獨諳閒意趣，草煙空愛一川明。"]'),
('27af918d-8622-4fae-ba80-afe9d40bb126','寒食前一日西湖閒泛三首  其二','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','驟暖懸知雨信濃，半陰臺榭碧烘濛。',32,'全唐诗/poet.song.171000.json','["驟暖懸知雨信濃，半陰臺榭碧烘濛。", "何心更敢携壺去，孤槳微吟尚未工。"]'),
('660964ae-925a-48ec-8406-aa986ccc7215','寒食前一日西湖閒泛三首  其三','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','衰鬢爭如竹際苔，秋千猶記玉驄回。',32,'全唐诗/poet.song.171000.json','["衰鬢爭如竹際苔，秋千猶記玉驄回。", "短籬數尺花成簇，一日春悰不往來。"]'),
('dfca1f10-0a50-4565-9f92-5ad704eb5a9c','春雲','張鎡','宋','宋诗','song-poetry','','[]','松邊寒彩過前山，松下鋪氈坐不還。',32,'全唐诗/poet.song.171000.json','["松邊寒彩過前山，松下鋪氈坐不還。", "澤物爲霖休自苦，且來相伴約齋閒。"]'),
('42d731f8-d1d4-45fc-a6a0-b878ac40ae8e','四月上澣日同寮約遊西湖十絕  其一','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','自得城隅水北居，西湖幽討句全疎。',32,'全唐诗/poet.song.171000.json','["自得城隅水北居，西湖幽討句全疎。", "今朝掩簿抽身出，更向誰邊不一書。"]'),
('c727a56b-9e85-455d-b434-fea5f955a907','四月上澣日同寮約遊西湖十絕  其二','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','清曉溟濛雨氣濃，出關晴色便葱蘢。',32,'全唐诗/poet.song.171000.json','["清曉溟濛雨氣濃，出關晴色便葱蘢。", "層雲特爲詩人喜，添起山頭四五峰。"]'),
('15830c1c-dc2c-4b06-ab34-c1173568cf4a','四月上澣日同寮約遊西湖十絕  其三','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','賣龜船小漾漪漣，折得蘋花亦當錢。',32,'全唐诗/poet.song.171000.json','["賣龜船小漾漪漣，折得蘋花亦當錢。", "我自滄洲隔三載，此花風調只依然。"]'),
('d1312004-ed36-4348-bb1e-cd66ddcda0dd','四月上澣日同寮約遊西湖十絕  其四','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','飯餘飛蓋北山來，上苑虛堂柳際開。',32,'全唐诗/poet.song.171000.json','["飯餘飛蓋北山來，上苑虛堂柳際開。", "繫馬林間寧復散，却容拄杖卓青苔。"]'),
('80c0634a-55e4-43d4-9234-798c21c901e7','四月上澣日同寮約遊西湖十絕  其五','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','賜沐山行策最長，遊人此日却相妨。',32,'全唐诗/poet.song.171000.json','["賜沐山行策最長，遊人此日却相妨。", "洞天只得東邊賞，開過燈花斷殺腸。"]'),
('4fa2b6ea-43e2-4737-868e-b85921e81443','四月上澣日同寮約遊西湖十絕  其六','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夾堤全少露桃紅，獨許垂楊翠拂空。',32,'全唐诗/poet.song.171000.json','["夾堤全少露桃紅，獨許垂楊翠拂空。", "千古蘇仙幾曾死，騎鯨時或下亭中。"]'),
('5f099341-73fc-427c-a8ec-e88d4c41e532','四月上澣日同寮約遊西湖十絕  其七','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','茭葑茸茸展翠氈，六橋分舞燕翎纖。',32,'全唐诗/poet.song.171000.json','["茭葑茸茸展翠氈，六橋分舞燕翎纖。", "撐船捷出蒼灣去，要看山圍玉鏡奩。"]'),
('cc95e35e-f0e5-4a38-8ec1-1784f69d8aab','四月上澣日同寮約遊西湖十絕  其八','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','喜逐芻蕘禁苑東，舜絃調處剩薰風。',32,'全唐诗/poet.song.171000.json','["喜逐芻蕘禁苑東，舜絃調處剩薰風。", "戎葵學得宮衣纈，不作人間錦樣紅。"]'),
('1e27a03b-70d9-4b8d-914a-0a4d5d2eb56b','四月上澣日同寮約遊西湖十絕  其九','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寮寀招邀勝引多，曠懷真語當絃歌。',32,'全唐诗/poet.song.171000.json','["寮寀招邀勝引多，曠懷真語當絃歌。", "聯翩逸駕知難及，乞我扁舟著釣蓑。"]'),
('057881d8-7559-408a-afcc-4f9cc0add95e','四月上澣日同寮約遊西湖十絕  其一○','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','豐樂樓前未夕暉，可堪魚鑰限城扉。',32,'全唐诗/poet.song.171000.json','["豐樂樓前未夕暉，可堪魚鑰限城扉。", "詩成快向歸時寫，丹墨明朝與興違。"]'),
('95aec620-b6e7-4ebe-bd6c-4c2aaf91a14c','鷗渚亭次韵茂洪西湖三詩  其一','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','出城猶記四年前，朝看西湖到暮煙。',32,'全唐诗/poet.song.171000.json','["出城猶記四年前，朝看西湖到暮煙。", "自有南湖相暖熱，可曾頻過六橋邊。"]'),
('66d21c19-b390-4704-aca2-5935156e9bee','鷗渚亭次韵茂洪西湖三詩  其二','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老子看山今益工，只憐雲氣不憐峰。',32,'全唐诗/poet.song.171000.json','["老子看山今益工，只憐雲氣不憐峰。", "擡頭半餉無人說，自向波心汎短篷。"]'),
