('bc35e1a6-d488-4603-ae0e-65d5d0191c7e','玉照堂觀梅二十首  其二○','張鎡','宋','宋诗','song-poetry','','[]','高窠依約百年餘，蠹枿重重艾衲鋪。',32,'全唐诗/poet.song.171000.json','["高窠依約百年餘，蠹枿重重艾衲鋪。", "親見主人來買地，遮番添得白髭鬚。"]'),
('1fe9c886-30fc-4584-8ac0-cbbefb1fa0e0','詠千葉緗梅  其一','張鎡','宋','宋诗','song-poetry','','[]','巧留芳艷待春回，不受霜飈苦折摧。',32,'全唐诗/poet.song.171000.json','["巧留芳艷待春回，不受霜飈苦折摧。", "應對羣葩羞冷淡，數花併作一花開。"]'),
('5c7be5f8-d739-4c9f-93a9-a91651db0d8e','詠千葉緗梅  其二','張鎡','宋','宋诗','song-poetry','','[]','忍凍拖筇月下看，烟籠繁影共汗漫。',32,'全唐诗/poet.song.171000.json','["忍凍拖筇月下看，烟籠繁影共汗漫。", "緗裘不是多重數，爭奈清宵爾許寒。"]'),
('02805cbe-e4ca-461c-a2ad-bf0ccf28526e','詠千葉緗梅  其三','張鎡','宋','宋诗','song-poetry','','[]','一枝深雪綻前村，冷落猶能役夢魂。',32,'全唐诗/poet.song.171000.json','["一枝深雪綻前村，冷落猶能役夢魂。", "况有堆林春萬疊，傳餐甘此度朝昏。"]'),
('6fed9f73-27d4-48e7-b2e1-ee3a87fcd73e','詠千葉緗梅  其四','張鎡','宋','宋诗','song-poetry','','[]','光摇層蘂望晴花，誰把鵝黄染練紗。',32,'全唐诗/poet.song.171000.json','["光摇層蘂望晴花，誰把鵝黄染練紗。", "已是被香清到骨，不須呼酒但烹茶。"]'),
('9f2ea4ee-2ed5-46df-aa68-eed5d32daf0b','詠千葉緗梅  其五','張鎡','宋','宋诗','song-poetry','','[]','玉砌珠攢萼翠中，開時應是費東風。',32,'全唐诗/poet.song.171000.json','["玉砌珠攢萼翠中，開時應是費東風。", "臨摹不著詩人手，剪綵徒勞蠹女工。"]'),
('d5a053e1-9b4c-4713-b685-7568fd3bf96c','玉照東西兩軒有紅梅及千葉緗梅未經題詠倒用前韵各賦五首  其一','張鎡','宋','宋诗','song-poetry','','[]','昔遊嘗到海中光，我與諸公各醉狂。',32,'全唐诗/poet.song.171000.json','["昔遊嘗到海中光，我與諸公各醉狂。", "同向塵中三十載，朱顔應笑鬢絲長。"]'),
('ce9e9e40-76cd-4474-b812-d3d986b30c6e','玉照東西兩軒有紅梅及千葉緗梅未經題詠倒用前韵各賦五首  其二','張鎡','宋','宋诗','song-poetry','','[]','雖嫌綠葉與青枝，入格依前自欠詩。',32,'全唐诗/poet.song.171000.json','["雖嫌綠葉與青枝，入格依前自欠詩。", "幾向斜陽溪畔見，猶將桃杏誤猜疑。"]'),
('678ca394-44c4-4d4d-a438-324a9d39a0a4','玉照東西兩軒有紅梅及千葉緗梅未經題詠倒用前韵各賦五首  其三','張鎡','宋','宋诗','song-poetry','','[]','一粒丹砂換骨來，移根聞自浙東栽。',32,'全唐诗/poet.song.171000.json','["一粒丹砂換骨來，移根聞自浙東栽。", "市門古矣留遺跡，問訊仙翁定姓梅。"]'),
('47c26009-67d1-4172-a56d-7f385676af10','玉照東西兩軒有紅梅及千葉緗梅未經題詠倒用前韵各賦五首  其四','張鎡','宋','宋诗','song-poetry','','[]','海棠曾把比朝眠，妃子粧慵玉鏡前。',32,'全唐诗/poet.song.171000.json','["海棠曾把比朝眠，妃子粧慵玉鏡前。", "若似此花顔色好，定教天寶畫師傳。"]'),
('d559621e-7e4d-4802-b910-4b8a205f4158','玉照東西兩軒有紅梅及千葉緗梅未經題詠倒用前韵各賦五首  其五','張鎡','宋','宋诗','song-poetry','','[]','方諸臺聳日邊雲，望拜青童上相君。',32,'全唐诗/poet.song.171000.json','["方諸臺聳日邊雲，望拜青童上相君。", "侍女百千皆絳服，恰如簷外樹紛紛。"]'),
