('8b931d41-5600-47c8-a23d-f24feb399f2b','任道源轉示玉豔亭探梅詩卷未暇屬和閏月十一日偶自北山塔院過亭下枝間已花因次元韵三首  其一','張鎡','宋','宋诗','song-poetry','','[]','因花不作等閒來，屐印苔紋酒便回。',32,'全唐诗/poet.song.171000.json','["因花不作等閒來，屐印苔紋酒便回。", "明日窗前追昨夢，似逢姑射不逢梅。"]'),
('cde033ed-2445-4881-9b38-6b077ce2fd0f','任道源轉示玉豔亭探梅詩卷未暇屬和閏月十一日偶自北山塔院過亭下枝間已花因次元韵三首  其二','張鎡','宋','宋诗','song-poetry','','[]','細看孤標迎臘瘦，爭如繁豔遇春酣。',32,'全唐诗/poet.song.171000.json','["細看孤標迎臘瘦，爭如繁豔遇春酣。", "古來節士功名薄，剩欲裁詩問水南。"]'),
('a0da4c89-2364-4a09-91c8-f877509eb479','任道源轉示玉豔亭探梅詩卷未暇屬和閏月十一日偶自北山塔院過亭下枝間已花因次元韵三首  其三','張鎡','宋','宋诗','song-poetry','','[]','占斷林家一種春，隔湖茅舍羨漁人。',32,'全唐诗/poet.song.171000.json','["占斷林家一種春，隔湖茅舍羨漁人。", "折枝弄蕊年年手，生怕長安揖馬塵。"]'),
('2800fa82-b651-45ba-9f36-31996cefb0f2','殘梅','張鎡','宋','宋诗','song-poetry','','[]','雨絲吹冷透窗紗，忽忽東風管鬢華。',32,'全唐诗/poet.song.171000.json','["雨絲吹冷透窗紗，忽忽東風管鬢華。", "豈爲梅殘便無恨，草生時節勝看花。"]'),
('ba66119f-da7c-4611-bf44-9302e7c60c5b','水閣即事二首  其一','張鎡','宋','宋诗','song-poetry','','[]','水閣開窗景不偏，斷橋堤柳盡橫前。',32,'全唐诗/poet.song.171000.json','["水閣開窗景不偏，斷橋堤柳盡橫前。", "平生到處居人後，已有貂璫泊畫船。"]'),
('e4843511-53df-47a4-89ad-f80feef96d2b','水閣即事二首  其二','張鎡','宋','宋诗','song-poetry','','[]','今歲春來我亦來，折花猶未見花開。',32,'全唐诗/poet.song.171000.json','["今歲春來我亦來，折花猶未見花開。", "新春况有四十日，莫怪幽人空手回。"]'),
('96799883-b819-4296-aefa-4985d958cbe3','余以雪牡丹歌呈誠齋回柬云只得籍沒是兵家不傳之妙謂不和答也又嘗以來日立夏問誠齋所謂風月庫中當作何措置蒙絕句示報因次韵致謝併破前說云','張鎡','宋','宋诗','song-poetry','','[]','春風欲去難留住，措置無如信野人。',32,'全唐诗/poet.song.171000.json','["春風欲去難留住，措置無如信野人。", "但解有詩隨手和，自然日日是青春。"]'),
('13ac7a53-8247-4ee8-ad30-48ca99460cc4','夏夜二首  其一','張鎡','宋','宋诗','song-poetry','','[]','燈暈紗籠靜者居，夜凉携扇繞階除。',32,'全唐诗/poet.song.171000.json','["燈暈紗籠靜者居，夜凉携扇繞階除。", "松間有句松間說，不向空中咄咄書。"]'),
('172a37c6-3feb-4394-8e39-8f292d88ddaf','夏夜二首  其二','張鎡','宋','宋诗','song-poetry','','[]','天上星辰金玉棋，輸贏何日是分時。',32,'全唐诗/poet.song.171000.json','["天上星辰金玉棋，輸贏何日是分時。", "多應却笑張居士，綺語妄言無了期。"]'),
('82e109bf-bb58-4af5-af02-edcd529e6ec8','戲詠鹹蛤','張鎡','宋','宋诗','song-poetry','','[]','鹽作棲巢涕作脂，樽前風味不勝低。',32,'全唐诗/poet.song.171000.json','["鹽作棲巢涕作脂，樽前風味不勝低。", "縱教一衲被雲水，無奈胸中著淤泥。"]'),
('426f1920-0f09-4155-b872-5af7062d55cb','尖簷帽','張鎡','宋','宋诗','song-poetry','','[]','落魄青樓倒接䍦，醉花爭插亂紅欹。',32,'全唐诗/poet.song.171000.json','["落魄青樓倒接䍦，醉花爭插亂紅欹。", "如今雨墊綸巾角，汝帽尖新却自宜。"]'),
('758d9385-ff24-4ede-b8c0-4cce74ccf242','謝李仁父茯苓','張鎡','宋','宋诗','song-poetry','','[]','岷峨山中千歲松，枝虯幹直摩青空。',224,'全唐诗/poet.song.171000.json','["岷峨山中千歲松，枝虯幹直摩青空。", "雪霜剝落中不槁，膏液下與靈泉通。", "龜跧鳬伏自磊砢，全堅玉潔仍豐融。", "篝明夜取喜得雋，煮鼎朝聽如吟風。", "杵成坐上香飛雪，更和乳酪收全功。", "當知至味本無味，子若服之壽無窮。", "巽巖脊梁硬如鐵，冠峨切雲佩明月。", "百好都隨春夢空，大藥獨傳欣寶訣。", "中宵咀嚼不摇頭，玉瀋生肥咽不徹。", "憐我百慮形早衰，裹贈扶持意何切。", "丹砂著眼謾爾傳，脂澤釀黍計已拙。", "由來妙道初不煩，此法莫從兒輩說。", "徑思舉袂揖浮丘，下視塵世真一吷。", "朱顔留得亦何爲，追逐同堅歲寒節。"]'),
('a7e38d2a-9e5f-4819-bd4d-75d6cb5dee9b','游九鎖山  其一','張鎡','宋','宋诗','song-poetry','','[]','九鎖非凡境，烟雲路不分。',48,'全唐诗/poet.song.171000.json','["九鎖非凡境，烟雲路不分。", "山寒長带雨，洞古不收雲。", "夜宿聽林鶴，晨炊摘野芹。", "黄冠皆好事，添注石爐熏。"]'),
('d4d71dbc-458d-414a-aacc-a0e05412fce7','游九鎖山  其二','張鎡','宋','宋诗','song-poetry','','[]','凉蟬亂叫朝暮雨，獨鶴不迷前後山。',32,'全唐诗/poet.song.171000.json','["凉蟬亂叫朝暮雨，獨鶴不迷前後山。", "芎葉煮湯勝茗椀，栗花然火照松關。"]'),
('eb60945e-35ac-4622-b627-2c48a698e161','再游  其一','張鎡','宋','宋诗','song-poetry','','[]','曉日晴崗路未分，昔年鐘磬隔林聞。',64,'全唐诗/poet.song.171000.json','["曉日晴崗路未分，昔年鐘磬隔林聞。", "龍歸古洞千巖雨，人卧空山半榻雲。", "異草靈苗交晚翠，野蘭芳芷雜秋芬。", "何時得似山中鶴，脫却雞群友鹿群。"]'),
('2d18b063-6668-4a04-8498-6b24a15b6dab','再游  其二','張鎡','宋','宋诗','song-poetry','','[]','天風吹我落人間，暫入青山又促還。',32,'全唐诗/poet.song.171000.json','["天風吹我落人間，暫入青山又促還。", "待得霜林收柿栗，却來重扣白雲關。"]'),
('3d2445be-55a0-4529-9c42-6a669407fb0c','題楊誠齋南海朝天二集','張鎡','宋','宋诗','song-poetry','','[]','作者于今星樣稀，凄其望古駟難追。',64,'全唐诗/poet.song.171000.json','["作者于今星樣稀，凄其望古駟難追。", "空桑枯竹陶元亮，玉佩瓊璩杜拾遺。", "自笑吟秋如懶婦，可能擊鼓和馮夷。", "報章不作南金直，慚愧君家丙稿詩。"]'),
('c7e57a68-f1d0-4294-a2de-66f7bc011c90','吟詩','張鎡','宋','宋诗','song-poetry','','[]','一日吟成九首詩，旁人都愛少瑕疵。',32,'全唐诗/poet.song.171000.json','["一日吟成九首詩，旁人都愛少瑕疵。", "直須作到無人愛，始是我詩長進時。"]'),
('1556e0db-c574-4a2a-8842-9ac5f76cd7e2','夜飲楊村','張鎡','宋','宋诗','song-poetry','','[]','轉柁初投獨樹村，杖藜因叩小蓬門。',64,'全唐诗/poet.song.171000.json','["轉柁初投獨樹村，杖藜因叩小蓬門。", "殷勤翁媼吹茅火，飣餖雞豚薦瓦樽。", "剩喜平時無暴客，祇愁連雨沒禾根。", "招邀縱簡真淳在，欲去猶嗔稚子喧。"]'),
('f33021e5-9fcb-4a84-8ba2-86b36ab7fa7d','暫住新市行次謝村二首  其一','張鎡','宋','宋诗','song-poetry','','[]','籠叢灌木繞低田，一雨催鳴爾許蟬。',32,'全唐诗/poet.song.171000.json','["籠叢灌木繞低田，一雨催鳴爾許蟬。", "平日詩懷何處吐，今年秋色此行先。"]'),
('de3dee10-7b74-4793-9eab-18d96083ead2','暫住新市行次謝村二首  其二','張鎡','宋','宋诗','song-poetry','','[]','推窗面面得凉多，陂濼風翻渴水荷。',32,'全唐诗/poet.song.171000.json','["推窗面面得凉多，陂濼風翻渴水荷。", "人語忽驚群鶩起，隔蘆知是小船遇。"]'),
('714dab87-2c8e-4b4f-8603-14e364a9b5d9','行次季村','張鎡','宋','宋诗','song-poetry','','[]','破衣鳴蓬雨，迎晨捩柁風。',48,'全唐诗/poet.song.171000.json','["破衣鳴蓬雨，迎晨捩柁風。", "擘茭溪飯白，鍛鐵店爐紅。", "于役多無定，於心少所同。", "船人探蟹室，持壽覓詩翁。"]'),
('90d8270e-2891-4229-aad1-6bb10263c234','過下黄村','張鎡','宋','宋诗','song-poetry','','[]','山腰摘菜穿雲裏，山嘴吹煙接雲起。',64,'全唐诗/poet.song.171000.json','["山腰摘菜穿雲裏，山嘴吹煙接雲起。", "響邊樵唱路幽幽，白處鵝群波瀰瀰。", "臨堤野毛槽盛水，破璧方簾自撩紙。", "相應不望褭蹄金，落得清閑養妻子。"]'),
('9bbcad9f-5dd0-4cc4-9494-d9ce207e0a44','過竹村','張鎡','宋','宋诗','song-poetry','','[]','再宿離城邑，全無世俗氣。',48,'全唐诗/poet.song.171000.json','["再宿離城邑，全無世俗氣。", "僧包輕濺水，漁竈冷炊雲。", "酒好休教盡，詩慳却自欣。", "晝閑貪睡穩，獨被不須重。"]'),
('a56bcc4e-a378-454f-a656-87f0c9b6df88','石汙尊','張鎡','宋','宋诗','song-poetry','','[]','萬事醉如泥，昔賢有名言。',24,'全唐诗/poet.song.171000.json','["萬事醉如泥，昔賢有名言。", "閉門五十載，真須石爲罇。"]'),
('66aa2644-3f25-4f4d-ba38-11a518f158ed','茂洪奉親携妾遷新館戲贈','張鎡','宋','宋诗','song-poetry','','[]','巷居南北喜相依，不患逢秋得句稀。',64,'全唐诗/poet.song.171000.json','["巷居南北喜相依，不患逢秋得句稀。", "采擷正當黄菊早，登臨寧嘆白雲飛。", "奉觴壽主歡宜洽，剪髮邀賓志莫違。", "從此維摩方丈室，散花香滿老萊衣。"]'),
('26aa5c31-37b5-4f09-a17b-e3598db1cde3','天聲館','張鎡','宋','宋诗','song-poetry','','[]','鸞鶴紛來下，天風駕月明。',24,'全唐诗/poet.song.171000.json','["鸞鶴紛來下，天風駕月明。", "語言難道斷，不墮世間聲。"]'),
('d6d03ff7-cc36-4396-b854-fdefb8aba665','蘋風館','張鎡','宋','宋诗','song-poetry','','[]','山頭鴟叫棕林雨，山下鷗移芰花著。',96,'全唐诗/poet.song.171000.json','["山頭鴟叫棕林雨，山下鷗移芰花著。", "開亭騁望豈固難，心迹雙閑罕儔侶。", "人生才智非謀己，太息塵勞誰縛汝。", "圖回田畝役宵夢，近對烟霏可無語。", "耦耕植杖千古賢，我欲從之胡不然。", "坐到月來休返舍，旁寺有牀書并借。"]'),
('3d670b23-45c1-4a37-b820-8c6035f2b07e','謁叢霄館  其一','張鎡','宋','宋诗','song-poetry','','[]','奉真祠宇并丹房，露下層壇夜未央。',64,'全唐诗/poet.song.171000.json','["奉真祠宇并丹房，露下層壇夜未央。", "玉繡球明依砌樹，翠鬘雲轉罨爐香。", "何心輕舉氛塵外，但願閑居歲月長。", "却上竹輿歸去路，約齋燈認隔林光。"]'),
('6c43ec58-cb97-4fd1-abf7-1d1f929b2d9e','謁叢霄館  其二','張鎡','宋','宋诗','song-poetry','','[]','飆御繽來下，儲休答意虔。',24,'全唐诗/poet.song.171000.json','["飆御繽來下，儲休答意虔。", "雖無名宦達，林墅保長年。"]'),
('ade87825-031d-4be3-b69a-f06a57f1e9e7','花仙館','張鎡','宋','宋诗','song-poetry','','[]','烟火心腸詠不真，風流嬌貴却無塵。',32,'全唐诗/poet.song.171000.json','["烟火心腸詠不真，風流嬌貴却無塵。", "何須更問花仙姓，便是扁舟共載人。"]'),
('7bcaa66a-50d6-4a3d-977b-ebf76c9c17f1','琅華洞天','張鎡','宋','宋诗','song-poetry','','[]','琪樹已無塵，山幽地更靈。',24,'全唐诗/poet.song.171000.json','["琪樹已無塵，山幽地更靈。", "羽流來往熟，仙飯設青精。"]'),
('0d8233e6-ac55-4629-a6fd-8ba7bfdf927c','送京仲遠次對制帥四川  其一','張鎡','宋','宋诗','song-poetry','','[]','林下忘官品，聞公近最榮。',48,'全唐诗/poet.song.171000.json','["林下忘官品，聞公近最榮。", "軍民制全蜀，名住列西清。", "器自海嶽重，文兼全玉聲。", "早來登政府，活法了寰瀛。"]'),
('b150a770-2d22-494d-a50c-14eec567fbdc','送京仲遠次對制帥四川  其二','張鎡','宋','宋诗','song-poetry','','[]','使北人爭說，今回國勢尊。',48,'全唐诗/poet.song.171000.json','["使北人爭說，今回國勢尊。", "屬聲堅執禮，黠虜殆忘魂。", "鉅業此猶細，故强行復存。", "鄉閭正關外，因夢逐西轅。"]'),
('d3719fd1-ac84-47f2-93c2-4ee616cdffb4','送京仲遠次對制帥四川  其三','張鎡','宋','宋诗','song-poetry','','[]','賤子夫誰問，鳴騶屢水湄。',48,'全唐诗/poet.song.171000.json','["賤子夫誰問，鳴騶屢水湄。", "自因閑肯顧，不是佞求知。", "山檻清持茗，花蹊笑說詩。", "雨風今送別，悽斷濕旌旗。"]'),
('fb9001f8-13ff-4650-a6b4-f672efe83240','衰疾幾半月梅事已空杏花亦爛熳矣忽往一觀成古詩三十韵','張鎡','宋','宋诗','song-poetry','','[]','年前約園梅，梅開主人病。',288,'全唐诗/poet.song.171000.json','["年前約園梅，梅開主人病。", "初英僅一窺，旋遭風雨橫。", "瑰奇耻浪設，收卷歸盡浄。", "追攀夢中事，詎復形嘯詠。", "連朝得暄晴，疾勢頓除摒。", "池西杏盈坡，芬菲想繁競。", "巾車試移轍，遠睇已輝映。", "披莊尺許足，領意豈煩更。", "亭亭喜余顧，笑粲若相迎。", "瑞錦圍坐幛，晹晶滿空鏡。", "疇知自心法，本匪生化柄。", "實虛總一體，曾何有衰盛。", "斯言忌輕拈，或能惹譏諍。", "尪孱阻劇賞，得句漫枯硬。", "非無戀勝交，倉卒費延請。", "浮生只堪樂，疎慵矧天性。", "能消屐幾䩫，盍早謀究竟。", "當年莘野叟，偶爾應三聘。", "後人循自售，例投俗眼輕。", "嗟予亦蒙愧，行矣關郡政。", "零丁門戶責，姑塞先世命。", "隨群畫紙末，觸目但癡𥋇。", "事功畧何禆，趍進徒伺偵。", "樸愚頼堅守，齪齪矜細行。"]'),
('854290a8-574e-4370-b53b-fb619030e6d3','大滌洞留題','張鎡','宋','宋诗','song-poetry','','[]','我生百無能，唯工說山水。',204,'全唐诗/poet.song.171000.json','["我生百無能，唯工說山水。", "洞霄天一柱，真仙昔居止。", "蒼崖入九鎖，修澗清徹底。", "層林仰首看，冷霧隨步起。", "饒君俗到骨，至此換却髓。", "一亭巧當門，乃是壓澗尾。", "便教寶玉做，思之未爲侈。", "道人喜客來，先引玩清泚。", "源頭放泉出，猛噴深壑裏。", "頃刻百萬丈，寧論尺與咫。", "冰濤卷雷鼓，滂湃力未已。", "天然句滿眼，潤色謝東里。", "擬議及思惟，望風當披靡。", "回觀翠蛟語，舞字最不死。", "兩詩故自妙，似覺泉在凡。", "正須吾三人，作意共整理。", "要令石點頭，滔滔那解此。"]'),
('f5305451-6d1b-46ae-b400-46f4eb105c21','偈','張鎡','宋','宋诗','song-poetry','','[]','鐘一擊，耳根塞，赤肉團邊去個賊。',32,'全唐诗/poet.song.171000.json','["鐘一擊，耳根塞，赤肉團邊去個賊。", "有人問我解何宗，瞬若多神面門黑。"]'),
('fc66209d-f126-45ed-9fab-2c1e10ff4edb','釣臺','張鎡','宋','宋诗','song-poetry','','[]','絳衣騎日扶桑上，三精九縣開靈貺。',264,'全唐诗/poet.song.171000.json','["絳衣騎日扶桑上，三精九縣開靈貺。", "趙梁雍代跡俱空，馮吳寇鄧勳相望。", "客星何處潛光芒，雙臺疊巘摩穹蒼。", "釣絲千丈捲烟雨，誰瞰一碧玻璃江。", "羊裘坐穩無心動，蒲輪纁幣知何用。", "故人聊爲小周旋，君房謬欲相推送。", "寥寥歲月今幾秋，山寒松吹多颼飀。", "春來日暖花氣發，極浦浪轉魚龍遊。", "先生有臺人共高，虛庭忍見生蓬蒿。", "斷碑敗壁蠹荒蘚，灌木野鳥捐枯巢。", "一朝鐘梵交雲際，簷楹改觀輝杉桂。", "非關好事取時名，此中恥但稱能吏。", "却經祠下羅清樽，試歌此詩當招魂。", "先生出兮佩蘭蓀，明璣耀旂駕瑶璠，黄麟道前翠虯奔。", "先生去兮山雲屯，玉妃金童從繽紛。", "吹簫鼓瑟聲冥冥，目斷暮靄棲遥林。"]'),
('d888f0a3-758a-4984-91e0-8df74cf1b2cc','句  其一','張鎡','宋','宋诗','song-poetry','','[]','一棹徑穿花十里，滿城無此好風光。',16,'全唐诗/poet.song.171000.json','["一棹徑穿花十里，滿城無此好風光。"]'),
('8bf19fde-6871-44ab-b765-5d3b47a5cc5e','句  其二','張鎡','宋','宋诗','song-poetry','','[]','斷橋斜取路，古寺未關門。',12,'全唐诗/poet.song.171000.json','["斷橋斜取路，古寺未關門。"]'),
('e69a6f88-16a2-4f92-8eca-13a51326234c','句  其三','張鎡','宋','宋诗','song-poetry','','[]','梨花風骨杏花妝。',8,'全唐诗/poet.song.171000.json','["梨花風骨杏花妝。"]'),
('0a656985-3fdc-4814-a0df-27bbb4097959','句  其四','張鎡','宋','宋诗','song-poetry','','[]','已從槐借葉，更染菊爲裳。',12,'全唐诗/poet.song.171000.json','["已從槐借葉，更染菊爲裳。"]'),
('f947a4b0-b699-46b5-bd05-39cf1353bf66','句  其五','張鎡','宋','宋诗','song-poetry','','[]','何時重來桂隠軒，爲我醉倒春風前。',32,'全唐诗/poet.song.171000.json','["何時重來桂隠軒，爲我醉倒春風前。", "看人喚作詩中仙，看人喚作飲中仙。"]'),
('3c80400b-7eba-4abd-9b90-a143c047d59d','句  其六','張鎡','宋','宋诗','song-poetry','','[]','吹殺梅花影裏燈。',8,'全唐诗/poet.song.171000.json','["吹殺梅花影裏燈。"]'),
('96bfc81e-cb40-482a-8c0a-02eba7d24e61','句  其七','張鎡','宋','宋诗','song-poetry','','[]','古剎藏幽勝。',6,'全唐诗/poet.song.171000.json','["古剎藏幽勝。"]'),
('9bbc071a-20ad-4b55-9cb2-700a199c01fd','句  其八','張鎡','宋','宋诗','song-poetry','','[]','開鏡影相歡。',6,'全唐诗/poet.song.171000.json','["開鏡影相歡。"]'),
('8ddafce9-1715-48ad-af1a-187661bfb0a0','句  其九','張鎡','宋','宋诗','song-poetry','','[]','自笑從來癖。',6,'全唐诗/poet.song.171000.json','["自笑從來癖。"]'),
('4c624259-5d3e-4efe-bd0e-1afe3f8094da','句  其一○','張鎡','宋','宋诗','song-poetry','','[]','清興寄毫端。',6,'全唐诗/poet.song.171000.json','["清興寄毫端。"]'),
('d93f953f-7041-4ce9-817c-8a611c3daaeb','句  其一一','張鎡','宋','宋诗','song-poetry','','[]','日烘花氣暖。',6,'全唐诗/poet.song.171000.json','["日烘花氣暖。"]'),
('545537a8-73cc-473d-8803-5a5d209a5da0','句  其一二','張鎡','宋','宋诗','song-poetry','','[]','空對爛銀盤。',6,'全唐诗/poet.song.171000.json','["空對爛銀盤。"]'),
('6ebfcf99-1ebf-48e4-b48e-bd344f0f0b2f','句  其一三','張鎡','宋','宋诗','song-poetry','','[]','芙蓉憔悴菊垂叢。',8,'全唐诗/poet.song.171000.json','["芙蓉憔悴菊垂叢。"]'),
('a7218188-ce3b-4e35-b217-1480d02ff86e','句  其一四','張鎡','宋','宋诗','song-poetry','','[]','己信此心安此命。',8,'全唐诗/poet.song.171000.json','["己信此心安此命。"]'),
('e9673775-5c73-4fe0-9512-7d63f18441b1','句  其一五','張鎡','宋','宋诗','song-poetry','','[]','燕子初歸已識面，牡丹未放已知名。',16,'全唐诗/poet.song.171000.json','["燕子初歸已識面，牡丹未放已知名。"]'),
('640540aa-5593-4bdd-af73-9e916b49ff43','次陸務觀韵','宋甡','宋','宋诗','song-poetry','','[]','欲求平易多成拙，稍涉新奇却未工。',32,'全唐诗/poet.song.171000.json','["欲求平易多成拙，稍涉新奇却未工。", "得句直須參造化，此身何必計窮通。"]'),
('c44e1021-fcb1-4256-9b48-a68e59bea811','題東山','俞烈','宋','宋诗','song-poetry','','[]','文會得吾黨，浄居清晝長。',156,'全唐诗/poet.song.171000.json','["文會得吾黨，浄居清晝長。", "平生愛山僻，暇日聊徜徉。", "風流謝康樂，肥遯計亦良。", "鍾鼎成淹留，江湖晚相望。", "山色青未改，山名久愈彰。", "松風度晚曲，巖花弄晨妝。", "尚疑縹緲人，髻鬟下鳴璫。", "淒涼懷古恨，野水涵方塘。", "功名不作難，出處何可忘。", "人自草木腐，看渠日爭光。", "香消酒力微，緣陰聽圓吭。", "悠然發遐想，莞爾還成章。", "歸途有清泚，濯纓詠滄浪。"]'),
('bf80a3e9-008e-482c-83ef-ab2821e41bb5','題凈梵院清虛堂','俞烈','宋','宋诗','song-poetry','','[]','天清蠶麥餘，綠結桃李實。',156,'全唐诗/poet.song.171000.json','["天清蠶麥餘，綠結桃李實。", "老僧詩銜袖，過我語言質。", "懷山意先行，如病夢芝朮。", "去□才一舍，鞭策不終日。", "堂筵新結束，空洞無長物。", "風來舞翠杉，土暖榮病橘。", "欲行意先清，舌評驥不及。", "何由解鞍卧，夜枕雨瀟瑟。", "泉清韵磬遠，林樾琅玕密。", "杯寒續飛斟，煙繼香遶室。", "談玄契參同，酒旨妙真一。", "懷新辜雅趣，意懶□健筆。", "亦如罷參僧，野禪縛枯律。"]'),
('167948be-220e-4393-a85f-3219d15c1e6f','詠松','李誠之','宋','宋诗','song-poetry','','[]','半依巖岫倚雲端，獨立亭亭耐歲寒。',32,'全唐诗/poet.song.171000.json','["半依巖岫倚雲端，獨立亭亭耐歲寒。", "一事頗爲清節累，秦時曾作大夫官。"]'),
('95ef2022-f920-4518-a5f1-180aa5635bfb','遊金焦二山','程卓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','揚子長江天際來，中流有山何壯哉。',272,'全唐诗/poet.song.171000.json','["揚子長江天際來，中流有山何壯哉。", "深根盤礴千萬丈，寸土不受雙崔嵬。", "金山屹據上流險，四面佛屋相環回。", "來帆去槳別艫舳，住僧過客煩追陪。", "排空傑閣揖滄海，海山亂點浮纖埃。", "龍潭別聳石峰巧，時立野鶴慵毰毸。", "堂頭回首指遺像，坡公印老留青煤。", "其人已去詩尚在，唱酬風月相徘徊。", "再三瞻敬下山去，縹緲又入雲濤堆。", "焦山一望祇十里，舟師駕櫓如奔雷。", "行行滉蕩呼吸頃，繫纜犖确登山隈。", "山中僧少竹木古，瘦根迸石穿莓苔。", "幽姿野態隨步出，勝處往往多樓臺。", "洪崖路轉尋瘞鶴，幾年浪打風雨摧。", "遺銘破碎石剝落，摩挲細讀心眸開。", "同行韵遠興未盡，飛仙亭上傾樽罍。", "酒酣我爲發奇絕，底須方外求蓬萊。"]'),
('43d8842f-6896-4f44-9b6c-d9277e5b466c','雲巖','程卓','宋','宋诗','song-poetry','','[]','石門一望路迢迢，五老峰高聳碧霄。',64,'全唐诗/poet.song.171000.json','["石門一望路迢迢，五老峰高聳碧霄。", "泉挂珠簾當洞口，烟拖練带束山腰。", "香爐捧出仙人掌，輦輅行過織女橋。", "午夜月明天似水，鶴歸松頂聽吹簫。"]'),
('e1f85393-3837-4af8-840a-608517910e03','偈頌七首  其一','釋亮','宋','宋诗','song-poetry','','["\u8861\u5c71"]','一葉落，天下秋，幾人於此辨來由。',32,'全唐诗/poet.song.171000.json','["一葉落，天下秋，幾人於此辨來由。", "衲僧冷地呵呵笑，南嶽天台拄杖頭。"]'),
('3f3ef1ab-6589-4272-aeeb-56daa5adeef8','偈頌七首  其二','釋亮','宋','宋诗','song-poetry','','[]','兩箇屎橛，合作一團。',26,'全唐诗/poet.song.171000.json','["兩箇屎橛，合作一團。", "熏天炙地誰能嗅，千古叢林作話端。"]'),
('6c2724a6-310c-4039-92c9-a126f6449576','偈頌七首  其三','釋亮','宋','宋诗','song-poetry','','[]','今朝十一月十五，光陰似箭歲將莫。',59,'全唐诗/poet.song.171000.json','["今朝十一月十五，光陰似箭歲將莫。", "參禪學道如何，切忌守株而待兔。", "若是金毛師子兒，翻身一擲無回互。", "無回互，驚殺南山白額虎。"]'),
('503176b4-c55e-432d-b41d-5d2eb1431f4e','偈頌七首  其四','釋亮','宋','宋诗','song-poetry','','[]','今朝三月半，百花開爛熳。',43,'全唐诗/poet.song.171000.json','["今朝三月半，百花開爛熳。", "祖意甚分明，何妨著眼看。", "看看，忽然花謝樹頭空，又被風吹別調中。"]'),
('b7d8274b-518d-4695-b787-14da52788350','偈頌七首  其五','釋亮','宋','宋诗','song-poetry','','[]','者僧問處絕誵訛，就便拈來付與它。',32,'全唐诗/poet.song.171000.json','["者僧問處絕誵訛，就便拈來付與它。", "嫩綠枝頭紅一點，動人春色不消多。"]'),
('bdfbffaf-989e-4808-ac71-f07d2526e044','偈頌七首  其六','釋亮','宋','宋诗','song-poetry','','[]','九旬禁足今朝滿，漆桶掀翻快活人。',32,'全唐诗/poet.song.171000.json','["九旬禁足今朝滿，漆桶掀翻快活人。", "莫怪點胸夸獨步，只緣過夏在清真。"]'),
('e9011030-b4b6-4efa-91fa-c4763c8f040e','偈頌七首  其七','釋亮','宋','宋诗','song-poetry','','[]','說參禪，彌天過，緣是見成行貨。',29,'全唐诗/poet.song.171000.json','["說參禪，彌天過，緣是見成行貨。", "可憐背覺合塵，飯籮邊忍饑餓。"]'),
('e9dff7b6-342a-4687-8bc5-89da4d845f6c','指三門','釋亮','宋','宋诗','song-poetry','','[]','蹋斷千差路，潑天門戶開。',24,'全唐诗/poet.song.171000.json','["蹋斷千差路，潑天門戶開。", "擡頭空蕩蕩，脚下起風雷。"]'),
('1740843e-bfa5-4cf3-9dbe-c63b2bb13fdd','偈頌五首  其一','釋亮','宋','宋诗','song-poetry','','[]','八十老婆心已灰，强顔抹粉與涂蚽。',32,'全唐诗/poet.song.171000.json','["八十老婆心已灰，强顔抹粉與涂蚽。", "自知潦倒無羞耻，遇興何妨舞一回。"]'),
('8e6ed107-a959-4ed4-80d1-1231335a250e','偈頌五首  其二','釋亮','宋','宋诗','song-poetry','','[]','柳緣花紅春鳥啼，明明祖意報君知。',32,'全唐诗/poet.song.171000.json','["柳緣花紅春鳥啼，明明祖意報君知。", "箇中直下知端的，已落吾家第二機。"]'),
('2fae70d4-92a7-4869-a5d7-20f3536f4519','偈頌五首  其三','釋亮','宋','宋诗','song-poetry','','[]','參學事，絕商量，急著眼，快承當，處處無非安樂鄉。',40,'全唐诗/poet.song.171000.json','["參學事，絕商量，急著眼，快承當，處處無非安樂鄉。", "阿呵呵，好快活，萬兩黄金也消得。"]'),
('bfb880f0-0f65-45dd-ad5d-ba8b670d89ec','偈頌五首  其四','釋亮','宋','宋诗','song-poetry','','[]','狂風暴雨轟霹壢，滿庭撼動花狼籍。',32,'全唐诗/poet.song.171000.json','["狂風暴雨轟霹壢，滿庭撼動花狼籍。", "紅紅白白已周遮，何勞飯袋重拈出。"]'),
('359ff16c-e02a-4b32-8495-47d845553686','偈頌五首  其五','釋亮','宋','宋诗','song-poetry','','[]','金風起，樹葉落，體露堂堂活鱍鱍。',40,'全唐诗/poet.song.171000.json','["金風起，樹葉落，體露堂堂活鱍鱍。", "報君知，快領略。", "回頭轉腦擬思量，錯認笊籬作木杓。"]'),
('1ce5a6bc-0c31-4833-affe-d30188889e02','頌古四首  其一','釋亮','宋','宋诗','song-poetry','','[]','你有主丈與主丈，你無主丈奪主丈。',32,'全唐诗/poet.song.171000.json','["你有主丈與主丈，你無主丈奪主丈。", "撥亂乾坤幾箇知，鶑啼不在花枝上。"]'),
('c8d6b7ab-42a6-4b4a-819f-7378f8a15af1','頌古四首  其二','釋亮','宋','宋诗','song-poetry','','[]','幾年湖海不知羞，一見桃花自點頭。',32,'全唐诗/poet.song.171000.json','["幾年湖海不知羞，一見桃花自點頭。", "堪笑傍觀猶眼熱，也來趁隊逞風流。"]'),
('fa718ae1-de0e-4f0b-b295-696167d6ac63','頌古四首  其三','釋亮','宋','宋诗','song-poetry','','[]','饑時定聞饑，飽時定聞飽。',24,'全唐诗/poet.song.171000.json','["饑時定聞饑，飽時定聞飽。", "婆子在臺山，趙州勘破了。"]'),
('da35044f-31ed-4f75-b20d-d7c46632d7f4','頌古四首  其四','釋亮','宋','宋诗','song-poetry','','[]','一色通身白，天然絕點塵。',24,'全唐诗/poet.song.171000.json','["一色通身白，天然絕點塵。", "吒沙當古路，不吼也驚人。"]'),
('4b88158d-2f0a-4e94-bffa-c7028cd31ff7','建康黄尚書請住清真曾以頌却之','釋亮','宋','宋诗','song-poetry','','[]','徹骨窮來不厭窮，橫眠倒卧白雲中。',32,'全唐诗/poet.song.171000.json','["徹骨窮來不厭窮，橫眠倒卧白雲中。", "饑餐一鉢和羅飯，此外無能振祖風。"]'),
('e69e6da9-f11e-460b-8681-ff48d179b7b5','悼遯庵','釋亮','宋','宋诗','song-poetry','','[]','無端拗曲作直，平白換人眼睛。',28,'全唐诗/poet.song.171000.json','["無端拗曲作直，平白換人眼睛。", "而今雙履歸去，且喜天下太平。"]'),
('84d28023-c5e2-4de5-a167-fa568b43dd5e','藤簟','釋亮','宋','宋诗','song-poetry','','[]','打成一片凝如水，風吹不動寒光起。',32,'全唐诗/poet.song.171000.json','["打成一片凝如水，風吹不動寒光起。", "飯飽齁齁快活眠，不知身在秋波裏。"]'),
('08c88a90-663c-4924-99e5-d42a5c551a8b','開塗田道者求語','釋亮','宋','宋诗','song-poetry','','[]','大海波濤湧，道人願力堅。',24,'全唐诗/poet.song.171000.json','["大海波濤湧，道人願力堅。", "當頭一截斷，萬頃看平田。"]'),
('38b6c0f4-4732-444a-a7e3-e127c7ce4db1','光維那歸鄉','釋亮','宋','宋诗','song-poetry','','[]','光境俱亡了，寒潭徹底清。',24,'全唐诗/poet.song.171000.json','["光境俱亡了，寒潭徹底清。", "泝流翻巨浪，五十四州驚。"]'),
('98cb57de-8093-4817-af84-9ee15da5e1a9','寄天童癡絕和尚','釋亮','宋','宋诗','song-poetry','','[]','潦倒西山百不能，隨身頼有一枝藤。',32,'全唐诗/poet.song.171000.json','["潦倒西山百不能，隨身頼有一枝藤。", "東撐西拄消閒日，甘作荒山小院僧。"]'),
('f7c48f0a-0279-40c3-a706-dc42465b3ee4','達上人乞語','釋亮','宋','宋诗','song-poetry','','[]','達道應須併六賊，六賊併了何所得。',32,'全唐诗/poet.song.171000.json','["達道應須併六賊，六賊併了何所得。", "十方坐斷眼頭空，觀音院裏無彌勒。"]'),
('1fbd321b-765c-4869-8e6f-9a69b2c25c73','碧雲寄華藏故舊','釋亮','宋','宋诗','song-poetry','','[]','碧雲深處望湖山，時步松門獨往還。',32,'全唐诗/poet.song.171000.json','["碧雲深處望湖山，時步松門獨往還。", "眼底故人都不見，但聞幽鳥語關關。"]'),
('9aac5d74-8c77-4dc4-b591-3171c0d044b0','見侍者求語','釋亮','宋','宋诗','song-poetry','','[]','三呼三應箭鋒拄，不呼不應全體露。',32,'全唐诗/poet.song.171000.json','["三呼三應箭鋒拄，不呼不應全體露。", "汝從雪竇到靈山，步步蹋著無差互。"]'),
('02eb4388-633e-45d5-a512-23583b7db35e','光上人求語','釋亮','宋','宋诗','song-poetry','','[]','光明寂照徧河沙，認著依前滿眼花。',76,'全唐诗/poet.song.171000.json','["光明寂照徧河沙，認著依前滿眼花。", "喪盡諸緣回首看，寥寥四顧絕周遮。", "絕周遮處未爲是，更須知有祖師關。", "透得關，生死佛魔甚屎屁。", "時來平地一聲雷，四海五湖如鼎沸。"]'),
('a83d7fc1-9101-488f-928f-a92443e67803','古禪人乞語','釋亮','宋','宋诗','song-poetry','','[]','底事完全亙古今，何勞特地徧參尋。',32,'全唐诗/poet.song.171000.json','["底事完全亙古今，何勞特地徧參尋。", "草鞋蹋破知端的，悔涉山川恨轉深。"]'),
('07154e27-3283-4999-9734-51746d6de113','分菊','郭仁','宋','宋诗','song-poetry','','[]','小畦香雨碧颸颸，分得新苗旋作籬。',64,'全唐诗/poet.song.171000.json','["小畦香雨碧颸颸，分得新苗旋作籬。", "爲待繁英供採掇，故尋異本鬭芳奇。", "野人自愛編青障，老圃先教擁綠泥。", "濁酒預拚重九約，狂風莫損最高枝。"]'),
('9fa11bb0-398f-4d9c-a4dd-0000580f0c53','村居','郭仁','宋','宋诗','song-poetry','','[]','移家楊柳灣，小築田家塢。',24,'全唐诗/poet.song.171000.json','["移家楊柳灣，小築田家塢。", "一宵春雨晴，滿地菜花吐。"]'),
('21cee430-1cc2-4b86-9603-e648aac36cf0','薇山書室爲朱惟節賦','郭仁','宋','宋诗','song-poetry','','[]','幽意曠何許，逃名東海傍。',48,'全唐诗/poet.song.171000.json','["幽意曠何許，逃名東海傍。", "卜隣惟拜石，覽勝不齎糧。", "帙散蘭亭近，書探禹穴忙。", "紫薇山畔月，流照有餘光。"]'),
('5bcef614-6015-4dfb-91c2-eb856728b8ce','巖礲洞留題','包伯騶','宋','宋诗','song-poetry','','[]','巍然造化功，斡擘成巖豅。',48,'全唐诗/poet.song.171000.json','["巍然造化功，斡擘成巖豅。", "石頂滴清瀝，洞深颼細風。", "我來畏暑間，憇此清泠中。", "緬懷二老調，逸思更無窮。"]'),
('c463cc9d-e472-4a7b-8ac1-cc7ccd92f49c','謝趙憲副使惠建茶','陳壎','宋','宋诗','song-poetry','','[]','貢餘自合到侯王，誰遣甘芳入莧腸。',64,'全唐诗/poet.song.171000.json','["貢餘自合到侯王，誰遣甘芳入莧腸。", "野客驚看龍鳳銙，家人學試蟹魚湯。", "題來諫議三封印，分到尚書八餠綱。", "盡灑從前腥腐氣，時時澆取簡編香。"]'),
('44667947-1c49-4246-830a-cb54b761b51e','嘲俠客','趙師商','宋','宋诗','song-poetry','','[]','計拙難敷食與衣，惟將俠氣借相知。',64,'全唐诗/poet.song.171000.json','["計拙難敷食與衣，惟將俠氣借相知。", "何如馮子歸彈鋏，爭似毛生立見錐。", "清世翩翩誰是美，塵寰碌碌已稱奇。", "有時舉翮連雲起，不比函關一隻雞。"]'),
('be2efc3b-329c-4142-9a87-580751643e24','仲弟應符用昌黎齪齪詩韵作咄咄篇自警家大人用韵作欣欣篇應求次韵作皦皦篇以見志云','孫應求','宋','宋诗','song-poetry','','[]','皦皦志士心，玉壺冰露寒。',144,'全唐诗/poet.song.171000.json','["皦皦志士心，玉壺冰露寒。", "整冠默危坐，撫卷慨永歎。", "膠擾天下事，豈逃吾靜觀。", "是心本如水，風過成濤瀾。", "蟻或作牛鬭，雀常用珠彈。", "萬境各顛倒，何者爲憂歡。", "聖學有宗盟，口血應未乾。", "進修在覆簣，趨舍防奔湍。", "正須極高深，乾坤見倪端。", "規摹括四代，宗廟富百官。", "譬如入玉府，璆琳雜琅玕。", "逢原在左右，諒非登天難。"]'),
('96faed96-fe2f-4862-8f92-1265d2406a09','丁未仲夏季弟海陵官舍家大人賞月作詩和韵','孫應求','宋','宋诗','song-poetry','','[]','銀蟾憂易缺，綵侍喜長圓。',48,'全唐诗/poet.song.171000.json','["銀蟾憂易缺，綵侍喜長圓。", "豈意他鄉會，均同一樂全。", "杯行驚話舊，星聚敢占天。", "但願人常久，頻將桂影延。"]'),
('b7711702-33ac-4aed-a9e1-e72ada255034','次季和宿龍泉寺遇雪韵','孫應求','宋','宋诗','song-poetry','','[]','艤岸投僧話，歡迎勢若歸。',48,'全唐诗/poet.song.171000.json','["艤岸投僧話，歡迎勢若歸。", "林巒窮勝處，樓閣盡翬飛。", "本謂身還舍，何期雪擁扉。", "莫嫌行復住，世事合隨機。"]'),
('39e7349d-fabc-4918-b76d-9bf667fd0ed7','恭次家大人初抵季弟海陵官舍之韵  其一','孫應求','宋','宋诗','song-poetry','','[]','一家千里赴吳陵，沿道遲留不問程。',64,'全唐诗/poet.song.171000.json','["一家千里赴吳陵，沿道遲留不問程。", "風物蕭條鄉愈遠，山川開豁眼增明。", "春田未有歸耕計，夜雨聊聽對榻聲。", "幸向萊庭同戲綵，回頭終有愧難兄。"]'),
('0572e8dc-d163-4590-b8e9-2dadc255317d','恭次家大人初抵季弟海陵官舍之韵  其二','孫應求','宋','宋诗','song-poetry','','[]','食貧寧問肉如陵，且喜官曹簡事程。',64,'全唐诗/poet.song.171000.json','["食貧寧問肉如陵，且喜官曹簡事程。", "千里平淮隨地闊，一江遠水照天明。", "幾多懷古登臨意，時作搔頭諷詠聲。", "酬唱敢希珠樹秀，粗分菽麥異周兄。"]'),
('53f61911-5565-4396-8f98-16e9f800346b','恭次家大人初抵季弟海陵官舍之韵  其三','孫應求','宋','宋诗','song-poetry','','[]','舟渡金山過廣陵，灣頭畧可計淮程。',64,'全唐诗/poet.song.171000.json','["舟渡金山過廣陵，灣頭畧可計淮程。", "回瞻建業祥煙繞，北望長安落日明。", "野曠春農虛地力，霜清曉角動邊聲。", "中原讎恥非難復，子弟皆思死父兄。"]'),
('14709805-d958-4639-bae8-2b00100499ea','仲弟應符生日大人作詩命和元韵','孫應求','宋','宋诗','song-poetry','','[]','阿連誕世在茲晨，月吐三更恰半春。',64,'全唐诗/poet.song.171000.json','["阿連誕世在茲晨，月吐三更恰半春。", "幸有斑衣堪共戲，何妨綠酒正相親。", "雍雍已覺和爲貴，勉勉當思德有鄰。", "所願百年長膝下，不勞相望似參辰。"]'),
('6b072991-1c6f-4a70-ade2-1ec8bfb7cceb','季弟黄巖任滿大人率家衆先歸作詩見示恭次元韵','孫應求','宋','宋诗','song-poetry','','[]','長拘棲寓季微官，携杖扶車愧二難。',64,'全唐诗/poet.song.171000.json','["長拘棲寓季微官，携杖扶車愧二難。", "翹首雲山魚雁遠，關心歲月骨毛寒。", "方來負米還爲養，未遂承顔數問安。", "何日庭前環戲綵，共馨夕膳潔晨餐。"]'),
('374ef32c-3934-4727-9655-d1fc162427cd','恭和家大人鬻田訓子詩韵','孫應求','宋','宋诗','song-poetry','','[]','家貧常産遽蕭然，只把詩書代力田。',64,'全唐诗/poet.song.171000.json','["家貧常産遽蕭然，只把詩書代力田。", "謀道固宜耽樂內，却行安可望追前。", "置錐今日憂無地，摛藻他時喜掞天。", "富貴學成終自有，服膺當務益拳拳。"]'),
('f21177e7-2406-4dcc-8630-f2b98c1ba83a','恭和家大人將赴季弟官舍書示及門之作  其一','孫應求','宋','宋诗','song-poetry','','[]','力穡良農必有年，先修人事乃言天。',32,'全唐诗/poet.song.171000.json','["力穡良農必有年，先修人事乃言天。", "士非學問無由立，勿道家饒負郭田。"]'),
('0b73cf4c-c411-4ab4-9cb5-e8845a81f939','恭和家大人將赴季弟官舍書示及門之作  其二','孫應求','宋','宋诗','song-poetry','','[]','少年不學待何年，長大無成莫怨天。',32,'全唐诗/poet.song.171000.json','["少年不學待何年，長大無成莫怨天。", "况是各承賢父訓，豈容弗肯播菑田。"]'),
('0e84d55d-7f8c-45ec-aa9f-74ea8b25a060','應符讀韓文公齪齪詩考其歲月乃三十二所作今應符生亦三十二年矣深有媿焉因借其韵爲咄咄篇以自警','孫應符','宋','宋诗','song-poetry','','[]','咄咄汝爲子，念之心可寒。',144,'全唐诗/poet.song.171000.json','["咄咄汝爲子，念之心可寒。", "慕則非所慕，歎則非所歎。", "愚生乃繫俗，達人斯大觀。", "大明高照耀，滄海足波瀾。", "不求勝己友，有過孰抨彈。", "不絕害心念，誠身奚喜歡。", "溝澮無源本，易盈還易乾。", "見善苟不明，譬彼東西湍。", "仁義根於心，視精而行端。", "讀書貴知道，事親寧以官。", "會稽産竹箭，西海出琅玕。", "虛名何足尚，所懼實才難。"]'),
('d5538d7b-7b7a-4f55-9d86-85ca9a47491b','次季和宿龍泉寺遇雪韵','孫應符','宋','宋诗','song-poetry','','[]','同入招提宿，初從城市歸。',48,'全唐诗/poet.song.171000.json','["同入招提宿，初從城市歸。", "雪輕渾欲舞，雲凍不成飛。", "客去尋溪棹，僧來叩竹扉。", "籬邊一枝玉，漏泄化工機。"]'),
('a8ec565b-43fe-454a-ac8c-e14a1465d92d','丁未仲夏季弟海陵官舍家大人賞月作詩恭次元韵','孫應符','宋','宋诗','song-poetry','','[]','賓僚成雅集，夜月正清圓。',48,'全唐诗/poet.song.171000.json','["賓僚成雅集，夜月正清圓。", "幸對芳樽滿，兼逢樂事全。", "哦詩追舊日，舉盞望青天。", "此會宜頻講，何妨祝壽延。"]'),
('df462800-fd24-41a3-8d2b-cc2d512b1d19','應符生日大人作詩以示恭次元韵','孫應符','宋','宋诗','song-poetry','','[]','初度追思夜向晨，敢安暇逸負青春。',64,'全唐诗/poet.song.171000.json','["初度追思夜向晨，敢安暇逸負青春。", "鴒原友悌同三益，鶴髮康寧拱二親。", "未遂功名酬誨育，勉將誠孝信鄉鄰。", "從今且願蒙天祐，日侍慈顔拜北辰。"]'),
('390c268b-7ca8-4225-a781-bd969e244970','季弟黄巖任滿大人挈家衆先掃作詩見示恭和元韵','孫應符','宋','宋诗','song-poetry','','[]','心處中虛治五官，物來能應固非難。',64,'全唐诗/poet.song.171000.json','["心處中虛治五官，物來能應固非難。", "移忠益本居家孝，閲暑知曾歷歲寒。", "父子賡歌真內樂，弟兄分職頼居安。", "何妨菽水爲歡養，會有時來詔賜餐。"]'),
('c33d79af-7a2d-4b6a-aaaa-be5b5890f6b0','恭次家大人初抵季弟海陵官舍之韵  其一','孫應符','宋','宋诗','song-poetry','','[]','學山初不止邱陵，驥子終期萬里程。',64,'全唐诗/poet.song.171000.json','["學山初不止邱陵，驥子終期萬里程。", "莫問官曹今落寞，正須人物自高明。", "斗升聊可爲親養，歲月行看播治聲。", "膝下團圞事文史，此身何幸忝居兄。"]'),
('9a2be92d-9fbc-46da-aebc-608f56347dd9','恭次家大人初抵季弟海陵官舍之韵  其二','孫應符','宋','宋诗','song-poetry','','[]','生於陵者自安陵，何事驅馳較驛程。',64,'全唐诗/poet.song.171000.json','["生於陵者自安陵，何事驅馳較驛程。", "却望鄉山千里隔，共看淮月一輪明。", "官閒足遂吟哦樂，俸薄休形歎息聲。", "最幸一家仍聚首，不須嗟弟與瞻兄。"]'),
('f45af8ba-f5f8-431c-b39e-4e03cbab7942','恭次家大人初抵季弟海陵官舍之韵  其三','孫應符','宋','宋诗','song-poetry','','[]','生憎世俗迭相陵，反己工夫有度程。',64,'全唐诗/poet.song.171000.json','["生憎世俗迭相陵，反己工夫有度程。", "大學在先知本末，中庸當務造誠明。", "諄諄自昔承嚴訓，默默終年愧令聲。", "至道不須由外索，事親友弟及從兄。"]'),
('fd5975f9-23b1-4bee-8fc8-ac39f2890761','恭次家大人鬻田訓子詩韵','孫應符','宋','宋诗','song-poetry','','[]','厄窮那復值凶年，典盡貧家五畝田。',64,'全唐诗/poet.song.171000.json','["厄窮那復值凶年，典盡貧家五畝田。", "暫給簞瓢居巷內，且將經史向窗前。", "潛心矻矻先修己，安命栖栖不怨天。", "爵祿功名宜自取，尤當勉力務勤拳。"]'),
('0d866683-360f-438d-b0ea-c7ac76d29515','恭和家大人將赴季弟官舍書示及門之作  其一','孫應符','宋','宋诗','song-poetry','','[]','純熟工夫積歲年，能知本性則知天。',32,'全唐诗/poet.song.171000.json','["純熟工夫積歲年，能知本性則知天。", "揠苗助長猶爲害，况復芸人舍己田。"]'),
('d45c62a9-bd55-4820-8917-8ab64511fcbf','恭和家大人將赴季弟官舍書示及門之作  其二','孫應符','宋','宋诗','song-poetry','','[]','焚膏繼晷且窮年，榮悴他時却在天。',32,'全唐诗/poet.song.171000.json','["焚膏繼晷且窮年，榮悴他時却在天。", "莫把光陰虛度了，吾徒耕道若耕田。"]'),
('d2e0ccdf-ef81-48fe-a0fa-074feb25db18','唐侯仲友之守台爲浮梁於江象山令蔣鶚考叔賦江有濟三章以獻余時官於台見而陋之作江有梁  其一','孫應時','宋','宋诗','song-poetry','','[]','江有梁，昔所無兮。',78,'全唐诗/poet.song.171000.json','["江有梁，昔所無兮。", "台之民，維艱虞兮。", "我南之耕，其出于于。", "我北之趨，維薪維芻。", "匪伊薪芻，行旅載途。", "風雨晦冥，海波愁予。", "豈無舟人，徼利以呼。", "偪仄淪胥，云誰之辜。"]'),
('ee6101b2-29ec-4c50-868a-2d1ba7133805','唐侯仲友之守台爲浮梁於江象山令蔣鶚考叔賦江有濟三章以獻余時官於台見而陋之作江有梁  其二','孫應時','宋','宋诗','song-poetry','','[]','江有梁，維今始兮。',78,'全唐诗/poet.song.171000.json','["江有梁，維今始兮。", "台之民，維天啟兮。", "邦有父母，視民如子。", "民號於溺，侯曰由己。", "乃相乃謀，乃築乃峙。", "其桴聯聯，其舟齒齒。", "民不知江，有道如砥。", "我醉我犇，云胡不喜。"]'),
('7f578252-dc5b-45c0-9c76-a33121ad6c10','唐侯仲友之守台爲浮梁於江象山令蔣鶚考叔賦江有濟三章以獻余時官於台見而陋之作江有梁  其三','孫應時','宋','宋诗','song-poetry','','[]','江有梁，孰使然兮。',78,'全唐诗/poet.song.171000.json','["江有梁，孰使然兮。", "台之民，曰侯賢兮。", "孰使侯賢，有命自天。", "天子聖仁，侯乃來宣。", "自我侯來，有麥有年。", "天姥之南，東溟之壖。", "濤瀾不驚，歌舞後先。", "汝不我信，視此一川。"]'),
('20c42146-f4ad-46fe-86bc-3af020307573','唐侯仲友之守台爲浮梁於江象山令蔣鶚考叔賦江有濟三章以獻余時官於台見而陋之作江有梁  其四','孫應時','宋','宋诗','song-poetry','','[]','我梁既成，我民既平。',60,'全唐诗/poet.song.171000.json','["我梁既成，我民既平。", "侯智不矜，侯心載寧。", "帝曰汝歸，其車宵征。", "予欲濟川，邦國是經。", "民留我侯，敢與帝爭。", "我帝我侯，眉壽無疆。"]'),
('84358a45-de59-4988-b180-77b41047fc31','四明山記遊八十韵','孫應時','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','平生抱遐尚，撫劍遠行遊。',288,'全唐诗/poet.song.171000.json','["平生抱遐尚，撫劍遠行遊。", "迹謝聲利牽，心與巖壑謀。", "東征泛滄海，南騖踰丹丘。", "西登岷峨嘯，北望關隴愁。", "匡廬挽歸轡，巫峽紆行舟。", "劍閣最險壯，龍門更奇幽。", "歷覽雖未飽，勝槩略以收。", "爾來卧燭湖，清夢長夷猶。", "家山維四明，名字橫九州。", "出門宛在眼，欲往輒不酬。", "人事真好乖，山靈豈吾仇。", "忽近益可笑，投老空自尤。", "茲辰正芳春，會心得良儔。", "贏糧幸易足，决策遂所求。", "中宵雨聲斷，逗曉霽色浮。", "天容極瑩凈，風氣正和柔。", "瘦筇挾籃輿，野服兼輕裘。", "遥遥指林麓，欣欣聽溪流。", "試屐請賢嶺，弭蓋白水湫。", "飛湍響淙潺，怪松韵蕭颼。", "艱然小羊額，喘若料虎頭。", "甓石訪歲期，負樵歌道周。", "百折快一眺，千里森雙眸。", "峰巒何綿聯，脈絡相纏繆。"]'),
('e8b0ce20-151f-4523-8c7d-c80765b660e4','送張敬夫栻以追送不作遠爲韵賦詩五章藉手言別不勝惓惓愛助之誠情見乎辭惟高明幸教  其一','孫應時','宋','宋诗','song-poetry','','[]','平生賦褰裳，親意許從師。',60,'全唐诗/poet.song.171000.json','["平生賦褰裳，親意許從師。", "四海非不廣，獨仰大雅姿。", "逡巡一再見，慘憺已復辭。", "霜風送旌節，遠目不可追。", "挾經問疑義，倘許結後期。"]'),
('3c4c2aa6-50b7-41e8-a75e-bf4e66ff84c1','送張敬夫栻以追送不作遠爲韵賦詩五章藉手言別不勝惓惓愛助之誠情見乎辭惟高明幸教  其二','孫應時','宋','宋诗','song-poetry','','[]','斯文肯空言，經世資實用。',60,'全唐诗/poet.song.171000.json','["斯文肯空言，經世資實用。", "紛紛諒奚爲，義取輒賓送。", "誠能正其本，談笑了羣動。", "公身紹前烈，時論倚隆棟。", "持茲竟安歸，引燈相與共。"]'),
('2fd55bc8-7de1-45cf-9a41-e57c73afafcb','送張敬夫栻以追送不作遠爲韵賦詩五章藉手言別不勝惓惓愛助之誠情見乎辭惟高明幸教  其三','孫應時','宋','宋诗','song-poetry','','[]','軒冕付儻來，良貴應自有。',60,'全唐诗/poet.song.171000.json','["軒冕付儻來，良貴應自有。", "若人出處間，與世揭山斗。", "雅宜踐高門，斷國極可不。", "臨風耿予思，霧雨深稂莠。", "凜然嚴冬柏，特立終耐久。"]'),
('8296c6fe-553b-4a86-bc6e-f5c70ec6aa66','送張敬夫栻以追送不作遠爲韵賦詩五章藉手言別不勝惓惓愛助之誠情見乎辭惟高明幸教  其四','孫應時','宋','宋诗','song-poetry','','[]','荆州形勝地，控引吁廣莫。',60,'全唐诗/poet.song.171000.json','["荆州形勝地，控引吁廣莫。", "英雄昔用武，跬步圖宛洛。", "至仁先內治，豈曾廢遠畧。", "公來手摩撫，士氣端可作。", "載歌江漢詩，奮袂空爵躍。"]'),
('d8c40418-78b2-4c6c-b9f7-5fcf63a1080a','送張敬夫栻以追送不作遠爲韵賦詩五章藉手言別不勝惓惓愛助之誠情見乎辭惟高明幸教  其五','孫應時','宋','宋诗','song-poetry','','[]','力行希孟韓，波蕩斥嵇阮。',60,'全唐诗/poet.song.171000.json','["力行希孟韓，波蕩斥嵇阮。", "聖門有佳處，誰爲發關鍵。", "歸依得其人，心豈間近遠。", "悄悄客路長，肅肅歲華晚。", "祝公黄髮期，永好情繾綣。"]'),
('1f99cc99-afec-42e6-896a-3b2fc19dc115','送友人楊仲能東下以一蹴自造青雲分韵得一字','孫應時','宋','宋诗','song-poetry','','[]','君王急搜羅，九土規混一。',180,'全唐诗/poet.song.171000.json','["君王急搜羅，九土規混一。", "蜀山甚疎遠，去者今稍密。", "夫君偉才具，文字尤炳蔚。", "陸沈簿領中，塵霧昏玉質。", "正應著臺省，邂逅破回遹。", "輕舟下三峽，春浪平如席。", "攬觀山川奇，感嘆日月疾。", "便好作諫書，胸憤吐堙鬰。", "薰風御爐香，天陛踏文石。", "此時恨見晚，端不負疇昔。", "或求西南州，爲國撫貧瘠。", "因以壽老親，繡幰圍畫戟。", "日邊豈無心，遲子付異日。", "離樽聊共持，愁思黯難釋。", "勇去仍趣歸，修途護眠食。"]'),
('1033aa29-b851-454c-89b4-3808bfa897cf','讀晦翁遺文悽愴有作','孫應時','宋','宋诗','song-poetry','','[]','先生千載人，浩氣隘穹壤。',288,'全唐诗/poet.song.171000.json','["先生千載人，浩氣隘穹壤。", "早薄聲利交，超然傲塵鞅。", "飲酒讀離騷，追游必豪爽。", "風月飽高吟，雲泉擅奇賞。", "切骨痛國讎，嚼齒憤奸黨。", "縱談天下事，一一如指掌。", "歛意師聖賢，精心玩圖象。", "全體極渾涵，靈根妙充養。", "昭昭陳軌轍，坦坦闢榛莽。", "陶鎔就醇粹，鞭策收勉强。", "瞿聃息遁辭，關雒大遺響。", "師道屹尊嚴，人材興倜儻。", "宸綸歎廉靖，朝蹟惎忠讜。", "康廬委符竹，越絕畀英簜。", "芻牧活饑惸，天日快幽枉。", "命義信行藏，風標何骯髒。", "晚來侍細旃，時益異疇曩。", "孤蹤反山林，百怪幻夔魍。", "先生一澹然，幾微寧怏怏。", "冬曦暖袍屨，秋風颯几杖。", "尚可淑後來，何言遂長往。", "暌離思遠道，殷勤媿殊奬。", "常懷訂羣疑，忍獨拜遺像。", "感舊日蕭瑟，出門增惝怳。"]'),
('90bf5214-62ee-4e9b-b4dc-1d738ed3fef1','七月一日獨遊頂山上方院','孫應時','宋','宋诗','song-poetry','','[]','澗水有奇觀，山蟬發清歌。',48,'全唐诗/poet.song.171000.json','["澗水有奇觀，山蟬發清歌。", "穹林翠光合，深谷凉風多。", "孤遊正寂歷，佇立久婆娑。", "平生頗須此，欲去意如何。"]'),
('6a7245d5-b452-4a49-b64e-feb9ce40adf0','立夏日汎舟遊青山憩楊氏庵示諸生','孫應時','宋','宋诗','song-poetry','','[]','歲序忽云夏，青春去安歸。',96,'全唐诗/poet.song.171000.json','["歲序忽云夏，青春去安歸。", "天清風氣朗，游子懷芳菲。", "碧湖泛我舟，輕雲湛晴暉。", "入谷山寂寂，緣溪水圍圍。", "翛然得幽憩，丹葩耀巖扉。", "鳥聲自歌呼，竹色相因依。", "舉觴佇遥念，日月如梭飛。", "平生靜中願，歲晚無相違。"]'),
('3b075f69-5cc5-45fb-bba8-8f4f6765ec70','和魏公再用韵勉子孫學','孫應時','宋','宋诗','song-poetry','','[]','儒家乃何事，駕言聖門歸。',96,'全唐诗/poet.song.171000.json','["儒家乃何事，駕言聖門歸。", "萬古江河流，三春卉木菲。", "忍將少年意，負此白日暉。", "拱把得封植，要看四十圍。", "東山公別墅，明湖照簷扉。", "塵囂澹一洗，六籍真可依。", "城南拜新作，妙墨龍蛇飛。", "著鞭繼家聲，臨岐莫依違。"]'),
('1a6bc1f7-62fe-43df-a2ac-8d48ec0ebd71','和陳亮功張次夔二同年唱酬廉字誠字之作  其一','孫應時','宋','宋诗','song-poetry','','[]','早韭到晚菘，紫蓼仍綠葵。',48,'全唐诗/poet.song.171000.json','["早韭到晚菘，紫蓼仍綠葵。", "古爲志節士，此味良自知。", "銀鞍黄金絡，綺戶芙蓉閨。", "丈夫各自適，物理那能齊。"]'),
('704cf7d5-d408-4e3f-aec6-e07d7c29aa47','和陳亮功張次夔二同年唱酬廉字誠字之作  其二','孫應時','宋','宋诗','song-poetry','','[]','虛中答遠響，不與律呂乖。',48,'全唐诗/poet.song.172000.json','["虛中答遠響，不與律呂乖。", "惟誠貫萬物，此豈欺我哉。", "九仞憂棄井，累土期層臺。", "汝州春風中，試坐一月來。"]'),
('e4b621df-9bb6-4d53-875f-ecf1f2a450ad','用前韵感事  其一','孫應時','宋','宋诗','song-poetry','','[]','駒去不食藿，馬佚能傷葵。',48,'全唐诗/poet.song.172000.json','["駒去不食藿，馬佚能傷葵。", "烈士多慷慨，耿耿誰當知。", "起吟清夜闌，邊月明春閨。", "寸心杜陵老，澒洞終南齊。"]'),
('533693d8-17e8-4026-b780-af4189e4a1c8','用前韵感事  其二','孫應時','宋','宋诗','song-poetry','','[]','竽門抱瑶瑟，雅與時好乖。',48,'全唐诗/poet.song.172000.json','["竽門抱瑶瑟，雅與時好乖。", "閉門守長饑，毅然丈夫哉。", "南楚卧龍士，北燕黄金臺。", "但使本根在，功名真儻來。"]'),
('13ab4963-b2c4-463f-aa6d-7d859ae0b22d','李允蹈以詩見詒走筆和之李號能詩諸貴人客也','孫應時','宋','宋诗','song-poetry','','[]','四海夥人物，百年各馳驅。',192,'全唐诗/poet.song.172000.json','["四海夥人物，百年各馳驅。", "持身付埃塵，擾擾竟何須。", "臨邛家四壁，洛北飯一孟。", "白首頗光榮，不媿初心無。", "男兒胸中奇，玉虹自呵噓。", "滄浪振幽潔，沆瀣餐雲腴。", "養性一無累，經世乃其餘。", "芙蓉爲裳衣，秋蘭爲珮琚。", "西遊畧崑崙，東征拂玄菟。", "乘風羾天門，九闕請三呼。", "太息治安策，中流資一壺。", "河山洗祲氛，日月行天衢。", "凌煙千載容，丹青爲君鋪。", "請君辦此事，勿待餘子俱。", "我懶復無用，藜羹守故書。", "敢云驪龍睡，妄意淵中珠。"]'),
('f324947e-e6a5-400b-a8fd-4180c2abc47e','李允蹈再詩言別次韵','孫應時','宋','宋诗','song-poetry','','[]','仙人騎長鯨，醉與月相追。',120,'全唐诗/poet.song.172000.json','["仙人騎長鯨，醉與月相追。", "落筆千萬篇，要與風雅期。", "里耳習巴唱，未省白雪詞。", "欲當莫邪鋒，斷毛真一吹。", "文章游戲耳，功名須鼎彝。", "推轂天下士，豈無鄭當時。", "我愚敢望君，君胡首肯之。", "酒酣激清嘯，八極隘指麾。", "丈夫嘆歲晚，不恨一別離。", "行行愛體素，江湖勞夢思。"]'),
('2700e4ca-2c68-4c9c-b887-2f840e7197df','吳文伯用李允蹈追字韵見贈亦次答之','孫應時','宋','宋诗','song-poetry','','[]','鷄鳴市聲起，冠蓋日相追。',120,'全唐诗/poet.song.172000.json','["鷄鳴市聲起，冠蓋日相追。", "終然寡同調，千里懷風期。", "憶從十年前，識君黄絹詞。", "安知淮海來，得此塤箎吹。", "武庫森器寶，清廟陳尊彝。", "持君胸中富，自足夸一時。", "况今亨衢開，秣馬隨所之。", "功名何足道，談笑觀指麾。", "交情無遠近，人事有合離。", "他年一尊酒，長恐勞相思。"]'),
('fcb9c1d2-596e-40d6-81c7-689ccb25961f','和答司馬宜春遡','孫應時','宋','宋诗','song-poetry','','[]','紛紛市道交，勢利爭攫取。',168,'全唐诗/poet.song.172000.json','["紛紛市道交，勢利爭攫取。", "煌煌鼎食家，聲色自纏糾。", "畸人固寂寞，蓬藋侵甕牖。", "有時步虛曲，植杖話農畝。", "清秋動幽興，有月欠肴酒。", "高軒肯相過，賢哉百乘友。", "空尋奕秋誨，不與歡伯偶。", "別來雁欲賓，晴喜鳩還婦。", "村酤聊可載，草具亦何有。", "飣餖止魚蝦，扶擎雜梨藕。", "君侯反觴客，欲起輒被肘。", "意重黄金百，氣豁雲夢九。", "長篇繼踵來，子建才八斗。", "勉和若登山，吾詩真培塿。"]'),
('cd888a3f-f594-4604-be78-992a3ef36aa8','答潘文叔見寄予十月嘗訪文叔文叔許來而猶未也','孫應時','宋','宋诗','song-poetry','','[]','別離一何久，迢遞阻音形。',192,'全唐诗/poet.song.172000.json','["別離一何久，迢遞阻音形。", "重上君子堂，相見眼終青。", "君顔尚冰玉，我鬢已星星。", "借問十載間，風波兩蓬萍。", "嶺劍各萬里，心目多所經。", "歸來且强健，怳然真夢醒。", "可憐萬修竹，清音玉瓏玲。", "蕭條媚寒日，約畧環翠屏。", "相携復一笑，芝蘭有餘馨。", "孤雲自舒卷，野鶴來青冥。", "平生閲羣彥，十八九彫零。", "吾徒亦何願，畢景依林坰。", "種秫令可釀，儲粟常滿缾。", "琴書奉娛玩，足以陶性靈。", "千載伐木篇，此意神所聽。", "往來亦奚憚，江浦堪揚舲。"]'),
('6e2ffb7d-2a06-4a4e-9cf8-ef681a1f1e00','毗陵龔君以崈見投古風思致不凡依韵答之  其一','孫應時','宋','宋诗','song-poetry','','[]','驅車適古道，道古世已今。',96,'全唐诗/poet.song.172000.json','["驅車適古道，道古世已今。", "翳翳逃空虛，幸有跫然音。", "歡言指萬里，握手再沈吟。", "得無霜露繁，恐復江漢深。", "我聞道渴者，朵頤望梅林。", "至味難誑口，達士多遠心。", "天淵本曠蕩，鳶魚各飛沈。", "相期崑崙顛，弄月鳴瑶瑟。"]'),
('3dceb19d-5cd3-4554-a694-546d2e8b5dc9','毗陵龔君以崈見投古風思致不凡依韵答之  其二','孫應時','宋','宋诗','song-poetry','','[]','松柏有佳色，矯矯澗谷涯。',96,'全唐诗/poet.song.172000.json','["松柏有佳色，矯矯澗谷涯。", "要經鸞鳳棲，豈怨人迹遐。", "匠石初未逢，千歲甘枯槎。", "萬牛送明堂，亦不以自誇。", "奇物固落落，念此毋嘆嗟。", "君看蒿蓬茂，正足供鳴蛙。", "深根忍霜雪，生意日已嘉。", "終然拔青雲，勿慮歲月賒。"]'),
('1cc498e9-e2ff-44c6-8359-79d8bc03a570','趙唐卿邀游西湖即席賦十二韵','孫應時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春風客皇州，積雨不得晴。',144,'全唐诗/poet.song.172000.json','["春風客皇州，積雨不得晴。", "倚樓望西湖，想見煙水平。", "芳時諒難負，勝侶欣來并。", "杖藜一蕭散，喚船弄空明。", "浮雲爲我開，好鳥爲我鳴。", "青山次第出，桃李正鮮榮。", "華屋何煌煌，縹緲連重城。", "都人競時節，酒舫各斜橫。", "而我得舒眺，緬然起深情。", "風景自千古，擾擾何所營。", "大鈞實愛物，無使可憐生。", "堯民保同樂，吾其獲歸耕。"]'),
('e3513065-2812-47ab-a66b-af2a110a6a6f','游靈巖觀瀑布','孫應時','宋','宋诗','song-poetry','','[]','一雨天氣清，暑事亮未酷。',192,'全唐诗/poet.song.172000.json','["一雨天氣清，暑事亮未酷。", "煩囂念蕭散，茲晨正休沐。", "籃輿試經行，勝槩入遐矚。", "紆餘緣清溪，窈窕得幽谷。", "一巖四壁凈，千仞落飛瀑。", "雷霆鞭蟄戶，風雨撼林麓。", "光寒白虹下，勢劇天河覆。", "繽紛曜冰雪，激射碎珠玉。", "危亭著佳處，盡日看不足。", "澒洞開心胸，眩晃新耳目。", "龍臍更奇事，滴滴掛崖腹。", "人言七年旱，不減此一掬。", "天壤富瓌怪，名字有顯伏。", "冉溪逢子厚，釀泉須永叔。", "摩挲蒼苔碑，徒倚古寺竹。", "微吟忽忘歸，俗駕不可宿。"]'),
('50fb7665-cae5-4ce3-b020-a9018c2fcee1','鄭倅是歲七月同游和余韵復和酬之','孫應時','宋','宋诗','song-poetry','','[]','高人遺世紛，山水好常酷。',192,'全唐诗/poet.song.172000.json','["高人遺世紛，山水好常酷。", "監州當暑來，風露勞櫛沐。", "千里生清凉，萬象入睞矚。", "公餘事幽討，駕言訪空谷。", "豈知叢爾縣，有此壯哉瀑。", "飛蓋繚崇阿，響屐穿翠麓。", "林聲疑雨鳴，石怪若釜覆。", "輝輝倚天劍，凜凜寒水玉。", "畫圖見所稀，瑶琴寫難足。", "餘霏濕巾袂，瑩色照眉目。", "平生此會心，一笑欲捧腹。", "酒間出新篇，明珠粲盈掬。", "留作巖壑光，長令鬼神伏。", "東山懷太傅，濂溪想茂叔。", "逸興渺乾坤，真賞謝絲竹。", "何由頻執鞭，雲峰恣遊宿。"]'),
('482f92eb-7d90-4ff0-a8ba-a31a5c8f4af7','孫生康祖從予海陵予薦之滁守趙叔明之門送以古詩','孫應時','宋','宋诗','song-poetry','','[]','洙泗諸公游，參實少且魯。',240,'全唐诗/poet.song.172000.json','["洙泗諸公游，參實少且魯。", "誰知一貫學，其進乃甚武。", "儒生多山野，此事亦已古。", "儇儇細兒黠，往往車上舞。", "後生識取舍，百不能四五。", "子兮何爲者，獨行事踽踽。", "嗟我離師友，歲月漸莽鹵。", "子辱從之游，未必免聾瞽。", "淮丞少官事，吏散日亭午。", "藜羹共脫粟，本不計客主。", "親年當喜懼，藥裹屬覼縷。", "勞子辭我去，天寒無乃苦。", "滁陽賢太守，豈弟民父母。", "青山照城郭，廣厦庇風雨。", "子往事佔畢，可但費樽俎。", "窗明棐几浄，堅坐勿闚戶。", "交情貴膽肝，師道在規矩。", "何妨坐椎鈍，未可習媚嫵。", "萬里須堅車，百步要彊弩。", "書來說新功，吾其俟飛羽。"]'),
('7947b1a7-a4fc-411f-a9b1-0543928dd297','和劉過夏蟲五詠 蛛','孫應時','宋','宋诗','song-poetry','','[]','么蟲夜飛飛，遭汝巧見縛。',48,'全唐诗/poet.song.172000.json','["么蟲夜飛飛，遭汝巧見縛。", "汝網非堅牢，豈無風雨惡。", "蟹怒橫戈矛，蜃喜吐樓閣。", "物生黠復癡，悟此一笑樂。"]'),
('72b54823-fcac-4b7f-8e26-3ac01a252748','和劉過夏蟲五詠 螢','孫應時','宋','宋诗','song-poetry','','[]','太陽不敢近，宵行聊自娛。',48,'全唐诗/poet.song.172000.json','["太陽不敢近，宵行聊自娛。", "過水亂繁星，隨風散平蕪。", "車公晚差樂，几案不汝須。", "方謀買娉婷，斛貯明月珠。"]'),
('ad0ef83c-95e0-41c8-bf23-f9fd3339417a','和劉過夏蟲五詠 蚓','孫應時','宋','宋诗','song-poetry','','[]','高人百尺樓，萬里對天宇。',48,'全唐诗/poet.song.172000.json','["高人百尺樓，萬里對天宇。", "白水渺江湖，清明到窗戶。", "跏趺作禪定，不聞雷破柱。", "從渠蚯蚓歌，自趁商羊舞。"]'),
('4ba5172b-4fe3-4476-94fa-38ee01369e78','和劉過夏蟲五詠 蚊','孫應時','宋','宋诗','song-poetry','','[]','利觜死一飽，何勞更喧譁。',48,'全唐诗/poet.song.172000.json','["利觜死一飽，何勞更喧譁。", "肉薄來如雲，舉扇誰能遮。", "諸君幸小忍，秋風期不賒。", "披襟約凉夜，明月釣寒沙。"]'),
('bb0b6906-53c2-470d-8bd0-01da612694a7','和劉過夏蟲五詠 蛙','孫應時','宋','宋诗','song-poetry','','[]','將軍鼓吹來，處士非所喜。',48,'全唐诗/poet.song.172000.json','["將軍鼓吹來，處士非所喜。", "誇汝風月夕，天籟鳴不已。", "汝姑勿自誇，坎井不可恃。", "當知馬伏波，笑殺公孫子。"]'),
('b53a784c-6c5b-48f6-a1b5-1ba2b23dd6e9','用范叔剛韵送陳亮功同年','孫應時','宋','宋诗','song-poetry','','[]','人物相後先，筦庫故多士。',120,'全唐诗/poet.song.172000.json','["人物相後先，筦庫故多士。", "若人海邦來，清渭照涇水。", "風塵不自憚，遠業正在此。", "林深蘭荃芳，波動金石止。", "三年亦何事，一笑聊復爾。", "天風今扶摇，勢作九萬里。", "未令游蓬山，亦合佐槐市。", "富貴善移人，須公直如矢。", "平生十年書，喜見習鑿齒。", "少留更舂容，春醪薦魴鯉。"]'),
('83d8c2c4-3990-4bd8-b557-543e5e82594e','如寧庵','孫應時','宋','宋诗','song-poetry','','[]','川原相縈紆，林谷遞深秀。',96,'全唐诗/poet.song.172000.json','["川原相縈紆，林谷遞深秀。", "步迎流水聲，聒聒新雨後。", "愴然瞻故丘，喬木百年舊。", "精廬跨略彴，苔竹故幽茂。", "憶昔戲綠陰，怡悅年方幼。", "蹉跎今白髮，寒暑厭相寇。", "區區濟物心，已矣真大謬。", "請尋遂初賦，泉石長枕潄。"]'),
('c09c8257-795d-455e-ba3a-81820c0507a1','小舟過吳江風雨大作夜泊三家村翌日風回到家日未中','孫應時','宋','宋诗','song-poetry','','[]','短篷僅容坐，一滴不通雨。',168,'全唐诗/poet.song.172000.json','["短篷僅容坐，一滴不通雨。", "不料西南風，滂沛遽如許。", "蕩摇首屢觴，跧彎背欲僂。", "行經四橋側，心動不敢語。", "茫洋萬頃天，一葉縱掀舞。", "翻思田舍樂，甚念篙人苦。", "黄昏隨意泊，古木蔭靈宇。", "小作鷄酒願，欲禱辭未吐。", "覺來風回東，快便誰所與。", "平明八十里，到家日未午。", "萬事一翻覆，戚欣何處所。", "舟定稍按摩，起身試步武。", "一室有餘寬，洗杓命兒女。", "門外風濤急，閉門良可禦。"]'),
('9b0b1300-21cd-496d-b9e4-978f844528e5','庭下小檜','孫應時','宋','宋诗','song-poetry','','[]','蒼蒼歲寒姿，凜凜凌雲幹。',48,'全唐诗/poet.song.172000.json','["蒼蒼歲寒姿，凜凜凌雲幹。", "何爲事蟠蹙，充君眼中玩。", "翔鸞與偃蓋，不如溝中斷。", "高岡有同根，天風拂河漢。"]'),
('224af2a1-8990-4aef-ba58-3964725fe844','石應之校書招同胡崇禮趙幾道飲白蓮社晚雨','孫應時','宋','宋诗','song-poetry','','[]','白蓮遠公社，不能致淵明。',120,'全唐诗/poet.song.172000.json','["白蓮遠公社，不能致淵明。", "雷峰峰下庵，乃復浪此名。", "野客當暑來，喜甚荷風生。", "柳渚睇窈窕，竹房步紆縈。", "西軒正虛寂，一鏡湖光平。", "小飲試談噱，高吟發幽清。", "兩士幕府彥，主人芸閣英。", "我雖漫浪者，頗復同勝情。", "六合自今古，百年各經營。", "悠然一笑粲，急雨催詩成。"]'),
('3ac1b270-c804-430b-9a4b-0cfc4badb59f','送彭子復臨海令滿秩  其一','孫應時','宋','宋诗','song-poetry','','[]','君侯古循吏，及物如春醲。',48,'全唐诗/poet.song.172000.json','["君侯古循吏，及物如春醲。", "民間自寧一，堂上何從容。", "平生眼中人，此尹未易逢。", "吏道益可悲，非君吾孰從。"]'),
('4440ac24-6358-4f78-984b-41ce54e8ab7f','送彭子復臨海令滿秩  其二','孫應時','宋','宋诗','song-poetry','','[]','由求政事科，量己如尺寸。',48,'全唐诗/poet.song.172000.json','["由求政事科，量己如尺寸。", "後生談天下，可笑不知分。", "吾曹師古心，日夜抱孤恨。", "脫身朱墨中，未妨尋學問。"]'),
('9beec099-312b-41b5-bff8-e4c4488e0a9a','送彭子復臨海令滿秩  其三','孫應時','宋','宋诗','song-poetry','','[]','相逢幾何時，相與何如許。',48,'全唐诗/poet.song.172000.json','["相逢幾何時，相與何如許。", "書來警吾過，切切父兄語。", "人生會合難，念別成悽楚。", "北望山千里，秋容渺煙渚。"]'),
('22abd078-e36a-47d0-88bc-cd0f92d9c369','送彭子復臨海令滿秩  其四','孫應時','宋','宋诗','song-poetry','','[]','秋風滿庭樹，策策鳴良宵。',48,'全唐诗/poet.song.172000.json','["秋風滿庭樹，策策鳴良宵。", "幽人獨晤歎，時序何蕭條。", "寒華豈不容，念之中心焦。", "我巢在一枝，風雨無漂摇。"]'),
('4869fbef-f6c9-4747-8bba-9126ae1154d7','送王木叔推官滿秩  其一','孫應時','宋','宋诗','song-poetry','','[]','聽雨宿空山，念當與君別。',48,'全唐诗/poet.song.172000.json','["聽雨宿空山，念當與君別。", "起行意無柰，雨聲轉幽咽。", "名賢去蓮幕，一郡慘不悅。", "人心到無言，冰寒炭故熱。"]'),
('540e9257-9186-4a44-8ac1-88c1182e362b','送王木叔推官滿秩  其二','孫應時','宋','宋诗','song-poetry','','[]','世道不平易，心如太行山。',48,'全唐诗/poet.song.172000.json','["世道不平易，心如太行山。", "交遊水上萍，相知甚獨難。", "感君一見初，信我眉睫間。", "松柏氣本同，蒼蒼期歲寒。"]'),
('f6bf31e3-926b-4324-9c7d-34cb74659b77','送王木叔推官滿秩  其三','孫應時','宋','宋诗','song-poetry','','[]','靈臺湛虛明，萬物懸一鏡。',48,'全唐诗/poet.song.172000.json','["靈臺湛虛明，萬物懸一鏡。", "饑餐夜熟寢，是我真實性。", "牛山多斤斧，草木非正命。", "君乎善自養，吾心本無病。"]'),
('6122fd58-c43c-41d7-a9ff-4b2441ce445f','送台州沈虞卿使君入朝  其一','孫應時','宋','宋诗','song-poetry','','[]','鼓聲霜曉寒，冠蓋滿衢路。',96,'全唐诗/poet.song.172000.json','["鼓聲霜曉寒，冠蓋滿衢路。", "詔書日邊到，使君朝天去。", "攀車願公留，稚耋紛無數。", "信哉慈父母，赤子中心慕。", "七州浙江東，此邦亦蕃庶。", "使君手拊摩，白髮緣汝故。", "明時急良猷，此行那能駐。", "眷眷公豈忘，江城一回顧。"]'),
('06e5f6fa-206c-49c3-b5d3-ae994fc5b0d1','送台州沈虞卿使君入朝  其二','孫應時','宋','宋诗','song-poetry','','[]','靖康建炎事，嘗聞諸公言。',96,'全唐诗/poet.song.172000.json','["靖康建炎事，嘗聞諸公言。", "志士日夕心，嗚咽聲氣吞。", "新亭五十年，塵埃尚中原。", "君王大經畧，夢想天河翻。", "時情習安宴，未辦酬國恩。", "修攘亦有序，此事難遽論。", "所要夙昔懷，勿以暮氣昏。", "爲公一悲歌，風雲澹乾坤。"]'),
('b8735bcc-e9d8-4fb0-a68e-06ffbccee908','送台州沈虞卿使君入朝  其三','孫應時','宋','宋诗','song-poetry','','[]','東南數十州，今惟本根地。',96,'全唐诗/poet.song.172000.json','["東南數十州，今惟本根地。", "因仍軍國須，支吾亦良費。", "簿書高沒人，大率非古意。", "先生海邦來，歷歷眼中事。", "誠心對天日，正色俯民吏。", "那無一夜驚，感歎不能寐。", "九重憂民深，時節苦未易。", "源流儻可言，請拜仁人賜。"]'),
('da6e6d4b-d231-4f50-ae2e-d6551a13c877','不寐','孫應時','宋','宋诗','song-poetry','','[]','索居在村坰，水陸走通津。',72,'全唐诗/poet.song.172000.json','["索居在村坰，水陸走通津。", "半夜有棹歌，鷄鳴語行人。", "中年近少睡，耿耿多達晨。", "外物非所念，頗復念我身。", "聖賢不敢欺，久大在日新。", "人生會有役，安得辭苦辛。"]'),
('ba51ffed-f658-415c-8093-0df112a989f7','別黄巖范令','孫應時','宋','宋诗','song-poetry','','[]','慶曆諸名卿，四海標一范。',240,'全唐诗/poet.song.172000.json','["慶曆諸名卿，四海標一范。", "堂堂元祐相，人望復不減。", "江河源流大，終華峰巒嶄。", "遠優士會燮，詎作欒書黶。", "君侯大雅士，淵然粹家範。", "春風花氣馥，秋月寒江湛。", "貞剛謝瑕缺，潔白消黕黤。", "驅車問前躅，雲路聲轞轞。", "牛刀亦何爲，游刃初不斬。", "解令襦袴民，桁楊戒無犯。", "時情互醒醉，世味各辛鹻。", "安知國中狂，正欠秋牙喊。", "丈夫自有在，細故非所歉。", "豈無昆明池，著此黄龍艦。", "伊余秉微尚，顧瞻隨軓軓。", "威儀覿麒鳳，冠緌笑蟬𧍙。", "吾徒本平曠，誰能事嶮巉。", "相知意氣得，欲別精神黯。", "東風動綺席，潮痕带晴檻。", "爲公醉登舟，離襟不能摻。"]'),
('11c5f994-7db6-4797-baf6-1eec9f76905e','和制帥效謝康樂體','孫應時','宋','宋诗','song-poetry','','[]','讀書在雪屋，長嘯亦蝸廬。',132,'全唐诗/poet.song.172000.json','["讀書在雪屋，長嘯亦蝸廬。", "茲晨從遠役，不柰爲饑驅。", "夕棹悄煙月，朝帆暖菰蒲。", "情欣秋風至，體愜袢暑徂。", "拾魚未妝潦，爭米聊趁虛。", "廓落展遐眺，舂容進前途。", "暮畫諒何取，世用實已迂。", "分閫重節制，三邊藉調娛。", "功成報天子，朝珮歸與與。", "下客一何幸，窮途非所虞。", "江山待公賞，佳處小踟躕。"]'),
('9dfd1c9c-e94c-4e49-8bb4-1c47791e310c','臨海道中書懷  其一','孫應時','宋','宋诗','song-poetry','','[]','六月呼清風，凉氣隔纖紵。',48,'全唐诗/poet.song.172000.json','["六月呼清風，凉氣隔纖紵。", "玄冬映窗隙，重繭不能御。", "天時迭乘除，人事多齟齬。", "愴焉感余懷，百年幾寒暑。"]'),
('2fd62457-e912-4172-8478-d5cbe1d46601','臨海道中書懷  其二','孫應時','宋','宋诗','song-poetry','','[]','儒生不知變，區區誦陳言。',48,'全唐诗/poet.song.172000.json','["儒生不知變，區區誦陳言。", "時人熟見之，嬉笑相排拫。", "江流去不返，何時復虞軒。", "餼羊誠無用，禮意儻可存。"]'),
('eea60107-771c-442c-98dc-b4fffc06231b','章安鎮感事','孫應時','宋','宋诗','song-poetry','','[]','越嶠東南窮，連山赴滄海。',192,'全唐诗/poet.song.172000.json','["越嶠東南窮，連山赴滄海。", "章安古州宅，陵谷諒遷改。", "前江渺萬頃，風雨魚龍匯。", "嗟哉地遠絕，髣髴形勢在。", "憶昨南渡初，雲雷震紛靉。", "莎洲艤龍艦，白日照金鎧。", "兒童識漢官，草木被堯彩。", "是時元勳誰，成公國上宰。", "人心翼宗社，天命安鼎鼐。", "那知中原事，驚呼五十載。", "丹衷自結髮，彈劍氣𡾋嵬。", "時清忘夙昔，悲歌起衰怠。", "舉頭天門高，狂言小臣罪。", "功名故難量，時節亦有待。", "臨流想前英，奕奕動風采。", "漁郎定何心，波間聲欵乃。"]'),
('2f2e16ae-7f7a-4b79-b8b9-088de11fb40a','頂山禱雨','孫應時','宋','宋诗','song-poetry','','[]','官身縛塵事，日日如絲棼。',144,'全唐诗/poet.song.172000.json','["官身縛塵事，日日如絲棼。", "駕言適秋郊，開顔慰艱勤。", "大田平如席，多稼綠於雲。", "早熟有餉穫，晚播方耦耘。", "停鞭問父老，笑語何欣欣。", "今年大好麥，稻復當十分。", "天應憐百姓，似亦憐令君。", "我本無善政，謗駡常紛紜。", "獨慚龍公賜，一念如相聞。", "尚憂北山外，漸有龜坼文。", "爲爾乞終惠，潔齊炷爐薰。", "何當足吾願，豐年周九垠。"]'),
('7e6423da-051e-4587-9d93-83ec29649648','端午侍母氏飲有懷二兄偶閲二蘇是日高安唱和慨然用韵','孫應時','宋','宋诗','song-poetry','','[]','簿書束縛人，揮汗日亭午。',120,'全唐诗/poet.song.172000.json','["簿書束縛人，揮汗日亭午。", "平生世念薄，問子何自苦。", "佳辰相尋過，樂事稀可數。", "撥置爲親壽，菖花糝盤黍。", "歡言記時節，風俗自荆楚。", "獨嗟我常棣，不得同笑語。", "楊梅應正熟，筀筍堪自煮。", "對床負歸約，枕流慚乃祖。", "會當誓丘墓，畏出如畏虎。", "莫作兩蘇公，空言終齟齬。"]'),
('9ffe0254-bddb-44c3-9f23-6b38aba6be1a','五月二十日還舊居有感','孫應時','宋','宋诗','song-poetry','','[]','晨光澹凉月，霽宇來清風。',132,'全唐诗/poet.song.172000.json','["晨光澹凉月，霽宇來清風。", "輕舟泛漣漪，初旭升曈矓。", "水氣散洲渚，蔓花綴榛叢。", "我行何所之，故林翳蒿蓬。", "捨棹理幽徑，開顔揖前峰。", "出門望平臯，良苗鬰以葱。", "恭惟昔先人，有此一畝宮。", "遺字滿塵壁，所憂非困窮。", "但願君與相，燮調致年豐。", "諒哉烈士心，舉世故莫同。", "踟躕不忍去，惻愴結微衷。"]'),
('a5a5710d-b4e0-4a57-94b9-1eb02e34e7b5','夜讀書有感','孫應時','宋','宋诗','song-poetry','','[]','王公昔壯年，已作衰翁歎。',96,'全唐诗/poet.song.172000.json','["王公昔壯年，已作衰翁歎。", "古來多志士，念此不能旦。", "嗟余何爲者，忽忽甘寢飯。", "故書翻手忘，神情日疎散。", "前途雖綿邈，初心如可辦。", "云何十年外，低徊猶有憚。", "蟋蟀鳴我階，秋風歲將宴。", "日月豈待人，及今當自諫。"]'),
('3ffaf298-08dc-4763-857d-b98e330a8c6c','和甲辰秋夜讀書有感韵','孫應時','宋','宋诗','song-poetry','','[]','物華相尋來，世事不足歎。',96,'全唐诗/poet.song.172000.json','["物華相尋來，世事不足歎。", "侯蟲知春秋，宿鳥各昏旦。", "百年相勞苦，且復加餐飯。", "堂堂白日在，擾擾浮雲散。", "詩書信家法，朱墨窘官辦。", "三十二年非，還改當何憚。", "低徊逢迎地，言笑紛晏晏。", "嗟汝其惕然，輿衡有規諫。"]'),
('1f85cda2-f651-4700-9b3f-90f4c1b90ff0','黄州呈趙使君  其一','孫應時','宋','宋诗','song-poetry','','[]','魯狂不媚世，世亦與我違。',48,'全唐诗/poet.song.172000.json','["魯狂不媚世，世亦與我違。", "平生懷識察，如公良獨稀。", "塵沙二十年，孤舟萬里歸。", "見公不忍去，安得長相依。"]'),
('c16cd4b0-d9ff-4cd9-a491-71c2e767b101','黄州呈趙使君  其二','孫應時','宋','宋诗','song-poetry','','[]','歐蘇遊息地，草木有輝光。',48,'全唐诗/poet.song.172000.json','["歐蘇遊息地，草木有輝光。", "使君何風流，入手兩印章。", "下客亦天幸，音塵許相望。", "不登醉翁亭，尚能登雪堂。"]'),
('3530925f-3fa0-4a5c-849a-b8d68369ca00','黄州呈趙使君  其三','孫應時','宋','宋诗','song-poetry','','[]','雪堂老居士，赤壁故將軍。',48,'全唐诗/poet.song.172000.json','["雪堂老居士，赤壁故將軍。", "蘭舟醉烟月，羽扇麾風雲。", "登臨生感慨，江空水沄沄。", "從公一長嘯，神游儻相聞。"]'),
('71cccf19-ae55-4720-bf10-7132ab44e48f','小孤山曉望','孫應時','宋','宋诗','song-poetry','','[]','維舟小孤下，終夜風水聲。',96,'全唐诗/poet.song.172000.json','["維舟小孤下，終夜風水聲。", "雞唱起推戶，耿耿殘月明。", "四望無纖雲，景氣穆以清。", "碧山吐紅日，綠樹啼鶬鶊。", "茲峰何娟妙，臨流竦春榮。", "再拜款靈宮，緬然念平生。", "一役已萬里，百年定何成。", "隔江見彭澤，懷古有餘情。"]'),
('8db38319-4840-46fb-bbc5-4aff7e610b55','到荆州春物正佳樞使王公招宴歡甚已而幕府諸公携餞荆江亭併成四詩  其一','孫應時','宋','宋诗','song-poetry','','[]','初日明遠岸，綠蕪滿平川。',48,'全唐诗/poet.song.172000.json','["初日明遠岸，綠蕪滿平川。", "天宇呈春姿，物物懷芳妍。", "長隄行車馬，高樓餘管絃。", "由來大國楚，風景故依然。"]'),
('c2b92232-ea5a-4f71-aa1e-99efaeddaf3a','到荆州春物正佳樞使王公招宴歡甚已而幕府諸公携餞荆江亭併成四詩  其二','孫應時','宋','宋诗','song-poetry','','[]','華亭冠層城，滿城桃與李。',48,'全唐诗/poet.song.172000.json','["華亭冠層城，滿城桃與李。", "微風散晴煙，七澤多春水。", "龍山集遐眄，章臺見遺址。", "感物思無窮，對酒差可喜。"]'),
('8e1d9721-1880-4f89-a14a-199fdadf1179','到荆州春物正佳樞使王公招宴歡甚已而幕府諸公携餞荆江亭併成四詩  其三','孫應時','宋','宋诗','song-poetry','','[]','簪弁從元侯，芳辰奉良宴。',48,'全唐诗/poet.song.172000.json','["簪弁從元侯，芳辰奉良宴。", "海棠映明燭，夜久星河轉。", "孤舟萬里客，邂逅驚深眷。", "慚無仲宣賦，荆州乃堪戀。"]'),
('7c06c6f4-5f12-4ba0-bc30-675c13317b3d','到荆州春物正佳樞使王公招宴歡甚已而幕府諸公携餞荆江亭併成四詩  其四','孫應時','宋','宋诗','song-poetry','','[]','幙府盡時彥，湛輩非所倫。',48,'全唐诗/poet.song.172000.json','["幙府盡時彥，湛輩非所倫。", "歡言念游子，載酒臨江津。", "醉別足可惜，俛仰迹易陳。", "相期崇明德，芳烈垂千春。"]'),
('10e840cd-9635-4b65-8e54-e069c42dd396','答王甫撫幹和荆江亭韵  其一','孫應時','宋','宋诗','song-poetry','','[]','劍鬰氣衝斗，珠潛光媚川。',48,'全唐诗/poet.song.172000.json','["劍鬰氣衝斗，珠潛光媚川。", "丈夫自有在，時俗難爲妍。", "鍾期苟未逢，我琴不須絃。", "別路渺湖海，相思心炯然。"]'),
('b83566a7-8550-49d5-93ea-a679c174cf7c','答王甫撫幹和荆江亭韵  其二','孫應時','宋','宋诗','song-poetry','','[]','清詩報我來，瓊玖羞木李。',48,'全唐诗/poet.song.172000.json','["清詩報我來，瓊玖羞木李。", "感我萬古心，迢迢如江水。", "楚宮歌舞地，春農耕廢址。", "變化日相尋，榮華何用喜。"]'),
('8d5d21c8-906e-4660-95fb-865db9439aea','答王甫撫幹和荆江亭韵  其三','孫應時','宋','宋诗','song-poetry','','[]','樂哉新相知，開懷接談讌。',48,'全唐诗/poet.song.172000.json','["樂哉新相知，開懷接談讌。", "插花醉不辭，風光惜流轉。", "酒闌欲上馬，握手增眷眷。", "平生我輩人，定非兒女戀。"]'),
('b31cdb86-a1c8-436a-8dfa-d0443be83e8d','答王甫撫幹和荆江亭韵  其四','孫應時','宋','宋诗','song-poetry','','[]','別時記撫掌，醉劇語無倫。',48,'全唐诗/poet.song.172000.json','["別時記撫掌，醉劇語無倫。", "君如齊轅固，獨不類平津。", "交遊半白頭，心跡誰爲陳。", "由來松柏榦，不爭桃李春。"]'),
('80251ee3-326a-48e5-acf4-a2933e825f8b','澗壁梁公主祠云武帝女也據高塚上林木鬰然形勢開敞蓋公主所葬歟無碑志未及考諸記載士大夫留詩未見有起人意者余守風四日爲十二韵','孫應時','宋','宋诗','song-poetry','','[]','蕭翁本勝士，諸郎多藝文。',144,'全唐诗/poet.song.172000.json','["蕭翁本勝士，諸郎多藝文。", "傷哉晚大謬，家國成絲棼。", "主昔食何邑，桃李爭穠芬。", "禁臠必王謝，風流映青雲。", "豈其獨天幸，不見臺城軍。", "曲阿故近甸，茂林有高墳。", "玉魚既無恙，廟食仍蒿焄。", "此事乃可書，所恨荒前聞。", "千舟集浦溆，吉卜叩靈氛。", "我亦肅襟屨，一瓣崇鑪薰。", "徘徊慨千載，江波日沄沄。", "誰當著奇語，歌之擬湘君。"]'),
('ae992a66-4f58-47b7-8447-ebc7bb520fd6','澗壁阻風登小山四望書懷','孫應時','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','崇阿岸長江，荒蹊得徐步。',264,'全唐诗/poet.song.172000.json','["崇阿岸長江，荒蹊得徐步。", "徘徊一舒眺，邂逅豁心素。", "天壤故宏廓，川涂渺回互。", "蒼烟極東溟，落日臨北固。", "波光蕩汀渚，碧色明草樹。", "淮南平如砥，萬象入指顧。", "低迷江都宮，隠轔瓜洲戍。", "依依眷昔游，惻惻起遐慕。", "向來猶喜事，所歷有奇趣。", "摧頹八九年，日已不如故。", "兩脚厭行李，萬里諳長路。", "迺窮岷山源，重到入海處。", "結交豈不廣，覽古亦云富。", "所抱憂國心，知非濟時具。", "晨昏耿重闈，裘葛窘童孺。", "脫然决東耕，孤舟久東騖。", "寖近真自喜，凌險有餘懼。", "可憐茲叢薄，政爾淹杖屨。", "雲容尚飛揚，風意何鬰怒。", "人事諒難必，江神非所忤。", "庶蒙皇天慈，穩借一帆度。", "致意孫興公，尋君遂初賦。"]'),
('433b24f3-bdf3-42d3-a978-5e07db9b1a91','子寶東歸以嚶其鳴矣求友聲爲韵作古詩七章寬予旅懷次其韵  其一','孫應時','宋','宋诗','song-poetry','','[]','一年三送君，到家能幾程。',48,'全唐诗/poet.song.172000.json','["一年三送君，到家能幾程。", "白雲耿我懷，更想啼孩嬰。", "過門道無恙，憂端幸少平。", "因之慰猿鶴，無爲長怨聲。"]'),
('716ede04-5530-48d7-aaf3-f87b027924e8','子寶東歸以嚶其鳴矣求友聲爲韵作古詩七章寬予旅懷次其韵  其二','孫應時','宋','宋诗','song-poetry','','[]','宇宙歸一槩，時勢相重輕。',48,'全唐诗/poet.song.172000.json','["宇宙歸一槩，時勢相重輕。", "人心太行山，我道如砥平。", "沈吟百年事，俛仰萬古情。", "五窮未可送，鬼語方嚘嚶。"]'),
('4292b875-20a6-4c28-8da5-6d572527fc33','子寶東歸以嚶其鳴矣求友聲爲韵作古詩七章寬予旅懷次其韵  其三','孫應時','宋','宋诗','song-poetry','','[]','傾城事行樂，春臺日熙熙。',48,'全唐诗/poet.song.172000.json','["傾城事行樂，春臺日熙熙。", "掩關獨愁思，誰能赴幽期。", "故山隔湖海，浮雲翳晴曦。", "由來武安客，豈復知魏其。"]'),
('1a6f6dbb-67d0-4fcc-bf2c-3cb62f76b7c9','子寶東歸以嚶其鳴矣求友聲爲韵作古詩七章寬予旅懷次其韵  其四','孫應時','宋','宋诗','song-poetry','','[]','哲人重出處，外物非所榮。',48,'全唐诗/poet.song.172000.json','["哲人重出處，外物非所榮。", "鳳饑不啄粟，鴻冥安可矰。", "早知屠羊肆，無所用三牲。", "儻來亦儻去，不平何足鳴。"]'),
('e3b17c79-65e3-49ae-b750-91c4b89f1dcf','子寶東歸以嚶其鳴矣求友聲爲韵作古詩七章寬予旅懷次其韵  其五','孫應時','宋','宋诗','song-poetry','','[]','歲寒松柏蒼，波動金石止。',48,'全唐诗/poet.song.172000.json','["歲寒松柏蒼，波動金石止。", "物生不自別，有時正須此。", "真源在極致，空談非實理。", "玉汝其或成，造物恩大矣。"]'),
('c7c5438c-1a5e-4172-8574-fc44b73b7f55','子寶東歸以嚶其鳴矣求友聲爲韵作古詩七章寬予旅懷次其韵  其六','孫應時','宋','宋诗','song-poetry','','[]','弱齡抱微尚，實耻爲身謀。',48,'全唐诗/poet.song.172000.json','["弱齡抱微尚，實耻爲身謀。", "頗依夷惠閒，不擇趙魏優。", "意行忘坎穽，失脚復何尤。", "但存斗升養，過此今無求。"]'),
('574351f3-cf93-473c-a376-8f951a1dfd90','子寶東歸以嚶其鳴矣求友聲爲韵作古詩七章寬予旅懷次其韵  其七','孫應時','宋','宋诗','song-poetry','','[]','教不貴多言，小知非大受。',48,'全唐诗/poet.song.172000.json','["教不貴多言，小知非大受。", "力久有天得，海涵而地負。", "少年今白髮，誰與鞭其後。", "詩來讀百過，君真吾畏友。"]'),
('6d9f8791-810b-457a-b6b6-6b210e6cb715','秋日程伯玉携詩見過次韵','孫應時','宋','宋诗','song-poetry','','[]','秋聲入梧桐，落葉驚甕牖。',168,'全唐诗/poet.song.172000.json','["秋聲入梧桐，落葉驚甕牖。", "菊叢生細香，安排作重九。", "幽子曳杖吟，蓬門獨搔首。", "故人惠然來，新詩出瓊玖。", "歡言掃吾室，餖飣隨所有。", "高談雜古今，疑義相可否。", "當年醉翁意，固不在杯酒。", "人生等一夢，諒無金石壽。", "從渠豢鍾鼎，未可薄藜糗。", "斯須較榮枯，千載判妍醜。", "君侯文章家，世胄衣冠後。", "何傷回憲貧，正是裘牧友。", "俗子揶揄人，古道陵遲久。", "無勞問董龍，定是何雞狗。"]'),
('e8a06535-8098-400d-992a-53d6126f23be','和劉師文飲城西見懷','孫應時','宋','宋诗','song-poetry','','[]','劉侯元祐家，高標振流俗。',144,'全唐诗/poet.song.172000.json','["劉侯元祐家，高標振流俗。", "益州西門外，勝日事幽矚。", "襟期得佳士，命駕不待促。", "壺觴傍水石，談笑滿林屋。", "經行舊臺苑，蕪沒長禾菽。", "長吟何激烈，遠思脫羈束。", "遥追七賢社，不負千鍾淥。", "詩囊寄同幕，足音到空谷。", "明月散昏埃，清風濯炎溽。", "壯游憶子美，感遇悲伯玉。", "功名垂耳驥，歲月長饑鵠。", "此事置勿言，時情鬭蠻觸。"]'),
('5eee8296-d0a6-4ffa-b9a7-566f8ff76f42','重答','孫應時','宋','宋诗','song-poetry','','[]','萬古同山川，八方異風俗。',144,'全唐诗/poet.song.172000.json','["萬古同山川，八方異風俗。", "男兒事弧矢，心目快一矚。", "結交必名勝，曠懷無狹促。", "昂昂千丈松，朗朗百間屋。", "彼富自鍾鼎，我貧甘芋菽。", "誰能工俯仰，未許相縛束。", "讀書頭欲白，對客樽無淥。", "由來多此士，皎皎駒在谷。", "瞿唐候水齊，秋風祛暑溽。", "歸歟奉親懽，羹絲鱠江玉。", "青衫雖霜葉，已勝袍立鵠。", "進退吾何疑，肯事羝羊觸。"]'),
('d41ed7cd-5aa0-4a65-97c6-8d933bc93ffd','入劍門和少陵韵','孫應時','宋','宋诗','song-poetry','','[]','客還入劍門，縱覽形勢壯。',132,'全唐诗/poet.song.172000.json','["客還入劍門，縱覽形勢壯。", "兩崖摩青天，石城岌相向。", "風雲鬰慘澹，神鬼見情狀。", "重關一何危，哀壑不可傍。", "巖蹲虎豹怒，水落龍蛇放。", "英雄意飛揚，行路色沮喪。", "殺人古如麻，俛仰有餘愴。", "我遊亦何事，哦詩神頗王。", "杜陵千年句，角逐不得讓。", "過關一雨涼，濃綠出千嶂。", "獨酌無與歌，懷人復怊悵。"]'),
('8155b355-0377-412b-8e84-68ceac643e81','石柜閣和少陵韵','孫應時','宋','宋诗','song-poetry','','[]','榴花開正紅，杏子熟已赤。',96,'全唐诗/poet.song.172000.json','["榴花開正紅，杏子熟已赤。", "谽谺倚天嶂，戌削出水石。", "小驛有幽意，江風滿青壁。", "悠然一杯酒，勞汝萬里客。", "長安此北去，古人多遺跡。", "蕭條干戈後，俛仰關塞迫。", "宿師苦餽餉，諸將飽恩澤。", "三歎復出門，危梯欲何適。"]'),
('07ad5abd-cda3-4924-95fa-1d3c248e9bcd','讀士元傳','孫應時','宋','宋诗','song-poetry','','[]','老賊狐鬼嘯，漢鼎不復支。',192,'全唐诗/poet.song.172000.json','["老賊狐鬼嘯，漢鼎不復支。", "再世益州牧，忍視宗國危。", "烈烈左將軍，四海聞英姿。", "東北久蕩析，西南天啟之。", "建旗入涪城，有蜀非公誰。", "檄璋送州印，我欲舉義師。", "鼠輩坐斂手，豪傑趨指麾。", "正爾豈不濟，安用譎取爲。", "孝直反覆士，獻計乃所宜。", "雛鳳獨何心，亦復喜出寄。", "造次盃酒間，而欲生嶮巘。", "平生大耳公，豈堪此瑕疵。", "向來隆中語，荆益實素期。", "惜不同茲役，次第觀所施。", "士元早捐世，未必爲漢悲。", "我詩訂千古，當有神明知。"]'),
('71eac178-a294-4a7d-9795-15eb37669dd9','定軍山歎','孫應時','宋','宋诗','song-poetry','','[]','仲達受巾幗，佐治來閉營。',204,'全唐诗/poet.song.172000.json','["仲達受巾幗，佐治來閉營。", "君看此情事，豈辦吾孔明。", "八陣有天威，千里無留行。", "但度渭水去，賊勢能不爭。", "便當截狼頭，三輔即日平。", "連年計茲役，獨坐糧運縈。", "所以五丈原，駐軍方雜耕。", "俶載維首夏，望望秋穀升。", "云何西風至，忽已落大星。", "痛哉萬世功，於此喪垂成。", "炎精遂淪謝，王路終榛荆。", "三馬肆蹄齧，羣雄迄縱橫。", "公乎少徐死，此禍何由生。", "天機定誰執，變化紛可驚。", "喬木定軍山，空有身後名。", "世論復鹵莽，嗚咽志士情。", "朗詠少陵詩，何誅陳壽評。"]'),
('36d1279b-5d20-4fbf-bb80-acd516fff111','勝果僧舍與葉養源論武侯出處作數韵記之','孫應時','宋','宋诗','song-poetry','','[]','隆中躬耕歸，抱膝詠梁父。',168,'全唐诗/poet.song.172000.json','["隆中躬耕歸，抱膝詠梁父。", "誰稱此卧龍，名字震東土。", "平生惟老龐，忘言各心許。", "相從亦何爲，誓不入州府。", "敲門劉豫州，見我欲安語。", "三來信勤懇，定非曹袁侶。", "社稷高帝孫，此公更儒苦。", "不辭爲君起，死生不相負。", "嗚呼豪傑士，所重在出處。", "人言漢丞相，阿衡師尚父。", "綸巾拜遺像，英氣凜千古。", "當時實少年，纔二十四五。", "風雲有時會，人物難浪與。", "諸賢誠慷慨，毋勞自夸詡。"]'),
('efb798ec-247c-4e33-a0eb-ae387b3911db','玉虛洞','孫應時','宋','宋诗','song-poetry','','[]','駕言玉虛游，奇絕慰心賞。',192,'全唐诗/poet.song.172000.json','["駕言玉虛游，奇絕慰心賞。", "餘雪明層陰，初旭上清朗。", "寒溪玻瓈色，遠壑風雨響。", "刺船度石瀨，散策步林莽。", "洞門劃褰開，瑶室下深廣。", "分明堂九筵，帢匝旗五丈。", "壁紋妙雕刻，石骨工剗磢。", "雲霞夾日月，麾幢導龍象。", "異哉非人境，儼然故仙仗。", "犬鹿訪前聞，笙鶴寄真想。", "天寶本衰運，靈扃爲誰敞。", "崢嶸昔祠殿，蕭瑟今廢壤。", "謝公詩絢麗，黄郎筆豪爽。", "斷碑亦可憐，英標復何往。", "把酒酹孤亭，回頭嘆塵鞅。", "幽討方自茲，當費屐幾兩。"]'),
('6abcd1bd-1e9a-4d64-98a6-7902509c2fc8','東歸留別幕中同舍  其一','孫應時','宋','宋诗','song-poetry','','[]','參謀蜀耆英，棠陰滿三郡。',48,'全唐诗/poet.song.172000.json','["參謀蜀耆英，棠陰滿三郡。", "開懷接兒輩，色不見喜慍。", "清朝貴老成，故家多典訓。", "佳氣引春帆，長安天日近。"]'),
('c3640d51-9903-47cf-aaac-2c8e07fe2038','東歸留別幕中同舍  其二','孫應時','宋','宋诗','song-poetry','','[]','梅溪千載人，我得交其子。',48,'全唐诗/poet.song.172000.json','["梅溪千載人，我得交其子。", "霜天行白日，了不受塵滓。", "明朝把一麾，闊步方自此。", "海內觀典刑，豈惟吾黨喜。"]'),
('8bb26852-79b1-4de8-a096-a94b0d775062','東歸留別幕中同舍  其三','孫應時','宋','宋诗','song-poetry','','[]','元祐賢子孫，忠肅家第一。',48,'全唐诗/poet.song.172000.json','["元祐賢子孫，忠肅家第一。", "豈惟富文雅，清苦用一律。", "君看我同年，踐履極真實。", "不待問著龜，公侯卦可必。"]'),
('6fb8e081-4709-4c04-a003-d99e716f7eae','東歸留別幕中同舍  其四','孫應時','宋','宋诗','song-poetry','','[]','大蓬有奇氣，人物見李侯。',48,'全唐诗/poet.song.172000.json','["大蓬有奇氣，人物見李侯。", "迥然謝凡質，霜鶻摩清秋。", "詔書相續來，去去躡瀛洲。", "汲直在漢庭，可寢淮南謀。"]'),
('ef010912-f61c-433e-8dc0-c2f0c9dde1c8','東歸留別幕中同舍  其五','孫應時','宋','宋诗','song-poetry','','[]','陳侯七閩秀，六年客西州。',48,'全唐诗/poet.song.172000.json','["陳侯七閩秀，六年客西州。", "蘭荃自芳潔，應世良優游。", "平生耐久朋，政復未易求。", "相期故不淺，抗節追前修。"]'),
('6474c552-51bd-42fa-8946-174f695c6d95','東歸留別幕中同舍  其六','孫應時','宋','宋诗','song-poetry','','[]','我家客星里，少小釣寂寞。',48,'全唐诗/poet.song.172000.json','["我家客星里，少小釣寂寞。", "推遷墮塵網，世味終然薄。", "萬里携一身，俛仰歎今昨。", "抖擻萊子衣，歸歟老林壑。"]'),
('3cd72ece-545a-4374-82c7-f3a69a127241','東歸留別幕中同舍  其七','孫應時','宋','宋诗','song-poetry','','[]','相從樂復樂，別離良獨難。',48,'全唐诗/poet.song.172000.json','["相從樂復樂，別離良獨難。", "傳觴秉明燭，起舞清夜闌。", "一醉何足辭，百年能幾歡。", "後會渺何許，相思江月寒。"]'),
('72e14525-e404-42f7-a9cb-208cefb8caf9','答季章和寄同舍韵  其一','孫應時','宋','宋诗','song-poetry','','[]','論交萬里外，意氣薄雲天。',48,'全唐诗/poet.song.172000.json','["論交萬里外，意氣薄雲天。", "孤舟日已遠，擁書夜無眠。", "驪珠從何來，光景明一川。", "櫝藏懷永好，欲報心茫然。"]'),
('da6f7797-911e-4da8-b302-2fc019160489','答季章和寄同舍韵  其二','孫應時','宋','宋诗','song-poetry','','[]','仙風自灑落，古氣更清深。',48,'全唐诗/poet.song.172000.json','["仙風自灑落，古氣更清深。", "雕几薦六瑚，定無塵土侵。", "儒生傳舊法，君子愛初心。", "願令百世下，重聽雲韶音。"]'),
('12ebda8c-fddf-4680-a21b-1962e126e2a8','元日自警','孫應時','宋','宋诗','song-poetry','','[]','王春肇嘉氣，天命未敢知。',48,'全唐诗/poet.song.172000.json','["王春肇嘉氣，天命未敢知。", "四十六年非，今日正一之。", "昭昭汝初心，敬戒以自持。", "神明監屋漏，此語不可欺。"]'),
('6adfb6c5-725b-43f9-bbf3-1b4255113924','自警','孫應時','宋','宋诗','song-poetry','','[]','忿燥肝或裂，懼劇膽能破。',72,'全唐诗/poet.song.172000.json','["忿燥肝或裂，懼劇膽能破。", "吾身幸無苦，及茲無迺過。", "虛中閲萬物，谷響聊應和。", "可令蟆蝕月，竟作蟻隨磨。", "根危實易感，驟嚥忽已唾。", "何當安如山，持用警昏惰。"]'),
('dd0dcdfa-1bce-48fc-9add-f454a6e9143d','寧庵即事','孫應時','宋','宋诗','song-poetry','','[]','颼颼松風鳴，翳翳山景暮。',72,'全唐诗/poet.song.172000.json','["颼颼松風鳴，翳翳山景暮。", "蟬聲清有餘，荷香美無度。", "幽人曳杖吟，事勝心獨悟。", "平生寡世念，正是愜襟素。", "坐看北斗移，竹葉明月露。", "夜久寂無人，佳眠不知曙。"]'),
('393f6a1f-84f7-4bc0-af2d-e010b2ad2b4d','道傍水行可愛','孫應時','宋','宋诗','song-poetry','','[]','寒風鳴歲陰，芸物已歸靜。',72,'全唐诗/poet.song.172000.json','["寒風鳴歲陰，芸物已歸靜。", "郊原何蕭瑟，松竹自清整。", "道傍足幽意，林屋甚井井。", "雞犬在籬落，沙水暮光映。", "古來奇逸士，往往託茲境。", "吾行將安得，悵望滄水永。"]'),
('f1a29378-18e6-4b9e-8ee7-096528af9d52','燈下學書偶成','孫應時','宋','宋诗','song-poetry','','[]','學書乃一樂，人或罕知趣。',144,'全唐诗/poet.song.172000.json','["學書乃一樂，人或罕知趣。", "而我欲成癖，矻矻了朝暮。", "天資苦凡弱，師法非早悟。", "目力又已衰，怳若在煙霧。", "雖然日數紙，就視輒自惡。", "旁人謬慫惥，定未識佳處。", "右軍固神品，大令亦體具。", "嫡傳張與顔，尚未肯懷素。", "頗怪近世評，似爲米老誤。", "雄奇在風骨，隠括須法度。", "安得再少年，令我進一步。", "人高書乃高，此語俗子怒。"]'),
('fdc788e4-9cee-4da5-be53-ffa89a2288c1','碧雲即事','孫應時','宋','宋诗','song-poetry','','[]','唧唧秋蛩鳴，耿耿秋夜長。',48,'全唐诗/poet.song.172000.json','["唧唧秋蛩鳴，耿耿秋夜長。", "簡篇負初心，枕簟怯新涼。", "朝曦入疎牖，宿雲散前岡。", "歸歟一葉舟，浩歌聽滄浪。"]'),
('4a1c266a-27fd-4b0f-a31c-ee060abe2885','和樓尚書賦趙大資重樓柏梁體','孫應時','宋','宋诗','song-poetry','','[]','浙中巖壑天下雄，越絕宛委吳穹窿。',352,'全唐诗/poet.song.172000.json','["浙中巖壑天下雄，越絕宛委吳穹窿。", "鍾奇角秀勞神工，復有四明冠南東。", "雲南雲北森橫縱，僊聖所宅光𤧚瓏。", "公樓極覽面面同，江霏海日開冥濛。", "翠屏列立千萬峰，勝畫孔雀繡芙蓉。", "春晴百花度香風，秋原下瞰禾黍芃。", "城郭游人紛蝶蜂，笙歌間發羅綺叢。", "我公心鏡百鍊銅，眼底萬物歸陶鎔。", "姬公胡留曲阜封，東平驃騎合侍中。", "小出勳業垂無窮，手扶日轂駕六龍。", "丹心正色羞容容，飄然謝出明光宮。", "坐收全名擅高蹤，錦衣故里還過逢。", "築室百堵聲隆隆，雅素不窮丹雘功。", "移花種竹親圃農，直嫌看山隔崇墉。", "層樓開豁星斗胸，晨登坐達夕鼓鼕。", "有書滿架酒不空，眼明脚健顔頰紅。", "身佩安危唐晉公，何妨綠野對洛嵩。", "文昌更似香山翁，與公勝日長相從。", "一談一笑如春濃，清歡不奏淫樂矇。", "高山流水操遞鍾，新篇絡繹疲奴僮。", "寒生感公恩義重，草根竊亦吟秋蟲。", "扁舟登門頻宿舂，敢逐炎凉如燕鴻。"]'),
('5d3855f4-4b13-45f6-b462-7838fd378ed8','遂安縣興學和詹本仁見贈詩','孫應時','宋','宋诗','song-poetry','','[]','萬物野馬相追奔，百年夢境更起仆。',288,'全唐诗/poet.song.172000.json','["萬物野馬相追奔，百年夢境更起仆。", "是中諸妄要掃刮，努力良心自成就。", "舞雩春風沂水側，當日羣公切磋究。", "大途九軌自可識，廣居安宅寧當僦。", "少年恐不保壯老，夜氣還能亡旦晝。", "詩書禮樂在庠序，鄉射絃歌列籩豆。", "共惟百聖貽後來，豈使一科圖急售。", "如何道術坐陸沉，獨指利名紛輻輳。", "斯文未喪天所賜，接踵諸賢出哀救。", "聖門榛棘得剗除，俗學膏肓有砭灸。", "晚出顓蒙格調卑，平生師友追從舊。", "敢言割雞慕牛刀，直恐狐裘雜羔袖。", "是邦山水故瀟洒，滿眼衣冠多整秀。", "向來張呂相逢地，遺韵餘風洗凡陋。", "眷然鄉校肯來游，勉矣英材起相副。", "名門政假扶持力，闔境似驚聞見驟。", "儒林丈人真好事，大筆新詩警昏瞀。", "寄言同社相知心，不怪狂歌續貂後。"]'),
('c9425658-8f40-4aea-aba3-f2e6d4873114','答楊霖用前韻見贈','孫應時','宋','宋诗','song-poetry','','[]','滄滄萬里無時盈，太山四維不可仆。',288,'全唐诗/poet.song.172000.json','["滄滄萬里無時盈，太山四維不可仆。", "蛙井跳梁徒自喜，蟻垤崔嵬欲何就。", "物情小大乃爾懸，人心是非當自究。", "榮名乍滿妻孥笑，權利偏供賓客僦。", "紛紛逐臭坐窮年，往往攫金忘正晝。", "談誇亦或輕萬鍾，蹴嘑忍能甘一豆。", "人憐世網苦易縛，我悲古道迂難售。", "文章小技本游戲，功業有時真際輳。", "六經墜地誰羽翼，衆說滔天誰拯救。", "獨行不畏迹隨削，危言便恐眉遭灸。", "舞雩鼓瑟洙泗遠，弄月吟風伊洛舊。", "晨霞翠柏足餱糧，秋蘭芳芷堪懷袖。", "此身今愧五斗役，歸心日繞千巖秀。", "平生未飽書冊願，老大自知人物陋。", "意存當世力不能，名忝儒生實難副。", "楊侯楊侯豪傑士，霜鶻橫空天馬驟。", "叵堪高誼謬推挽，喜見雄詞豁昏瞀。", "端能有意千載前，執鞭請試從公後。"]'),
('df7c891f-fba0-4561-8e5f-66237e3c7e4c','鄞川道中呈友人','孫應時','宋','宋诗','song-poetry','','[]','青山不斷煙蒼蒼，梅花如雪東風香。',64,'全唐诗/poet.song.172000.json','["青山不斷煙蒼蒼，梅花如雪東風香。", "春來天地恰十日，眼見草木生輝光。", "清溪行舟暮鳴櫓，並舡開樽共君語。", "人生邂逅自可憐，明日江東聽江雨。"]'),
('eff4fc64-7bfc-494f-beb9-bf1840be3212','斗南竹林祠歌','孫應時','宋','宋诗','song-poetry','','[]','君不見唐河諸將兵馬回，河朔百城門不開。',243,'全唐诗/poet.song.172000.json','["君不見唐河諸將兵馬回，河朔百城門不開。", "邊烽夜舉天子怒，六龍曉發鳴春雷。", "金陵玉壘中道惑，澶淵一擲吁難哉。", "當時事勢在國史，萊公之功不其偉。", "幽燕可還敵可臣，西顧寧論夏州李。", "用公不盡天所惜，天不生公更誰恃。", "嗟公雄豪從少年，如虎在山龍在淵。", "淮陰指掌楚歸漢，望諸叱咤齊爲燕。", "兩朝五起豈不遇，膠漆擺撼難爲堅。", "癭相讒巧亦云極，鶴相惡謀何卒卒。", "青衫到骭吾一咍，羊酒迎道爾堪恤。", "可憐夷獠護裝橐，想見神明扶正直。", "公安插竹南遷時，手回造化理不疑。", "雲車風馭今來否，迎神送神姑爾爲。", "蕭蕭寒綠泣江雨，長似襄陽墮淚碑。"]'),
('ff0db39e-2698-455b-bcb5-74450deb274c','沌中即事','孫應時','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','武昌西南雲夢澤，水平不動玻璃碧。',192,'全唐诗/poet.song.172000.json','["武昌西南雲夢澤，水平不動玻璃碧。", "葭蘆莽蒼生暮煙，楊柳蕭條带秋色。", "北接滄浪南洞庭，八九百里荒荒白。", "一渠紆縈十日行，巧避江濤如過席。", "平生聞說沌魚美，滿籃不受百錢直。", "我來漲潦漁者稀，罾網高懸釣竿擲。", "葦屋人家絕可憐，欲沒未沒三四尺。", "倚樹爲巢葑作床，剝菱炊菰自朝夕。", "青裙皂髻長兒女，城市繁華豈曾識。", "屋頭一艇是生涯，丁算未必逃官籍。", "迢迢客路幾歎息，茫茫宇宙何終極。", "有酒無魚莫浪愁，獨醉月明聽吹笛。"]'),
('b41910d3-a317-4a0b-a8a9-51d130e0a9f2','巫山歌','孫應時','宋','宋诗','song-poetry','','[]','平生想巫山，奇絕冠三峽。',120,'全唐诗/poet.song.172000.json','["平生想巫山，奇絕冠三峽。", "及茲飽雙眸，無乃天下甲。", "遠看插天碧叢叢，近看玲瓏金玉峰。", "垠崖光彩相映發，交絡紫翠疎蒙茸。", "雲華夫人瑶池女，何物纔至得奇遇。", "我來初日明輕霞，更勝朝雲暮行雨。", "水轉峰回無定姿，地靈天巧奇復奇。", "少陵山谷不著語，浪作推敲君定癡。"]'),
('a6038467-cfcb-4ca6-8b95-f26023cf244c','峽中歌','孫應時','宋','宋诗','song-poetry','','[]','峽中翠壁何崢嶸，排空百雉如層城。',280,'全唐诗/poet.song.172000.json','["峽中翠壁何崢嶸，排空百雉如層城。", "重樓複道明丹青，神剜鬼刻斧鑿精。", "呀然裂入兀不崩，飛流罅出懸珠瓔。", "旌旆夾道繽逢迎，霜鋒雪鍔立萬兵。", "奇峰十二劍削成，真贋等好不可評。", "天柱拔立千仞擎，團團石骨瑩玉冰。", "傍有巖穴半開扃，飛仙之宅凝神清。", "蝦蟆下飲腹不盈，背負陰壑深窈冥。", "金碧滿洞層雲生，泓泉泠泠琴筑鳴。", "林端黄牛老不耕，灘回白日隨人行。", "石馬隻耳夢偶靈，神祠簫鼓何鏗鏗。", "江流萬古鬰不平，四時雷霆風雹聲。", "天垂匹練相回縈，日月避隠韜光明，朝雲暮雨犬吠晴。", "山腹人家真畫屏，亦有竹閣連松亭。", "褰裳可登呼可譍，但愁蠻語無由聽。", "我來泝峽纔幾程，所見如許心骨驚。", "陽臺灧澦次第經，磨礪筆鋒吾敵勍。"]'),
('f84fb9c4-80b8-4880-a310-c7c50b70353c','劍門行','孫應時','宋','宋诗','song-poetry','','[]','兩崖夾道立削鐵，澗水悲鳴淺飛雪。',128,'全唐诗/poet.song.172000.json','["兩崖夾道立削鐵，澗水悲鳴淺飛雪。", "上有石城連天橫，劍戟相磨氣明滅。", "出門下瞰山盤紆，石磴斗落十丈餘。", "敵來仰首不得上，百萬渠能當一夫。", "井蛙未識河山廣，分明到此生狂想。", "豈知天險乃誤人，禍首子陽終衍昶。", "渭水秦川指顧中，劍門空復老英雄。", "傳檄將軍真得意，落星愁殺卧龍翁。"]'),
('86834294-d65e-490a-a09b-26be540aced7','三泉龍門','孫應時','宋','宋诗','song-poetry','','[]','蒼山石骨高稜層，繚斷谷口如堅城。',160,'全唐诗/poet.song.172000.json','["蒼山石骨高稜層，繚斷谷口如堅城。", "何年穴作甕門入，豁然天地中開明。", "門深十丈碧鐵色，錯落鱗甲潛光晶。", "溪聲瀉出駭風雨，巖泉亂滴紛珠瓔。", "老藤翠木蔚回合，幽花好鳥相逢迎。", "異哉人世有此境，顧盼蕭爽心骨驚。", "想見伏龍擘山出，澒洞冰雹轟雷霆。", "不然避秦客仙去，中有桃花門不扃。", "谷深路窈望不極，有泉可濯田可耕。", "何當顓此一丘壑，家在東吳空復情。"]'),
('8b128d6f-bc3b-4bc9-ba60-f1336a12c169','梁山劉制參園亭','孫應時','宋','宋诗','song-poetry','','[]','劉侯家有相業堂，東都舊第城中央。',176,'全唐诗/poet.song.172000.json','["劉侯家有相業堂，東都舊第城中央。", "劍南參謀今白髮，官班且復尚書郎。", "買田築室蟠龍下，閨門孝友師一鄉。", "好園十畝當道入，綠竹萬箇攙天長。", "池亭面勢各有趣，花木手種新成行。", "客來呼酒徑留飲，小鬟妙舞工持觴。", "人生適意但如此，何用塵土紛劻勷。", "我來度峽五十日，山深路惡神慘傷。", "眼明此邦萬石壩，况逢好事容徜徉。", "野鶴寮中最清絕，蠟梅水仙方弄香。", "爲公一醉出門去，祝公眉壽長康彊。"]'),
('cf3fdabe-0d9c-4c53-a53b-bf1f50ccc80d','同邱直長和歐公三游洞韵','孫應時','宋','宋诗','song-poetry','','[]','維舟下牢關，散策上西嶺。',152,'全唐诗/poet.song.172000.json','["維舟下牢關，散策上西嶺。", "天風吹我裳，恍惚非人境。", "丹崖翠壁明空山，呀然洞府葱蘢間。", "珊瑚爲門玉爲裏，石骨千年凝綠髓。", "伏龍奇鬼相回環，窗戶玲瓏五雲起。", "風馬霓旌去不留，棋牀丹竈巖之幽。", "流水潺潺山寂寂，時有野鶴飛迎客。", "提携琴酒聊一歡，呼取漁樵任爭席。", "日暮欲歸歸路迷，襟期浩蕩誰當知。", "好種桃花便終老，更尋何處武陵溪。"]'),
('29f1feeb-fd92-406d-bac4-6669983dcbaa','送別宋金州','孫應時','宋','宋诗','song-poetry','','[]','安康使君發成都，羣公祖送車塞途。',155,'全唐诗/poet.song.172000.json','["安康使君發成都，羣公祖送車塞途。", "秋風關山二千里，王命不得辭崎嶇。", "使君世族楚彭城，家今會稽之上虞。", "我居咫尺不早識，萬里相逢天一隅。", "眼中豪傑未易得，使君人物當代無。", "連年三取太守印，赫然帥鉞兼兵符。", "不憂無地起勳業，所要許國存規橅。", "貴人例急歌舞娛，使君善愛千金軀。", "國恥未雪長荷殳，一念勿忘先大夫。", "嗚呼，一念勿忘先大夫。"]'),
('04bf6e3f-31f4-4314-9c33-730420959d5b','傅惟肖贊府假西遊集作長篇送還奇甚次其韵','孫應時','宋','宋诗','song-poetry','','[]','醉鄉不遊遊睡鄉，眼花對案如迷藏。',240,'全唐诗/poet.song.172000.json','["醉鄉不遊遊睡鄉，眼花對案如迷藏。", "夢踏秋草悲蛩螿，風松露菊三徑荒。", "忽然欠伸日在廊，悟此身世何荒唐。", "故書棄擲塵滿箱，魯堂不復聞絲簧。", "鏡中容顔老不揚，浪求斗升助糟糠。", "江湖蘭珮芙蓉裳，踟躕不歸愁斷腸。", "偉君威鳳鳴朝陽，文章五色照我傍。", "艷如屈宋班馬香，千載作者蔚相望。", "對床泮水月滿堂，追游山椒款寶坊。", "劇談發我平生狂，劃如乘風上翺翔。", "蒼蒼雲海一葦航，周流四方來故鄉。", "羣兒醉飽死不償，我獨與君酌天漿。", "紛紛爝火明寒窗，何如光芒萬丈長。", "空吟平子四愁章，欲報英瓊無可將。", "明朝癡兒公事忙，從今謝君當括囊。"]'),
('0c99c2e5-6d3d-4e1d-a4c3-4d19d20f87f9','永康虎頭山','孫應時','宋','宋诗','song-poetry','','[]','去年東上虎頭灘，今年西踏虎頭山。',64,'全唐诗/poet.song.172000.json','["去年東上虎頭灘，今年西踏虎頭山。", "定無萬里封侯相，且復兩川行脚還。", "眼中金馬碧雞路，坐上銅梁玉壘關。", "丈夫萬事付前定，長嘯往來天地間。"]'),
('627f3d69-0fe5-471d-ad1c-10ec9feb1178','夜深至寧庵見壁間端禮昆仲倡和明日次其韵','孫應時','宋','宋诗','song-poetry','','[]','杉松廡門森老蒼，佛屋深夜幡花香。',64,'全唐诗/poet.song.172000.json','["杉松廡門森老蒼，佛屋深夜幡花香。", "借床健倒怳何處，夢隨潛魚聽夜榔。", "咿啞禽語曉光浄，蟋蟀草鳴朝雨涼。", "哦詩出門懷二妙，春漲遶山湖水黄。"]'),
('b072ee4e-3396-4ead-8553-de0687cc662f','和答陸華父  其一','孫應時','宋','宋诗','song-poetry','','[]','幽蘭懷春風，葭蓬亦芽茁。',68,'全唐诗/poet.song.172000.json','["幽蘭懷春風，葭蓬亦芽茁。", "同時不同調，物物自生活。", "士窮不自食，苦學代耕獵。", "文如六經非小伎，餘事不足置牙齒。", "人言擲盧勝擲雉，我言函人不爲矢。"]'),
('fa4e81a0-1312-4103-8e68-419e40062f74','和答陸華父  其二','孫應時','宋','宋诗','song-poetry','','[]','雒都有佳人，高卧雪塞戶。',76,'全唐诗/poet.song.172000.json','["雒都有佳人，高卧雪塞戶。", "千載尚可期，一寒那足顧。", "功名誠儻來，貧賤有難去。", "食竹豈非鳳，食蟲豈非雞。", "騶虞世不識，羔豚日刳刲。", "且須拊掌共一笑，坐上鴟夷能滑稽。"]'),
('66cb1935-110a-4bb9-bae0-c95298ce3b9c','和答潘端叔見寄','孫應時','宋','宋诗','song-poetry','','[]','髮白念少年，萬事風雨過。',100,'全唐诗/poet.song.172000.json','["髮白念少年，萬事風雨過。", "倦游得來歸，一切付懶惰。", "獨抱杞天憂，徬徨意無奈。", "濠魚定何樂，幕燕渠敢賀。", "歎君陽春詞，激我巴里和。", "古來奇特事，信是英雄作。", "東山有晚遇，西山有終餓。", "拭目須君早著鞭，乞與高人北窗卧。"]'),
('1c2858a8-4e01-430f-a059-c7dc3e67d9fa','頃過周叔和見故人石應之詩及諸賢和篇大軸邀余繼韵久不暇遣因通五夫諸李丈書劃然有懷走筆寄之','孫應時','宋','宋诗','song-poetry','','[]','別君二十年，往事飛鳥過。',100,'全唐诗/poet.song.172000.json','["別君二十年，往事飛鳥過。", "相逢歌慷慨，頗復起衰惰。", "朱顔各華髮，此已無可奈。", "結廬擅青山，吾獨爲君賀。", "示我諸賢詩，三歎不忍和。", "功名付千載，袖出莫輕作。", "老去會有死，嗟來不如餓。", "燭湖旁舍酒可沽，勝日相從同醉卧。"]'),
('07ad893c-5a59-4604-99df-fc30ce0fb8fc','中秋次仲兄韵','孫應時','宋','宋诗','song-poetry','','[]','萬古清秋月，連年滿意晴。',48,'全唐诗/poet.song.172000.json','["萬古清秋月，連年滿意晴。", "坐從衣露濕，目恐海雲生。", "盎盎盃中趣，悠悠世上名。", "柴門幸無客，不用酌公榮。"]'),
('ff0094b1-3558-4949-b6d3-a6f41ef3344f','杜子貞遠訪自言山居之勝以二詩送之  其一','孫應時','宋','宋诗','song-poetry','','[]','識子雲溪上，天星已再周。',48,'全唐诗/poet.song.172000.json','["識子雲溪上，天星已再周。", "故人今略盡，斯世果何求。", "得喪元相似，乘除豈自謀。", "初心幸無恙，餘事一虛舟。"]'),
('18c3a727-2b3e-4041-b664-54e8dee3b1d5','杜子貞遠訪自言山居之勝以二詩送之  其二','孫應時','宋','宋诗','song-poetry','','[]','喜說山居勝，蘭亭一盼中。',48,'全唐诗/poet.song.172000.json','["喜說山居勝，蘭亭一盼中。", "松楸今十世，竹帛故三公。", "念德心何極，幽栖道未窮。", "吾歸訪巖壑，雞黍更誰同。"]'),
('7c4e5f7f-65d5-498d-9337-0ee6bded25bf','山庵秋夕','孫應時','宋','宋诗','song-poetry','','[]','山晚下樵牧，秋聲生夜長。',48,'全唐诗/poet.song.172000.json','["山晚下樵牧，秋聲生夜長。", "精廬脫塵想，倦枕愜新涼。", "萬里一筇在，百年雙鬢蒼。", "定知閒有味，不必醉爲鄉。"]'),
('bc38059a-8a94-4d8b-8fb7-b4472d79b1d9','十七夜如山庵','孫應時','宋','宋诗','song-poetry','','[]','一雨秋能好，連宵月迥明。',48,'全唐诗/poet.song.172000.json','["一雨秋能好，連宵月迥明。", "百年今夕話，萬里去年情。", "水滿天相蕩，山空人獨行。", "蟬聲發奇思，携酒未須傾。"]'),
('b123ccc5-5a9b-4903-9c4e-4b829588d0fd','宿寶墟庵','孫應時','宋','宋诗','song-poetry','','[]','水靜回風度，天晴落日酣。',48,'全唐诗/poet.song.172000.json','["水靜回風度，天晴落日酣。", "因隨漁子艇，得憇野僧庵。", "獨飲不成醉，高懷無與談。", "微吟夜寥閴，一睡極清甘。"]'),
('6c6ccd60-e38e-4095-8be5-18166e049b7a','晨興有歎','孫應時','宋','宋诗','song-poetry','','[]','月落霜如雪，風回水正冰。',48,'全唐诗/poet.song.172000.json','["月落霜如雪，風回水正冰。", "百思勞夜夢，多病怯晨興。", "世事甘牢落，心期獨戰兢。", "床頭書在眼，且莫負寒燈。"]'),
('46c7383b-48ca-4b0d-8f3a-754c0b568666','晚望','孫應時','宋','宋诗','song-poetry','','[]','倚杖柴門外，蟬聲晚正清。',48,'全唐诗/poet.song.172000.json','["倚杖柴門外，蟬聲晚正清。", "水涵初月白，山對落霞明。", "心迹真無事，行藏付此生。", "鄰翁過相語，有喜近西城。"]'),
('70aed185-3a87-4bcb-90bb-6a62475fabff','隆興甲申仲冬回自郡城宿龍泉寺遇雪','孫應時','宋','宋诗','song-poetry','','[]','乘興登山寺，匆匆未暇歸。',48,'全唐诗/poet.song.172000.json','["乘興登山寺，匆匆未暇歸。", "偶逢天色變，忽見雪花飛。", "佛屋渾迷瓦，僧房半掩扉。", "坐看青嶂老，一笑透禪機。"]'),
('b05dc4d0-29de-471d-bc7f-989197d239b3','秋曉','孫應時','宋','宋诗','song-poetry','','[]','高葉明初日，偏林澹遠烟。',48,'全唐诗/poet.song.172000.json','["高葉明初日，偏林澹遠烟。", "晴空如滉漾，秋氣更暄妍。", "睡足小窗浄，心清浮慮捐。", "與人同樂意，憂國見豐年。"]'),
('be2ced89-7cf0-42d6-823a-9357b84a9881','曉晴  其一','孫應時','宋','宋诗','song-poetry','','[]','碧海明初日，青山破宿煙。',48,'全唐诗/poet.song.172000.json','["碧海明初日，青山破宿煙。", "寒陰都辟易，芳景正澄鮮。", "屋角禽聲姹，池塘蝶影翩。", "春光吾負汝，今日一欣然。"]'),
('fe30ddb2-d0a7-4483-b9fb-49cd929358b5','曉晴  其二','孫應時','宋','宋诗','song-poetry','','[]','君行定何許，捨棹越林丘。',48,'全唐诗/poet.song.172000.json','["君行定何許，捨棹越林丘。", "社甕不容挽，溪毛聊可羞。", "禪床應濯足，衲被徑蒙頭。", "靜境有真趣，樂哉何所憂。"]'),
('e806a9bd-41e2-4182-98fe-44b8a845ad9c','曉晴  其三','孫應時','宋','宋诗','song-poetry','','[]','短髮日夜白，年華令我愁。',48,'全唐诗/poet.song.172000.json','["短髮日夜白，年華令我愁。", "平生幾蠟屐，舊隠一漁舟。", "漫有詩陶寫，應須酒拍浮。", "相過慰情素，數肯抱琴不。"]'),
('6007e6a0-9ca9-4d44-ad97-5614eded0efa','慈溪道中次伯兄韵','孫應時','宋','宋诗','song-poetry','','[]','露洗三更月，秋澄萬里天。',48,'全唐诗/poet.song.172000.json','["露洗三更月，秋澄萬里天。", "潮生聲蕩潏，雲渡影聯翩。", "物妙本無盡，世分直可憐。", "悠然一杯酒，橫策自鳴舷。"]'),
('50fe0a14-b023-43f4-8a59-8ee8b2b0259c','送史同叔司直造朝  其一','孫應時','宋','宋诗','song-poetry','','[]','天壤王郎子，芝蘭謝傅家。',48,'全唐诗/poet.song.172000.json','["天壤王郎子，芝蘭謝傅家。", "班行想風采，詩禮倍光華。", "萬里鞭先著，連城玉未瑕。", "公餘閉齋閣，黄卷有生涯。"]'),
('3660bbf1-6d90-41cc-af15-6f9e8f8fe6aa','送史同叔司直造朝  其二','孫應時','宋','宋诗','song-poetry','','[]','相國三槐位，郎君疊桂枝。',48,'全唐诗/poet.song.172000.json','["相國三槐位，郎君疊桂枝。", "談經天祿閣，指日鳳凰池。", "道術千年緒，功名百世期。", "中朝呂范氏，端的有餘師。"]'),
('77c812f1-9ecb-4b6f-8dc4-6fb1b573b11c','次仲氏韵','孫應時','宋','宋诗','song-poetry','','[]','客裏三年恨，歸來百慮輕。',48,'全唐诗/poet.song.172000.json','["客裏三年恨，歸來百慮輕。", "靜堪眠夜雨，夢不數郵程。", "荒徑九節杖，凉窗二尺檠。", "吾生本易足，此外復何營。"]'),
('780cd27f-5c34-4da2-826f-19e54b5f7ca8','詒姪生日','孫應時','宋','宋诗','song-poetry','','[]','吾惟兩猶子，汝復近成童。',48,'全唐诗/poet.song.172000.json','["吾惟兩猶子，汝復近成童。", "已枉十年讀，何時萬卷通。", "聖賢垂日月，豪傑起雲風。", "燈火清秋夜，宜加百倍功。"]'),
('c5aecf3b-3d66-410c-aec4-ae0d129a6c77','醉中五言一首送楊叔與昆仲','孫應時','宋','宋诗','song-poetry','','[]','一杯分夕露，連璧映清湖。',48,'全唐诗/poet.song.172000.json','["一杯分夕露，連璧映清湖。", "北道山方好，西風暑况徂。", "掄才終遠器，發軔更良圖。", "腸斷山陽賦，看君氣一蘇。"]'),
('dc6559a0-21d1-4a78-b3f0-0d33ce0d90bc','送史同叔知池州  其一','孫應時','宋','宋诗','song-poetry','','[]','弄水亭無恙，青溪古畫圖。',48,'全唐诗/poet.song.172000.json','["弄水亭無恙，青溪古畫圖。", "民風最淳朴，郡計足枝梧。", "漢璽行褒召，潘輿且燕娛。", "平生故人意，未改歲寒無。"]'),
('fd1a008b-b724-48ed-bd71-5fdebb005ee6','送史同叔知池州  其二','孫應時','宋','宋诗','song-poetry','','[]','人地維垣後，功名治郡初。',48,'全唐诗/poet.song.172000.json','["人地維垣後，功名治郡初。", "細尋循吏傳，少輟子雲書。", "鈴閤閒無奈，江山興有餘。", "由來形勝地，保障定何如。"]'),
('53572bf0-afd2-43a8-983a-fcd3adb4b323','予頃至鄞中常館同叔之筠軒修篁交陰奇石中峙清風爽致襲人肌骨今年夏又假榻數夕嘗得小詩以示同叔因其通書寫寄池陽郡齋','孫應時','宋','宋诗','song-poetry','','[]','玉立衆君子，巖瞻一丈夫。',48,'全唐诗/poet.song.172000.json','["玉立衆君子，巖瞻一丈夫。", "老蒼何突兀，密節各敷腴。", "風日清如許，塵埃到得無。", "主人三益友，不厭著臞儒。"]'),
('5e4d10c2-3d8b-4d1c-ba0e-8e0a36d4c673','和仲氏除夕書懷','孫應時','宋','宋诗','song-poetry','','[]','頭顱遂如許，忽忽意多違。',48,'全唐诗/poet.song.172000.json','["頭顱遂如許，忽忽意多違。", "漸合知天命，能無悟昨非。", "春觴欣母壽，秋穀爲民祈。", "猿鶴應催我，塵埃好振衣。"]'),
('628f0720-1011-4efa-8728-f56f583b23ad','新春書懷','孫應時','宋','宋诗','song-poetry','','[]','樂國急春早，寒窗獨夜分。',48,'全唐诗/poet.song.172000.json','["樂國急春早，寒窗獨夜分。", "舊期心不動，今恐老無聞。", "結習唯黄卷，凝愁奈白雲。", "梅梢香漸少，還起炷爐薰。"]'),
('1f23df36-863d-4b37-a1f8-f618ecce3366','送高南仲之華亭','孫應時','宋','宋诗','song-poetry','','[]','子向雲間去，吾空澤畔吟。',48,'全唐诗/poet.song.172000.json','["子向雲間去，吾空澤畔吟。", "長因句中眼，不忘別時心。", "梁木蟠根大，淵泉汲綆深。", "丈夫千載事，莫待鬢霜侵。"]'),
('82d6617d-e805-4cfd-925f-7f558d9dbb01','送高南伯入太學','孫應時','宋','宋诗','song-poetry','','[]','我昔橋門客，于今喜送君。',48,'全唐诗/poet.song.172000.json','["我昔橋門客，于今喜送君。", "天資自金玉，風味更蘭薰。", "各爲親年重，難忘別意勤。", "功名何必問，怒翼正垂雲。"]'),
('878133a7-9a2b-46b9-aa9f-765975924d90','留妻兄張伯高  其一','孫應時','宋','宋诗','song-poetry','','[]','千里三年別，輪腸日萬周。',48,'全唐诗/poet.song.172000.json','["千里三年別，輪腸日萬周。", "交親誰得似，聲氣早相求。", "把手兒能笑，開樽婦可謀。", "天寒須且住，未放剡溪舟。"]'),
('be41e957-b797-4b70-a0f8-85c9dc9ff3f3','留妻兄張伯高  其二','孫應時','宋','宋诗','song-poetry','','[]','歎息青雲器，功名指掌中。',48,'全唐诗/poet.song.172000.json','["歎息青雲器，功名指掌中。", "星星今一老，衮衮看諸公。", "飲劇休辭醉，文高不送窮。", "丈夫心事在，未許俗人同。"]'),
('f1108c44-0e44-49d2-9343-3f8c484576f5','冬十月赴官海陵過會稽諸生飲餞魯墟橋酒罷就舟倦甚眷然有作','孫應時','宋','宋诗','song-poetry','','[]','體倦知茵薄，寒侵覺歲高。',48,'全唐诗/poet.song.172000.json','["體倦知茵薄，寒侵覺歲高。", "功名兩蝸角，人物九牛毛。", "行意看飛鳥，離歌指大刀。", "依依紅葉樹，回首入秋毫。"]'),
('7fa3aef1-31c4-4891-91cb-8c03eb72ea48','海陵歲暮  其一','孫應時','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','地氣長江北，雲容古戍邊。',48,'全唐诗/poet.song.172000.json','["地氣長江北，雲容古戍邊。", "層冰明薄日，積雪了窮年。", "鄉遠勞羈夢，官閒足晏眠。", "客來相勞苦，不責坐無氈。"]'),
('3460ab27-c711-4e49-b35a-6685d614c3d2','海陵歲暮  其二','孫應時','宋','宋诗','song-poetry','','[]','獵騎呼鷹地，胡笳落雁邊。',48,'全唐诗/poet.song.172000.json','["獵騎呼鷹地，胡笳落雁邊。", "梅花非故里，草色近新年。", "莫苦登樓望，聊須殢酒眠。", "江南多貴將，歌舞悵垂氈。"]'),
('8c25b3bb-90a2-4f34-8959-dda5df0df528','海陵歲暮  其三','孫應時','宋','宋诗','song-poetry','','[]','城郭依荒草，風雲带極邊。',48,'全唐诗/poet.song.172000.json','["城郭依荒草，風雲带極邊。", "猶多故時老，共說太平年。", "歲聘皇華去，秋防戍鼓眠。", "誰知明主意，拊髀憶青氈。"]'),
('c711f2c2-9d07-4c32-bd44-8d6bb8171eaa','正月二十八日避難至海陵從先流寓兄弟之招仍邂逅馮元禮故人二首之一','孫應時','宋','宋诗','song-poetry','','[]','百閑身猶在，尪羸怯鏡看。',48,'全唐诗/poet.song.172000.json','["百閑身猶在，尪羸怯鏡看。", "干戈朝食拙，風雨夜眠難。", "天際旄頭遠，淮南春首寒。", "病夫藥裹外，兄弟爲謀安。"]'),
('845bffe2-8899-40b9-a1a2-79537da7d18d','秋雨復將害稼  其一','孫應時','宋','宋诗','song-poetry','','[]','頗怪秋頻雨，兼疑暑頓涼。',48,'全唐诗/poet.song.172000.json','["頗怪秋頻雨，兼疑暑頓涼。", "歲方祈有駜，夢豈誤無羊。", "敢與朝廷議，唯觀宇宙康。", "由來誇上瑞，不必頌芝房。"]'),
('2e77cbe0-4009-4239-b0a6-b79fc5d724fd','秋雨復將害稼  其二','孫應時','宋','宋诗','song-poetry','','[]','廢圃餘荒徑，扶筇獨往來。',48,'全唐诗/poet.song.172000.json','["廢圃餘荒徑，扶筇獨往來。", "未愁風脫葉，生怕雨添苔。", "得與民心樂，何妨笑口開。", "神龍應念我，落日首重回。"]'),
('3b44853f-4a8d-427a-9f95-0e207d6b3dda','秋雨旬日偶成','孫應時','宋','宋诗','song-poetry','','[]','積雨斷行迹，滿門秋草深。',48,'全唐诗/poet.song.172000.json','["積雨斷行迹，滿門秋草深。", "老禾眠水底，野菌出牆陰。", "懶負讀書眼，閒多憂國心。", "夜長幽夢短，清耳聽蟲吟。"]'),
('32aebf39-2899-48f5-8e4f-417ed8f6f1d4','宿上方院禱晴','孫應時','宋','宋诗','song-poetry','','[]','鵲爲晚晴喜，山如秋夜凉。',48,'全唐诗/poet.song.172000.json','["鵲爲晚晴喜，山如秋夜凉。", "蟬聲起竽瑟，雲影散牛羊。", "神理應難昧，民憂得自康。", "平生蔬笋腹，不厭宿僧房。"]'),
('24ceb086-d795-4531-9bb2-8275b232a5c1','丁未仲夏海陵官舍家大人賞月作詩恭和元韵','孫應時','宋','宋诗','song-poetry','','[]','官署成鄉社，人圓月正圓。',48,'全唐诗/poet.song.172000.json','["官署成鄉社，人圓月正圓。", "清歡閒裏共，真樂酒中全。", "興到因懷舊，詩成擬問天。", "芳樽幸長照，後會敢遷延。"]'),
('50363c8f-faf9-466e-8fa2-632dadbe27dd','伊川先生祠','孫應時','宋','宋诗','song-poetry','','[]','平生子程子，此地有精廬。',48,'全唐诗/poet.song.172000.json','["平生子程子，此地有精廬。", "隠几江聲在，當窗林影疎。", "百年心未死，再拜意何如。", "可忍蹉跎老，長慚案上書。"]'),
('46d4525a-0466-4d27-bd13-bc7a0dafc312','早秋獨出初行邑西湖','孫應時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雙湖带山郭，三歲甫來過。',48,'全唐诗/poet.song.172000.json','["雙湖带山郭，三歲甫來過。", "獵獵葭蘆老，飛飛鴻鴈多。", "晨暉明野樹，晚思渺煙波。", "懷我孤山下，歸歟具一蓑。"]'),
('2a472693-d709-40ad-927d-f10cfafd2c13','挽吳給事芾  其一','孫應時','宋','宋诗','song-poetry','','[]','人物中興後，猗公一世雄。',48,'全唐诗/poet.song.172000.json','["人物中興後，猗公一世雄。", "虹蜺輝霽景，山岳鎮頹風。", "用舍關輕重，聲名擅始終。", "堂堂今日盡，海宇盡哀恫。"]'),
('3bd8643f-e5a5-4bd2-927e-f2e902552510','挽吳給事芾  其二','孫應時','宋','宋诗','song-poetry','','[]','早歲規模大，中年出處明。',48,'全唐诗/poet.song.172000.json','["早歲規模大，中年出處明。", "兩朝高獻納，六郡凜威名。", "雖作收身去，終餘報國誠。", "秣陵天下計，惆悵此時情。"]'),
('6b06f1ba-18b7-40f1-9f44-6c18f69394de','挽吳給事芾  其三','孫應時','宋','宋诗','song-poetry','','[]','里社湖山勝，歸休十四年。',48,'全唐诗/poet.song.172000.json','["里社湖山勝，歸休十四年。", "千鍾窮燕賞，雙劍去聯翩。", "家有遺經盛，名今太史傳。", "欺心儻容髮，天豈許公全。"]'),
('3c64ed1f-eee5-4b18-b876-06e6c6cd18d5','挽吳給事芾  其四','孫應時','宋','宋诗','song-poetry','','[]','與世栽桃李，身閒意不衰。',48,'全唐诗/poet.song.172000.json','["與世栽桃李，身閒意不衰。", "涓塵猶奬錄，尺寸各扶持。", "永恨登門約，空傳墮淚碑。", "微生渺何極，不敢負公知。"]'),
('61112cf4-45c5-440a-92fc-7273d4791b5e','送司馬尊古赴平江戶掾','孫應時','宋','宋诗','song-poetry','','[]','文獻傳家舊，功名發軔初。',48,'全唐诗/poet.song.172000.json','["文獻傳家舊，功名發軔初。", "榮華勸行色，珍重別吾廬。", "老醜渾無頼，殷勤獨未疎。", "西來多雁字，數寄一行書。"]'),
('e98ee759-3602-4c9e-915d-394addf37f8a','挽石應之提刑  其一','孫應時','宋','宋诗','song-poetry','','[]','天姥千年秀，西京萬石孫。',48,'全唐诗/poet.song.172000.json','["天姥千年秀，西京萬石孫。", "蟬聯書雁塔，鼎盛說龍門。", "奮建光前躅，封胡藹後昆。", "寢門今日淚，悽斷不堪論。"]'),
('be2d04bd-e901-4289-a23e-ed9ca10b9a2c','挽石應之提刑  其二','孫應時','宋','宋诗','song-poetry','','[]','芹泮青燈夜，山亭皂蓋春。',48,'全唐诗/poet.song.172000.json','["芹泮青燈夜，山亭皂蓋春。", "重更雙使節，總爲兩淮民。", "德意人人浹，工夫事事新。", "帝城車馬外，纔此寄經綸。"]'),
('8853cdc1-c57d-4fe8-b538-f7fd2d0b7324','挽石應之提刑  其三','孫應時','宋','宋诗','song-poetry','','[]','甫聽祥琴御，遄瞻瑞節榮。',48,'全唐诗/poet.song.172000.json','["甫聽祥琴御，遄瞻瑞節榮。", "許朝丹闕去，指奉板輿行。", "松柳餘哀切，膏肓一夢成。", "意長身未老，何事了平生。"]'),
('238abcd8-0155-409f-bd77-c8f57e646466','挽石應之提刑  其四','孫應時','宋','宋诗','song-poetry','','[]','昨歲吳門信，勤勤慰我窮。',48,'全唐诗/poet.song.172000.json','["昨歲吳門信，勤勤慰我窮。", "歸來愁未憗，相望渺難同。", "契闊今三歎，交游併一空。", "哀哀蓋棺了，餘論若爲公。"]'),
('7967011f-712a-4d9b-9d3a-e25f11841657','見巖桂有感','孫應時','宋','宋诗','song-poetry','','[]','苦被天香惱，𤧚瓏又一枝。',48,'全唐诗/poet.song.172000.json','["苦被天香惱，𤧚瓏又一枝。", "年年秋好處，故故月明時。", "勝絕何妨晚，凄凉却自宜。", "客愁添白髮，辜負小山期。"]'),
('82c1d930-15fa-4a07-b363-76a573e97e82','哭東萊呂先生  其一','孫應時','宋','宋诗','song-poetry','','[]','慟哭斯文禍，蒼茫可問天。',48,'全唐诗/poet.song.172000.json','["慟哭斯文禍，蒼茫可問天。", "百年曾未半，千載忍無傳。", "梁木誰扶厦，狂瀾莫障川。", "吞聲言不忍，有淚徹重泉。"]'),
('db9bb34c-2616-4a16-8d3c-48a79d2250c9','哭東萊呂先生  其二','孫應時','宋','宋诗','song-poetry','','[]','往歲風雲接，重霄日月開。',48,'全唐诗/poet.song.172000.json','["往歲風雲接，重霄日月開。", "奏篇聞歎息，造膝諗圖回。", "延閣初優病，鋒車又趣來。", "恭惟天子聖，殄瘁豈無哀。"]'),
('c068da8d-e927-4c02-bc3c-fbba0210cf7a','哭東萊呂先生  其三','孫應時','宋','宋诗','song-poetry','','[]','文獻承家大，規模與世公。',48,'全唐诗/poet.song.172000.json','["文獻承家大，規模與世公。", "典刑身任重，權度我時中。", "六合清淳氣，諸儒輔翼功。", "生賢竟何意，霜雹隕春風。"]'),
('f4c3828a-b039-4be8-b932-955d46d01cb1','哭東萊呂先生  其四','孫應時','宋','宋诗','song-poetry','','[]','蟠際函三極，精微破一毫。',48,'全唐诗/poet.song.172000.json','["蟠際函三極，精微破一毫。", "百川滄海受，五嶽衆山高。", "退託初何有，聲名肯自豪。", "誰人傷日月，用力爾徒勞。"]'),
('9fb88a9e-ddda-47aa-b97c-561823dc6b22','哭東萊呂先生  其五','孫應時','宋','宋诗','song-poetry','','[]','昨歲荆州訃，江流恨未平。',48,'全唐诗/poet.song.172000.json','["昨歲荆州訃，江流恨未平。", "天乎令後學，今又哭先生。", "剝落真如此，扶持豈易成。", "河汾遺禮樂，誰慰九原情。"]'),
('986edc84-19dc-417e-a784-ca64b1f1572f','哭東萊呂先生  其六','孫應時','宋','宋诗','song-poetry','','[]','鏡曲重携杖，京都再及門。',48,'全唐诗/poet.song.172000.json','["鏡曲重携杖，京都再及門。", "詩書窺梗槩，耳目竟煩昏。", "怊悵身何極，蹉跎意獨存。", "長途風雨晦，十駕謇追奔。"]'),
('cb273b8b-d8a5-4203-9f80-4ef534af745d','哭亡友胡達材  其一','孫應時','宋','宋诗','song-poetry','','[]','少日徐卿子，他年董相孫。',48,'全唐诗/poet.song.172000.json','["少日徐卿子，他年董相孫。", "斂藏神氣重，進止德容尊。", "人物當今歎，風流雅望存。", "拊棺疑不死，誰與賦招魂。"]'),
('78d53ee6-b59e-40a3-8cc0-b52ddd564f00','哭亡友胡達材  其二','孫應時','宋','宋诗','song-poetry','','[]','味薄身無累，心平理自長。',48,'全唐诗/poet.song.172000.json','["味薄身無累，心平理自長。", "公卿知叔度，州里敬元方。", "璞玉須瑚璉，春風便雪霜。", "重言吾不忍，天地日蒼茫。"]'),
('02de1cb8-5142-423b-8c5f-be11a1312246','哭亡友胡達材  其三','孫應時','宋','宋诗','song-poetry','','[]','匹馬勞山縣，風霜度十旬。',48,'全唐诗/poet.song.172000.json','["匹馬勞山縣，風霜度十旬。", "能令萬人活，不計百年身。", "事業秋毫盡，聲華白日淪。", "之人纔筦庫，誰獨上麒麟。"]'),
('9538de3c-59ef-4e2f-9e6a-766caa111ce9','哭亡友胡達材  其四','孫應時','宋','宋诗','song-poetry','','[]','嗟我論交重，相知照膽明。',48,'全唐诗/poet.song.172000.json','["嗟我論交重，相知照膽明。", "十年離合地，今日死生情。", "驚定心猶碎，悲來淚獨傾。", "絕憐江上夢，一一話生平。"]'),
('1841ff0a-1e71-4582-9f04-a03633316e6f','讀程子易傅','孫應時','宋','宋诗','song-poetry','','[]','事業潛三聖，文章似六經。',48,'全唐诗/poet.song.172000.json','["事業潛三聖，文章似六經。", "微言歸易簡，精意極丁寧。", "道在非疇昔，人亡故典刑。", "齋心對薰几，秋月夢初醒。"]'),
('3a686f99-d283-47b7-b2e6-65b280d18420','挽曾仲躬侍郎之室秦國太夫人馮氏','孫應時','宋','宋诗','song-poetry','','[]','數近期頤壽，尊封大國秦。',48,'全唐诗/poet.song.172000.json','["數近期頤壽，尊封大國秦。", "三從皆鼎食，九族盡朝紳。", "神劍須重合，蟠桃不再春。", "只令彤史載，備福更何人。"]'),
('aa423566-e536-46f1-974d-d758e811a1b0','送外姪莫幼明還里療疾','孫應時','宋','宋诗','song-poetry','','[]','愛子天資靜，能來讀我書。',48,'全唐诗/poet.song.172000.json','["愛子天資靜，能來讀我書。", "積痾無自苦，小別未云疎。", "外物人難必，良師古有餘。", "吳松春萬頃，一覽意何如。"]'),
('1dac1922-899f-4b3a-9da2-720c4e5ba500','挽王季海丞相  其一','孫應時','宋','宋诗','song-poetry','','[]','聖世持盈計，慈皇閲士多。',48,'全唐诗/poet.song.172000.json','["聖世持盈計，慈皇閲士多。", "十年深注倚，一德妙中和。", "日月長循軌，邊疆竟息戈。", "到今清浄化，彷彿漢民歌。"]'),
('33eaf32a-25b9-4052-9bdc-ef10d2f281ea','挽王季海丞相  其二','孫應時','宋','宋诗','song-poetry','','[]','海量真無滿，天和得大全。',48,'全唐诗/poet.song.172000.json','["海量真無滿，天和得大全。", "朝儀覿麟鳳，仙骨稱貂蟬。", "分陝初聊爾，騎箕遂窅然。", "平生融洩樂，端不捨黄泉。"]'),
('0578e5d6-11c1-4bf5-a42c-3d841cf83660','挽王季海丞相  其三','孫應時','宋','宋诗','song-poetry','','[]','舊託通家子，容干相國尊。',48,'全唐诗/poet.song.172000.json','["舊託通家子，容干相國尊。", "身猶安燕幕，心每繫龍門。", "赤舄三年去，清朝百度存。", "灊峰天柱折，一慟豈私恩。"]'),
('f2c8acc1-da40-470c-912f-639b765f6cd3','不寐','孫應時','宋','宋诗','song-poetry','','[]','向夕起秋思，無眠知夜長。',48,'全唐诗/poet.song.172000.json','["向夕起秋思，無眠知夜長。", "年華一俛仰，人事幾炎涼。", "自喜全虛白，何妨兀老蒼。", "空庭風露入，唧唧話蛩螿。"]'),
('44ca1677-4dc3-4c5f-8fea-a5e12353272c','挽李資政','孫應時','宋','宋诗','song-poetry','','[]','自我交賢子，逢人重此翁。',48,'全唐诗/poet.song.172000.json','["自我交賢子，逢人重此翁。", "一門傳義槩，奕世積陰功。", "丘壑身無恨，詩書道不窮。", "定知編太史，高揜漢于公。"]'),
('5406f572-925d-4fc5-869c-94897f6b9b68','送趙仲禮入朝爲大理寺簿  其一','孫應時','宋','宋诗','song-poetry','','[]','决科遄入幕，更秩遂登朝。',48,'全唐诗/poet.song.172000.json','["决科遄入幕，更秩遂登朝。", "龍化無重浪，鵬摶即九霄。", "仙凡端有命，天壤一何遼。", "願踵門庭盛，勳庸日月昭。"]'),
('4e8f7e0a-1c0f-43c7-91b0-3080211e9fbc','送趙仲禮入朝爲大理寺簿  其二','孫應時','宋','宋诗','song-poetry','','[]','綵服慈顔喜，綸音寵渥新。',48,'全唐诗/poet.song.172000.json','["綵服慈顔喜，綸音寵渥新。", "教忠當事主，顧養苦思親。", "杭葦東西近，郵筒早晚頻。", "宗公天下鎮，眉壽保千春。"]'),
('ca9f7f30-1fc9-4133-8e83-a17c80ad6394','送趙仲禮入朝爲大理寺簿  其三','孫應時','宋','宋诗','song-poetry','','[]','忠孝吾根柢，功名古緒餘。',48,'全唐诗/poet.song.172000.json','["忠孝吾根柢，功名古緒餘。", "月雲無染著，鏡象本空虛。", "不必相同異，何妨小闊疎。", "達庵今宦達，味此意何如。"]'),
('e9310c61-3b9e-4921-aafe-7fa9061dddca','挽曾原伯大卿  其一','孫應時','宋','宋诗','song-poetry','','[]','世豈無全德，今猶見古人。',48,'全唐诗/poet.song.172000.json','["世豈無全德，今猶見古人。", "大圭非刻畫，天醴自清醇。", "未說功名地，猶令宇宙春。", "蒼茫何處覓，丹素豈精神。"]'),
('d366d9a1-f138-444b-888a-5d541ea8ad04','挽曾原伯大卿  其二','孫應時','宋','宋诗','song-poetry','','[]','羣獻餘端緒，中原故典刑。',48,'全唐诗/poet.song.172000.json','["羣獻餘端緒，中原故典刑。", "風霜催短日，河漢獨晨星。", "悽惻丹心在，蕭條世路丁。", "天高那可問，揮淚濕青冥。"]'),
('03c857b2-b5cd-4fcd-b472-d9ddc3cd504b','挽曾原伯大卿  其三','孫應時','宋','宋诗','song-poetry','','[]','天下張廷尉，君王付老成。',48,'全唐诗/poet.song.172000.json','["天下張廷尉，君王付老成。", "不辭勞日夜，初豈爲恩榮。", "竹隠今年志，萱堂晚歲情。", "全歸雖不恨，此段渺難平。"]'),
('d3d999ad-413f-4232-8d34-505d1cc02d24','挽曾原伯大卿  其四','孫應時','宋','宋诗','song-poetry','','[]','夙昔吾何幸，龍門獲御公。',48,'全唐诗/poet.song.172000.json','["夙昔吾何幸，龍門獲御公。", "青燈鳴夜雨，白髮對春風。", "契闊今安訪，蹉跎媿所蒙。", "源流千古意，鉛槧若爲功。"]'),
('294a8f0d-296e-499f-a6c6-54d0546a841d','送胡婿晉遠赴義烏丞','孫應時','宋','宋诗','song-poetry','','[]','送子官何許，稽城十舍間。',48,'全唐诗/poet.song.172000.json','["送子官何許，稽城十舍間。", "清心向松竹，洗眼更湖山。", "學問駒千里，功名豹一斑。", "明年經鄭驛，助我悅慈顔。"]'),
('d223d3ee-2ca9-462c-9afb-fa7ade08eabe','贈分水奚令','孫應時','宋','宋诗','song-poetry','','[]','分手橋門外，風塵二十年。',48,'全唐诗/poet.song.172000.json','["分手橋門外，風塵二十年。", "相逢非偶爾，話舊各依然。", "飲啄寧無地，窮通故有天。", "文書有餘力，心事約加鞭。"]'),
('ff7e3939-6cb1-45b0-a327-4ad827969aae','贈淳安趙令','孫應時','宋','宋诗','song-poetry','','[]','吳越風聲近，邾滕壤地鄰。',48,'全唐诗/poet.song.172000.json','["吳越風聲近，邾滕壤地鄰。", "頻書期面語，一見劇情親。", "我本江海士，君真臺閣人。", "莫忘今夕話，努力壽斯民。"]'),
('96fa1718-9d23-4df5-af7e-f75c7589518d','挽潘德夫左司  其一','孫應時','宋','宋诗','song-poetry','','[]','家聲高內史，國望凜氷翁。',48,'全唐诗/poet.song.172000.json','["家聲高內史，國望凜氷翁。", "生長聖門學，周旋前輩風。", "人才須用舊，士論雅期公。", "不見朝宣室，秋山閟一宮。"]'),
('f4812ed3-0ff6-4b32-aa49-c8d34364320e','挽潘德夫左司  其二','孫應時','宋','宋诗','song-poetry','','[]','綜理何精密，胸中故坦然。',48,'全唐诗/poet.song.172000.json','["綜理何精密，胸中故坦然。", "愛民真爲國，事世不欺天。", "霜氣星臺表，春風竹馬前。", "湘江盡南海，遺績尚千年。"]'),
('58692463-7b3b-48e2-a6fa-7f4c70c44a5f','挽潘德夫左司  其三','孫應時','宋','宋诗','song-poetry','','[]','愛士風流古，繙書氣味長。',48,'全唐诗/poet.song.172000.json','["愛士風流古，繙書氣味長。", "詩家入陶謝，書法到顔楊。", "竹石故無恙，人琴今則亡。", "二龍天下秀，一一看增光。"]'),
('a590cff3-d3fa-4474-b67d-918dc6efcff7','挽潘德夫左司  其四','孫應時','宋','宋诗','song-poetry','','[]','結髮欽前輩，風流日渺然。',48,'全唐诗/poet.song.172000.json','["結髮欽前輩，風流日渺然。", "從今我鄰邑，不見此癯仙。", "攬轡范清詔，分符黄潁川。", "江湖終白首，那得盡公賢。"]'),
('33a30428-1669-43d0-83b9-a6604a565d65','挽潘德夫左司  其五','孫應時','宋','宋诗','song-poetry','','[]','湖海歸來近，山林興故長。',48,'全唐诗/poet.song.172000.json','["湖海歸來近，山林興故長。", "勇辭黄閣掾，却上白雲鄉。", "縹緲書樓壯，凄凉筆冢荒。", "家聲傳二妙，公死未應亡。"]'),
('27d253bf-97ee-41b8-9910-541efed2b97d','挽潘德夫左司  其六','孫應時','宋','宋诗','song-poetry','','[]','憶侍吾兄側，初瞻父友尊。',48,'全唐诗/poet.song.172000.json','["憶侍吾兄側，初瞻父友尊。", "爾來親燕几，長復痛鴒原。", "山立儀刑重，春回笑語溫。", "古今真共盡，淚下欲何言。"]'),
('38b49155-f95f-4c0c-b3e8-37808575b13c','挽趙子固左司  其一','孫應時','宋','宋诗','song-poetry','','[]','只道功名晚，居然寵數蕃。',48,'全唐诗/poet.song.172000.json','["只道功名晚，居然寵數蕃。", "偏令淮楚地，屢覩鉞旄尊。", "身隔公卿議，民私父母恩。", "東關往來處，腸斷不堪論。"]'),
('375c4c97-f938-4538-bfd2-7a571c79b2f4','挽趙子固左司  其二','孫應時','宋','宋诗','song-poetry','','[]','曾上郎官直，中辭宰掾高。',48,'全唐诗/poet.song.172000.json','["曾上郎官直，中辭宰掾高。", "丹衷耿天日，外物等絲毫。", "內養神方壯，前知數莫逃。", "阜陵人物舊，江漢日滔滔。"]'),
('aef8de75-c27f-4032-a7f0-9ea438d0947f','挽趙子固左司  其三','孫應時','宋','宋诗','song-poetry','','[]','每歎公知我，垂恩及父兄。',48,'全唐诗/poet.song.172000.json','["每歎公知我，垂恩及父兄。", "逢人說名姓，會面寫平生。", "近別無雙鯉，傷懷忽九京。", "翟公門下客，誓不負交情。"]'),
('255a5752-be0f-4b11-bec2-12f44cef0fd9','挽楊子美侍郎  其一','孫應時','宋','宋诗','song-poetry','','[]','游刃刀無缺，韜光玉自溫。',48,'全唐诗/poet.song.172000.json','["游刃刀無缺，韜光玉自溫。", "世途猶砥柱，士論亦龍門。", "仁者宜三壽，天乎遽九原。", "老成周雅歎，此事更誰論。"]'),
('bca749d4-4e59-4689-81b3-60cdfab8fb7a','挽楊子美侍郎  其二','孫應時','宋','宋诗','song-poetry','','[]','榮祿連三紀，賢勞匝四方。',48,'全唐诗/poet.song.172000.json','["榮祿連三紀，賢勞匝四方。", "風煙鬢蒼白，道路馬玄黄。", "不是論思晚，終然疾病妨。", "誰書循吏傳，處處有甘棠。"]'),
('271cb869-fd10-4b97-98b3-f3d3cc4d71eb','挽楊子美侍郎  其三','孫應時','宋','宋诗','song-poetry','','[]','萬里鵬纔息，千年鶴近歸。',48,'全唐诗/poet.song.172000.json','["萬里鵬纔息，千年鶴近歸。", "光榮人所羨，閒樂意終違。", "碧海沉佳氣，空山送落暉。", "翟公生死塚，雨淚獨沾衣。"]'),
('db269c18-fe61-4f10-bce0-6f6168a2524e','高南仲自雲間歸退軒蓋明府以四詩送之末章專以見及南仲索和遂次其韵  其一','孫應時','宋','宋诗','song-poetry','','[]','麗澤存相益，和羹忌苟同。',48,'全唐诗/poet.song.172000.json','["麗澤存相益，和羹忌苟同。", "別懷長耿耿，見日苦匆匆。", "經派懲燕說，詞源味國風。", "平生子陳子，一瓣記南豐。"]'),
('5f5bfbf6-0cde-4e93-a323-d4c34a836abc','高南仲自雲間歸退軒蓋明府以四詩送之末章專以見及南仲索和遂次其韵  其二','孫應時','宋','宋诗','song-poetry','','[]','鵬鷃逍遥意，鳩鷹變化時。',48,'全唐诗/poet.song.172000.json','["鵬鷃逍遥意，鳩鷹變化時。", "物生良自足，天命本無私。", "戚戚真何事，平平亦大奇。", "相逢一笑粲，無語自心知。"]'),
('93020067-2e4d-4ebb-a07a-1ca803f3b3be','高南仲自雲間歸退軒蓋明府以四詩送之末章專以見及南仲索和遂次其韵  其三','孫應時','宋','宋诗','song-poetry','','[]','清鏡朝容減，寒燈夜影孤。',48,'全唐诗/poet.song.172000.json','["清鏡朝容減，寒燈夜影孤。", "身曾諳作客，情亦念携孥。", "寶劍千金重，晴虹萬丈舒。", "功名生感慨，有路莫辭迂。"]'),
('05289e4a-9ece-442a-ab18-9ad23b49393b','高南仲自雲間歸退軒蓋明府以四詩送之末章專以見及南仲索和遂次其韵  其四','孫應時','宋','宋诗','song-poetry','','[]','少日諸公後，流年兩鬢斑。',48,'全唐诗/poet.song.172000.json','["少日諸公後，流年兩鬢斑。", "世情春冰泮，行路太行艱。", "何計分珠履，空懷對玉山。", "風期知不淺，逸駕恐難攀。"]'),
('84d43e23-946e-49d5-8bc8-c5b9d9407f5a','挽樓文昌母安康太夫人汪氏  其一','孫應時','宋','宋诗','song-poetry','','[]','中外三孤貴，康寧百歲期。',48,'全唐诗/poet.song.172000.json','["中外三孤貴，康寧百歲期。", "榮於列女傳，美矣二南詩。", "蟬蛻無餘戀，龍淵有合時。", "十經湯沐賜，風木更須悲。"]'),
('7291b09f-3f48-4c4c-8adb-4b70daeee8ca','挽樓文昌母安康太夫人汪氏  其二','孫應時','宋','宋诗','song-poetry','','[]','積慶源流遠，娠賢社稷光。',48,'全唐诗/poet.song.172000.json','["積慶源流遠，娠賢社稷光。", "斯文今北斗，舉代一文昌。", "象服山河壽，斑衣日月長。", "生芻此時事，四海爲悲凉。"]'),
('939a5440-fa6b-4944-83e6-ae6cf0287830','挽趙泰州母劉夫人','孫應時','宋','宋诗','song-poetry','','[]','玉葉宜家舊，金花錫命稠。',48,'全唐诗/poet.song.172000.json','["玉葉宜家舊，金花錫命稠。", "修齡開九秩，榮養指三州。", "足矣真無戀，翛然去不留。", "板輿行樂地，蕭瑟桂花秋。"]'),
('9e01f03a-e60a-49ab-9827-4b29f2e7017b','送胡婿晉遠赴嘉興酒官  其一','孫應時','宋','宋诗','song-poetry','','[]','逃暑吾無地，將家子在塗。',48,'全唐诗/poet.song.172000.json','["逃暑吾無地，將家子在塗。", "隨宜簡人事，莫久住行都。", "最肯加餐否，剛能却酒無。", "功名殊未晚，愛惜萬金軀。"]'),
('1408f2f2-335b-474b-ab1e-89d8339781b4','送胡婿晉遠赴嘉興酒官  其二','孫應時','宋','宋诗','song-poetry','','[]','名世非科目，傳家豈搢紳。',48,'全唐诗/poet.song.172000.json','["名世非科目，傳家豈搢紳。", "紛紛一炊夢，鼎鼎百年身。", "看取無窮事，何如不朽人。", "侯翁雖齟齬，此話故情親。"]'),
('8ddbe073-c222-43f5-9209-df0061565572','挽南康冷知軍  其一','孫應時','宋','宋诗','song-poetry','','[]','禮樂三千字，聲名五十秋。',48,'全唐诗/poet.song.172000.json','["禮樂三千字，聲名五十秋。", "士元纔展驥，李廣不封侯。", "香火猶彊健，笙歌足燕休。", "如何早仙去，寒日慘山丘。"]'),
('4e0305d2-dbca-4bff-ba4a-16dd0492f034','挽南康冷知軍  其二','孫應時','宋','宋诗','song-poetry','','[]','近託龍門御，欽聞月旦評。',48,'全唐诗/poet.song.172000.json','["近託龍門御，欽聞月旦評。", "感公非輩行，見我若平生。", "杖屨已陳迹，山川空復情。", "階庭森玉樹，端不負留耕。"]'),
('ee2b5da1-b4ea-4550-abab-2f96c0f749ce','挽南安錢知軍佖  其一','孫應時','宋','宋诗','song-poetry','','[]','風雅猶家學，精明獨吏師。',48,'全唐诗/poet.song.172000.json','["風雅猶家學，精明獨吏師。", "與人無軫域，於道不磷緇。", "天理終堪信，鄉評久更思。", "見公雖已晚，慟哭爲相知。"]'),
('123ba726-5a4b-426e-9d72-0f5c4349cf9e','挽南安錢知軍佖  其二','孫應時','宋','宋诗','song-poetry','','[]','別我南江去，風帆半夜開。',48,'全唐诗/poet.song.172000.json','["別我南江去，風帆半夜開。", "苦無爲郡樂，已復蓋棺回。", "契闊空三歎，凋零併一哀。", "遥知泣遺愛，愁殺嶺頭梅。"]'),
('e298cfca-5b32-4afa-add7-62939a8ebc3f','悼趙提幹  其一','孫應時','宋','宋诗','song-poetry','','[]','偉岸佳公子，功名早自强。',48,'全唐诗/poet.song.172000.json','["偉岸佳公子，功名早自强。", "力臻門戶立，學務本源長。", "命服空遺像，斑衣負北堂。", "增輝頼金友，筆墨妙揄揚。"]'),
('596fd619-8950-4be3-a8a0-a4db1a555c6c','悼趙提幹  其二','孫應時','宋','宋诗','song-poetry','','[]','一第規模勝，雙樓氣象高。',48,'全唐诗/poet.song.172000.json','["一第規模勝，雙樓氣象高。", "生涯輕阿堵，來往屬吾曹。", "落落心非淺，冥冥數莫逃。", "含悽想平昔，不忍過江臯。"]'),
('b78c3f5d-9dba-467e-815b-d096659e6a27','悼畢進士','孫應時','宋','宋诗','song-poetry','','[]','磨勵燈前志，瀾翻筆底春。',48,'全唐诗/poet.song.172000.json','["磨勵燈前志，瀾翻筆底春。", "果題新進士，歸悅太夫人。", "更值千金産，懸需五鼎珍。", "茫茫竟何往，一念忍忘親。"]'),
('d5f2d661-b0a9-4f2d-8881-19349ce769d6','挽樓嚴州  其一','孫應時','宋','宋诗','song-poetry','','[]','天與才難似，家傳學更優。',48,'全唐诗/poet.song.172000.json','["天與才難似，家傳學更優。", "著鞭心汗馬，游刃目無牛。", "奏語聞三歎，論功僅一州。", "人才苦牢落，那不使公留。"]'),
('2794ce07-4200-48b3-bdfe-e66047d0693f','挽樓嚴州  其二','孫應時','宋','宋诗','song-poetry','','[]','昨歲桐江去，羣公盛祖筵。',48,'全唐诗/poet.song.172000.json','["昨歲桐江去，羣公盛祖筵。", "安輿皆鶴髮，綵服正蟬聯。", "回首那爲此，傷心可問天。", "萱堂留仲博，猶足慰黄泉。"]'),
('48ba20ca-36f9-4c7f-982e-5f5e1279bf5f','挽趙泰州善忱','孫應時','宋','宋诗','song-poetry','','[]','唾拾儒科早，階升命秩尊。',48,'全唐诗/poet.song.172000.json','["唾拾儒科早，階升命秩尊。", "斑衣娛壽斝，綺席稱名園。", "五馬催三駕，千秋閉九原。", "春風破山路，松柏慘何言。"]'),
('1d6aaca0-e3e0-4455-82e5-af4fc326fb2e','送德安王休司戶','孫應時','宋','宋诗','song-poetry','','[]','相逢何必早，傾蓋已知心。',48,'全唐诗/poet.song.172000.json','["相逢何必早，傾蓋已知心。", "璞玉渾金質，高山流水音。", "眼中江漢闊，別後雪雲深。", "莫作窮途歎，功名始自今。"]'),
('67f9a517-394f-45d6-a8c7-a65697830964','挽松陽楊秉修處士','孫應時','宋','宋诗','song-poetry','','[]','飽說楊居士，沉浮楚越間。',48,'全唐诗/poet.song.172000.json','["飽說楊居士，沉浮楚越間。", "高懷渺雲海，健句壓江山。", "歲晚還家樂，生平滿意閒。", "合存耆舊傳，百世表鄉關。"]'),
('3b3b68e9-1c14-48db-a401-3587b249344d','挽陸景淵主簿  其一','孫應時','宋','宋诗','song-poetry','','[]','世道懸千載，書生困一科。',48,'全唐诗/poet.song.172000.json','["世道懸千載，書生困一科。", "看君榮落際，重我感傷多。", "斜日能鏖戰，春風得凱歌。", "平生一主簿，慟哭閉南柯。"]'),
('d2acbb36-2ca1-4216-87b3-4f400c467082','挽陸景淵主簿  其二','孫應時','宋','宋诗','song-poetry','','[]','輩行吾雖晚，交情久最親。',48,'全唐诗/poet.song.172000.json','["輩行吾雖晚，交情久最親。", "湖山追勝賞，棋酒過比隣。", "滿眼思羣彥，傷懷已二人。", "君今復何往，不忍夢音塵。"]'),
('15d012aa-c01d-42f5-8163-346a473d18e6','挽陸景淵主簿  其三','孫應時','宋','宋诗','song-poetry','','[]','儒學咸相詬，居賢不易逢。',48,'全唐诗/poet.song.172000.json','["儒學咸相詬，居賢不易逢。", "談經棄燕說，閲士似蟻封。", "涇渭流無雜，芝蘭氣自醲。", "百年雖有死，我輩故情鍾。"]'),
('1087988b-8486-40ca-9042-1f1a3e42587e','挽陸景淵主簿  其四','孫應時','宋','宋诗','song-poetry','','[]','兒女今何似，門闌想寂然。',48,'全唐诗/poet.song.172000.json','["兒女今何似，門闌想寂然。", "哀哀未白髮，莽莽就黄泉。", "淮浦西風外，雲溪宰木邊。", "緘辭致千里，雨淚不能湔。"]'),
('27435d87-5cd3-4843-8d37-66b30e14b855','秋日書懷','孫應時','宋','宋诗','song-poetry','','[]','宦情都漠漠，愁思正悠悠。',48,'全唐诗/poet.song.172000.json','["宦情都漠漠，愁思正悠悠。", "黄葉白蘋渚，清風明月樓。", "歸歟想彭澤，老矣欠菟裘。", "行止君休問，吾生不繫舟。"]'),
('00e57c43-67d5-402d-ad5d-0bcd826b5baa','送劉蘇州誠之帥夔門  其一','孫應時','宋','宋诗','song-poetry','','[]','卧轍違吳會，開帆指蜀門。',48,'全唐诗/poet.song.172000.json','["卧轍違吳會，開帆指蜀門。", "江關自奇險，節制故雄尊。", "一吐遐方氣，勤宣聖主恩。", "歸來對宣室，獻納佇司存。"]'),
('31bd1978-dbbb-4711-a77f-403d5e1243a8','送劉蘇州誠之帥夔門  其二','孫應時','宋','宋诗','song-poetry','','[]','了了八陣磧，巍巍三峽堂。',48,'全唐诗/poet.song.172000.json','["了了八陣磧，巍巍三峽堂。", "竹枝歌感慨，麯米醉淋浪。", "今古英雄思，風流翰墨場。", "公行秋水落，穩穩上瞿唐。"]'),
('b11db683-12e4-4b1d-932c-d9f783060348','于彝甫用許右丞別黄巖韵見寄亦用韵答之','孫應時','宋','宋诗','song-poetry','','[]','世道從來久，襟期我輩知。',48,'全唐诗/poet.song.172000.json','["世道從來久，襟期我輩知。", "躊躇遂初賦，歎息考槃詩。", "歌斷尊長破，心存鼓未衰。", "江湖秋葉外，千里更愁思。"]'),
('fd931931-69d2-4753-8438-92de9b42db4e','答陳子序庠見貽  其一','孫應時','宋','宋诗','song-poetry','','[]','論功畏蠅虎，作計只蝸牛。',48,'全唐诗/poet.song.172000.json','["論功畏蠅虎，作計只蝸牛。", "松菊招元亮，江湖要子牟。", "閒須杯問月，愁不賦登樓。", "從此相尋地，羊裘一釣舟。"]'),
('a4107b22-6102-4d8b-9883-5b3a1ec72865','答陳子序庠見貽  其二','孫應時','宋','宋诗','song-poetry','','[]','汩沒知何事，摧頹欲暮年。',48,'全唐诗/poet.song.172000.json','["汩沒知何事，摧頹欲暮年。", "劍鳴長自匣，琴弄更須絃。", "落落心元在，星星髮可憐。", "與君三歎息，不忍話前賢。"]'),
('b990cbcc-045d-42e2-91ba-3f385dcdc52f','答陳子序庠見貽  其三','孫應時','宋','宋诗','song-poetry','','[]','可人無俗韵，之子故清門。',48,'全唐诗/poet.song.172000.json','["可人無俗韵，之子故清門。", "直節豫章後，高名唯室孫。", "早知文律令，還要學根原。", "逆旅能頻過，何妨坐達昏。"]'),
('c1d3fab6-6eb6-4a9b-a0ad-34be3fcdafe8','挽王知復書監  其一','孫應時','宋','宋诗','song-poetry','','[]','五世衣冠盛，吾鄉識故家。',48,'全唐诗/poet.song.172000.json','["五世衣冠盛，吾鄉識故家。", "渥洼駒有種，和氏璧無瑕。", "了縣真談笑，還朝看咄嗟。", "天乎那可料，丹旐出京華。"]'),
('0b012d4f-e0e7-4515-bb26-444cb0e091e0','挽王知復書監  其二','孫應時','宋','宋诗','song-poetry','','[]','飛橋壯吾邑，虹影麗高深。',48,'全唐诗/poet.song.172000.json','["飛橋壯吾邑，虹影麗高深。", "義不煩千室，功無措萬金。", "美哉承考意，偉矣濟時心。", "此段無窮盡，江聲共古今。"]'),
('acdf4668-0845-4b64-a81c-0818b2d27d71','挽王知復書監  其三','孫應時','宋','宋诗','song-poetry','','[]','公子三槐族，貧交五柳門。',48,'全唐诗/poet.song.172000.json','["公子三槐族，貧交五柳門。", "鄉閭雖不數，書劄屢相溫。", "前輩風流遠，時情勢利尊。", "哀哀埋玉樹，此意復誰論。"]'),
('3f6605c3-3017-458e-b88d-819ab5ec6a42','小兒阿開周晬憶之有作','孫應時','宋','宋诗','song-poetry','','[]','愛子人情共，吾兒亦所憐。',48,'全唐诗/poet.song.172000.json','["愛子人情共，吾兒亦所憐。", "精神如欲可，門戶儻能傳。", "歸去隔千里，生來正一年。", "遥知晬盤側，王母意歡然。"]'),
('f4786feb-a1f2-4e65-ac8d-e580a7628b50','挽李中甫使君  其一','孫應時','宋','宋诗','song-poetry','','[]','赫赫中興佐，英風想大門。',48,'全唐诗/poet.song.172000.json','["赫赫中興佐，英風想大門。", "得交人物懿，喜見典刑存。", "拱立嚴諸父，躬行表後昆。", "世家今萬石，一代合推尊。"]'),
('e3023e2a-4a2d-4907-a0ce-811aa54df13b','挽李中甫使君  其二','孫應時','宋','宋诗','song-poetry','','[]','圭玉身無玷，春風物自熙。',48,'全唐诗/poet.song.172000.json','["圭玉身無玷，春風物自熙。", "學非隨俗尚，心故有天知。", "里社成鄒魯，交游不惠夷。", "思君兼衆美，凋落使人悲。"]'),
('0e2b1472-18fb-46c6-bf22-fc8d58009364','挽李中甫使君  其三','孫應時','宋','宋诗','song-poetry','','[]','發軔期行志，鳴琴最得民。',48,'全唐诗/poet.song.172000.json','["發軔期行志，鳴琴最得民。", "淵魚何用察，桑雉本來馴。", "可歎雙旌暮，猶歌五袴新。", "誰爲良吏傳，吾欲表斯文。"]'),
('7004bbe5-a250-42db-9c20-7d7eccd53b5e','挽李中甫使君  其四','孫應時','宋','宋诗','song-poetry','','[]','書卷平生事，篝燈靜夜分。',48,'全唐诗/poet.song.172000.json','["書卷平生事，篝燈靜夜分。", "韵鈞奏韓柳，黼黻補卿雲。", "不鄙頻揮麈，曾窺一運斤。", "詞人嗟不遇，地下早修文。"]'),
('960eeceb-fb6b-48b5-9dab-1a3933b44e67','挽李中甫使君  其五','孫應時','宋','宋诗','song-poetry','','[]','少日論心密，中年會面艱。',48,'全唐诗/poet.song.172000.json','["少日論心密，中年會面艱。", "相逢愈青眼，太息各蒼顔。", "離合窮通裏，悲歡夢寐間。", "蒙園歲寒約，秋草泣空山。"]'),
('859a3cc5-2e60-4982-8dfa-3ffbf8f46e5d','挽李中甫使君  其六','孫應時','宋','宋诗','song-poetry','','[]','憶奉先人窆，深勤長者車。',48,'全唐诗/poet.song.172000.json','["憶奉先人窆，深勤長者車。", "哀辭推傑作，虞主爲佳書。", "今日君仙去，秋陰我病餘。", "莫酬三施重，緘淚洒幽墟。"]'),
('ed5c5c06-e7d3-4766-9f04-5ad93d41fa2c','和答張衡仲  其一','孫應時','宋','宋诗','song-poetry','','[]','志畧周公瑾，才名陸敬輿。',48,'全唐诗/poet.song.172000.json','["志畧周公瑾，才名陸敬輿。", "可憐空老大，不敢問何如。", "松菊閒吟外，風波噩夢餘。", "諸公自臺省，吾復愛吾廬。"]'),
('064ae001-b106-4114-b409-d8fa4f7a47e7','和答張衡仲  其二','孫應時','宋','宋诗','song-poetry','','[]','我方開竹徑，公肯屈籃輿。',48,'全唐诗/poet.song.172000.json','["我方開竹徑，公肯屈籃輿。", "別去夢猶見，詩來錦不如。", "乾坤愁思裏，風月醉眠餘。", "會卜溪橋畔，鄰牆小結廬。"]'),
('076ac20b-dc2c-435d-9cf5-4087a4198a4b','送司馬大亨赴遂昌宰','孫應時','宋','宋诗','song-poetry','','[]','蒲璧邦家重，蒼山道路深。',48,'全唐诗/poet.song.172000.json','["蒲璧邦家重，蒼山道路深。", "剸裁知唾手，拊字勉勞心。", "通鑑家傳學，迂書坐右箴。", "故人情誼重，贈別比南金。"]'),
('3848c446-9041-4cc9-9f31-7bd96fd92923','清凉寺','孫應時','宋','宋诗','song-poetry','','[]','勝絕清涼寺，低迷德慶堂。',48,'全唐诗/poet.song.172000.json','["勝絕清涼寺，低迷德慶堂。", "崇阿納遐景，遺蹟想前王。", "豪傑兵戈後，風流翰墨場。", "憑欄意何極，歸鳥度斜陽。"]'),
('b65c0ae5-c3e1-45eb-bdee-6c9e67f943d4','挽司馬季若知郡  其一','孫應時','宋','宋诗','song-poetry','','[]','前日巴東守，中朝涑水家。',48,'全唐诗/poet.song.172000.json','["前日巴東守，中朝涑水家。", "風規踵清白，牘奏述忠嘉。", "鼎鼎名逾重，堂堂髮未華。", "如何空疊組，不見海陵瓜。"]'),
('53f973d9-df8a-49a3-824a-b319fbea1505','挽司馬季若知郡  其二','孫應時','宋','宋诗','song-poetry','','[]','榘矱猶前輩，襟懷更古風。',48,'全唐诗/poet.song.172000.json','["榘矱猶前輩，襟懷更古風。", "子孫娛謝傅，賓客愛山公。", "喬木千年思，晨星一瞬空。", "彬彬看祠事，盛德世無窮。"]'),
('bc396d16-8c0b-4dc4-bef2-b8ac415c5cbf','挽司馬季若知郡  其三','孫應時','宋','宋诗','song-poetry','','[]','越絕枌榆社，吳陵松竹間。',48,'全唐诗/poet.song.172000.json','["越絕枌榆社，吳陵松竹間。", "相親逾骨肉，海見豁心顔。", "契闊今生死，蕭條舊往還。", "春風數行淚，吹度鏡湖山。"]'),
('91a25735-c0a6-4a4a-8487-e26e1305cc42','送虞仲房赴潼川漕  其一','孫應時','宋','宋诗','song-poetry','','[]','夙昔青雲上，誰令鬢髮蒼。',48,'全唐诗/poet.song.172000.json','["夙昔青雲上，誰令鬢髮蒼。", "家聲唐祕監，墨妙漢中郎。", "牢落山林久，間關道路長。", "西風足清嘯，幾日上瞿唐。"]'),
('113e9625-d0ca-4c1b-84be-001236fdc62f','送虞仲房赴潼川漕  其二','孫應時','宋','宋诗','song-poetry','','[]','保障平時計，遐民力未寬。',48,'全唐诗/poet.song.172000.json','["保障平時計，遐民力未寬。", "梓潼將漕險，廊廟擇才難。", "江水東流急，秦山北顧寒。", "平沙八陣在，倚劍夕陽看。"]'),
('0c7f5657-0644-430d-9ff5-77fa988f09c9','送虞仲房赴潼川漕  其三','孫應時','宋','宋诗','song-poetry','','[]','小隠橫溪勝，青山照眼高。',48,'全唐诗/poet.song.172000.json','["小隠橫溪勝，青山照眼高。", "芝蘭春滿痤，風雨醉揮毫。", "苦恨登門晚，深慚倒屣勞。", "公歸佩荷橐，肯問及蓬蒿。"]'),
('7eaaf0ef-e524-4c26-a812-7dd66281f277','又寄潼川漕仲房  其一','孫應時','宋','宋诗','song-poetry','','[]','巴蜀勞膚使，溪山隔歲華。',48,'全唐诗/poet.song.172000.json','["巴蜀勞膚使，溪山隔歲華。", "一身知許國，萬里豈忘家。", "臘雪裝歸轡，春風閲禁花。", "君王定前席，不必賦長沙。"]'),
('b53af9c4-69ba-4f5c-b773-457730406625','又寄潼川漕仲房  其二','孫應時','宋','宋诗','song-poetry','','[]','郡縣仍荒政，朝廷念遠方。',48,'全唐诗/poet.song.172000.json','["郡縣仍荒政，朝廷念遠方。", "向來傳詔札，不獨戒戎羌。", "帝德乾坤大，天聰日月光。", "邊防須至計，社稷倚安疆。"]'),
('4a0e1e1b-02a1-4045-b1ca-c0e675c14636','又寄潼川漕仲房  其三','孫應時','宋','宋诗','song-poetry','','[]','鴻鴈天涯到，雲泥未闊疎。',48,'全唐诗/poet.song.172000.json','["鴻鴈天涯到，雲泥未闊疎。", "漢卿來子墨，秦殿識中書。", "欲作遼東獻，空慙楚地餘。", "寒蟲吟露草，此意合憐渠。"]'),
('fbaef33c-5b9a-4c93-98d2-095b445d62e4','和諸葛行之','孫應時','宋','宋诗','song-poetry','','[]','相看各華髮，舊學更何疑。',48,'全唐诗/poet.song.172000.json','["相看各華髮，舊學更何疑。", "世事幾反覆，人生半別熟。", "忍窮真有味，知命欲誰欺。", "我學陶元亮，君師榮啟期。"]'),
('61a2b4a0-2c8a-4845-ab84-fd7e007a182c','和答陳傳朋  其一','孫應時','宋','宋诗','song-poetry','','[]','羈愁閲寒暑，歸夢耿晨昏。',48,'全唐诗/poet.song.172000.json','["羈愁閲寒暑，歸夢耿晨昏。", "本意營三鬴，何如老一村。", "齒牙從世議，頂踵尚君恩。", "多謝知心友，相過得細論。"]'),
('cf997686-ac11-4179-b187-738439155d0e','和答陳傳朋  其二','孫應時','宋','宋诗','song-poetry','','[]','別來如一日，話著又三冬。',48,'全唐诗/poet.song.172000.json','["別來如一日，話著又三冬。", "信斷悲鱗羽，情親憶駏蛩。", "非君詩律妙，奈我客愁濃。", "嘆息青雲器，誰能識仲容。"]'),
('8b41156b-129c-4ff9-8412-c17592b415e8','邵武李公晦方子佳士也以其祖澹軒先生呂之行實挽詩見示爲作八句','孫應時','宋','宋诗','song-poetry','','[]','海內非無士，南中更有公。',48,'全唐诗/poet.song.172000.json','["海內非無士，南中更有公。", "一門嚴禮範，十世篤儒風。", "不遇心何媿，雖亡道未窮。", "芝蘭今鼎盛，天必報陰功。"]'),
('68c6c8f4-cd21-4eea-9769-5ffc88a629e7','送張清叔主簿','孫應時','宋','宋诗','song-poetry','','[]','客路雖萍梗，心交真弟兄。',48,'全唐诗/poet.song.172000.json','["客路雖萍梗，心交真弟兄。", "懸知有時別，何忍獨先行。", "綵服黄花酒，青雲白玉京。", "寒蟬正淒切，回首得忘情。"]'),
('32bb2024-9ed3-44ff-b2da-ded425088eaa','悼周堯夫  其一','孫應時','宋','宋诗','song-poetry','','[]','勇義千鈞力，虛懷萬物容。',48,'全唐诗/poet.song.172000.json','["勇義千鈞力，虛懷萬物容。", "材名稱遠大，俊傑靄遊從。", "許可皆諸老，升聞到九重。", "惜哉言與位，大厦折喬松。"]'),
('a9261907-dd1b-4ad6-9209-5d0af7d8cbac','悼周堯夫  其二','孫應時','宋','宋诗','song-poetry','','[]','傾耳鄉評舊，登門恨末繇。',48,'全唐诗/poet.song.172000.json','["傾耳鄉評舊，登門恨末繇。", "公今成夢覺，人共泣川流。", "剡水陰功遠，山堂勝具留。", "喜觀雙玉樹，接武在英遊。"]'),
('49a6e046-44b4-4fdf-b143-3069f819881c','挽諸葛壽之  其一','孫應時','宋','宋诗','song-poetry','','[]','幼學蒙題品，童心託弟兄。',48,'全唐诗/poet.song.172000.json','["幼學蒙題品，童心託弟兄。", "過從十年足，悃款一家情。", "無力寬貧病，傳書隔死生。", "西風吹客淚，萬里寸心明。"]'),
('04cd0ea9-4b44-4b83-8740-e0a21ecccdf2','挽諸葛壽之  其二','孫應時','宋','宋诗','song-poetry','','[]','人物殊高朗，交遊見直溫。',48,'全唐诗/poet.song.172000.json','["人物殊高朗，交遊見直溫。", "蠅頭深故帙，麈尾富名言。", "憗不儀多士，猶令重一門。", "若耶溪上月，空復閉山村。"]'),
('02df404a-8951-4631-bad1-0b0c056552ca','挽諸葛壽之  其三','孫應時','宋','宋诗','song-poetry','','[]','命矣三年病，天乎百歲期。',48,'全唐诗/poet.song.172000.json','["命矣三年病，天乎百歲期。", "尸饔猶有母，傳業更無兒。", "便作平生盡，空多國士知。", "增光在金友，人得記塤箎。"]'),
('04fc3e05-965f-4b4a-b9ff-196f63773b58','挽莫子晉丈  其一','孫應時','宋','宋诗','song-poetry','','[]','我里談耆舊，高門二百年。',48,'全唐诗/poet.song.172000.json','["我里談耆舊，高門二百年。", "衣冠新族緒，龜筴故山川。", "家以儒相勵，公於志獨堅。", "九原疑不瞑，諸子更加鞭。"]'),
('94a54e83-c078-4283-9160-2aad86d63a57','挽莫子晉丈  其二','孫應時','宋','宋诗','song-poetry','','[]','少日從諸老，丁年重一鄉。',48,'全唐诗/poet.song.172000.json','["少日從諸老，丁年重一鄉。", "塤箎鳴正樂，蘭玉秀成行。", "坐客多匡鼎，途人說鄭莊。", "哀哀晚何事，衰病訖淒涼。"]'),
('2bf8fd85-22b7-4fcb-b644-d35279b56049','挽莫子晉丈  其三','孫應時','宋','宋诗','song-poetry','','[]','吾父古君子，公家賢主人。',48,'全唐诗/poet.song.172000.json','["吾父古君子，公家賢主人。", "一門常旅拜，三世極情親。", "遺事今誰問，知心莫重陳。", "上林烟草綠，千里倍傷神。"]'),
('c1ab2547-e5f5-4814-8356-11953f1e030c','挽胡子瑞  其一','孫應時','宋','宋诗','song-poetry','','[]','耆舊長庚月，斯人馬少游。',48,'全唐诗/poet.song.172000.json','["耆舊長庚月，斯人馬少游。", "平生自繩尺，方寸不戈矛。", "細細巾箱字，琅琅燈火秋。", "子孫森滿眼，賫志可無酬。"]'),
('52a1ec1d-fed6-4977-8105-7f73817b33eb','挽胡子瑞  其二','孫應時','宋','宋诗','song-poetry','','[]','三十年間事，論交踵父兄。',48,'全唐诗/poet.song.172000.json','["三十年間事，論交踵父兄。", "叩門時下榻，話舊各傷情。", "我亦華雙鬢，君仍隔九京。", "滯留違一慟，腸斷暮雲橫。"]'),
('d40e0717-4302-4f9c-8d6b-aa74b11a37a4','挽葉無咎  其一','孫應時','宋','宋诗','song-poetry','','[]','詩酒平生事，風流六十翁。',48,'全唐诗/poet.song.172000.json','["詩酒平生事，風流六十翁。", "詞人尋鄭老，坐客愛車公。", "已惜漳濱卧，那堪冀北空。", "交情不論晚，爲子泣西風。"]'),
('739fdeda-cafc-4a56-b2f4-fbc7679a3504','挽葉無咎  其二','孫應時','宋','宋诗','song-poetry','','[]','偃室多賓客，周南隔歲年。',48,'全唐诗/poet.song.172000.json','["偃室多賓客，周南隔歲年。", "我窮甘悄悄，君義獨悁悁。", "病著心何壯，書來墨尚鮮。", "含桃餉時節，一念一悽然。"]'),
('69ce405b-cf6f-4289-80df-759b262663dc','挽先兄外舅施文子支使  其一','孫應時','宋','宋诗','song-poetry','','[]','天質全渾厚，鄉評獨老成。',48,'全唐诗/poet.song.172000.json','["天質全渾厚，鄉評獨老成。", "箕裘三葉盛，椿桂一時榮。", "賓席疑年少，官曹歎眼明。", "歸來江路永，那忍望銘旌。"]'),
('2a8a76c3-6b92-452a-bda9-0783f09a3a34','挽先兄外舅施文子支使  其二','孫應時','宋','宋诗','song-poetry','','[]','憶我元方在，欽公彥輔賢。',48,'全唐诗/poet.song.172000.json','["憶我元方在，欽公彥輔賢。", "艱難時款曲，孤寡共悲憐。", "契闊湖南幕，吁嗟絳縣年。", "杜門違一慟，緘淚五雲邊。"]'),
('87f7ef57-c86d-49a1-9c3b-26a36a91706a','挽沈雲夫','孫應時','宋','宋诗','song-poetry','','[]','我昔垂髫日，君來學雪齋。',48,'全唐诗/poet.song.172000.json','["我昔垂髫日，君來學雪齋。", "寧知重骨肉，借作老生涯。", "喜劇相過密，驚吁一病乖。", "平生此長別，雨淚獨傷懷。"]'),
('42843f30-6a0c-4edd-88bf-dbfbca524dcd','寄通州徐居厚使君  其一','孫應時','宋','宋诗','song-poetry','','[]','珍重通州守，凝香足燕清。',48,'全唐诗/poet.song.172000.json','["珍重通州守，凝香足燕清。", "海風喧夜永，江日盪春明。", "未廢青燈讀，應添白髮生。", "長沙休賦鵩，歸作漢公卿。"]'),
('60e104f8-e31e-45da-b9c4-05421a4cd3c6','寄通州徐居厚使君  其二','孫應時','宋','宋诗','song-poetry','','[]','久已安時論，狂因歎史才。',48,'全唐诗/poet.song.172000.json','["久已安時論，狂因歎史才。", "及知前輩少，誰說過江來。", "日月閒難得，星霜老易催。", "陽秋百年事，作意莫遲回。"]'),
('3448062b-cb01-4f9d-930c-a68bd7a15aa1','哭沈叔晦墓','孫應時','宋','宋诗','song-poetry','','[]','宿草遂如許，吾誰作九原。',48,'全唐诗/poet.song.172000.json','["宿草遂如許，吾誰作九原。", "堂堂那有此，凜凜尚能存。", "日落松風迥，天清霜氣暄。", "百年知己淚，洒淚欲何言。"]'),
('e2006aa2-1b36-4299-8aa1-511ab02c94a9','用韵戲簡叔','孫應時','宋','宋诗','song-poetry','','[]','平生習主簿，涇渭極分明。',48,'全唐诗/poet.song.172000.json','["平生習主簿，涇渭極分明。", "學道深忘味，能詩新有聲。", "弈寧論勝負，琴不計虧成。", "獨怕春宵鴈，南來動別情。"]'),
('51379182-dd12-4a26-9cfa-5da0350de441','早行','孫應時','宋','宋诗','song-poetry','','[]','畏暑裝行早，江村雞未鳴。',48,'全唐诗/poet.song.172000.json','["畏暑裝行早，江村雞未鳴。", "林廬相遠近，河漢正縱橫。", "思眇關山迥，心依斗極明。", "小橋聊駐馬，流水有佳聲。"]'),
('f73ca26f-7406-4175-803f-352bedbd2cdf','入棧','孫應時','宋','宋诗','song-poetry','','[]','棧險名天下，吾行信所聞。',48,'全唐诗/poet.song.172000.json','["棧險名天下，吾行信所聞。", "落虹橫絕壁，匹馬上浮雲。", "咫尺南北斷，毫釐生死分。", "誰令鍾鄧輩，十萬度秦軍。"]'),
('8e05dd4e-c09e-4bf0-8470-4b84dcd1959e','客思','孫應時','宋','宋诗','song-poetry','','[]','竟作西江去，其如客思何。',48,'全唐诗/poet.song.172000.json','["竟作西江去，其如客思何。", "無情秋色老，不盡楚山多。", "且賦南蠻句，休懷下里歌。", "平生一柱觀，明日得經過。"]'),
('c5c2a4cf-1678-4fff-ab86-8351d0c66f21','八陣磧','孫應時','宋','宋诗','song-poetry','','[]','江近瞿唐急，沙從魚腹橫。',48,'全唐诗/poet.song.172000.json','["江近瞿唐急，沙從魚腹橫。", "千秋應有恨，八陣竟難平。", "望斷青煙晚，愁邊白鳥明。", "身微定何補，且復老躬耕。"]'),
('4ffb5958-ceb3-4d0e-b1c1-a0add3933881','寄詠東屯','孫應時','宋','宋诗','song-poetry','','[]','聞說東屯勝，詩仙有舊遊。',48,'全唐诗/poet.song.172000.json','["聞說東屯勝，詩仙有舊遊。", "茅齋深翠竹，石徑俯寒流。", "几杖千山月，鉏犂百頃秋。", "歸途客酹酒，句法儻堪求。"]'),
('4a4c2fab-e740-487b-8c57-cc7b9875c38a','和共父游青羊宮二首  其一','孫應時','宋','宋诗','song-poetry','','[]','野興偶所愜，勝遊聊一尋。',48,'全唐诗/poet.song.172000.json','["野興偶所愜，勝遊聊一尋。", "雙臺隠空曲，萬竹護清深。", "嵐翠明巾屢，風香度笑吟。", "端能重載酒，盡日聽鳴琴。"]'),
('a9c3c21e-c60f-4b53-84ad-8d22495c7607','和共父游青羊宮二首  其二','孫應時','宋','宋诗','song-poetry','','[]','訪古未云已，會心良獨多。',48,'全唐诗/poet.song.172000.json','["訪古未云已，會心良獨多。", "猶應趁風月，從此徧岷峨。", "萬里澹秋色，一江明暮波。", "他年問魚鳥，能復記相過。"]'),
('40cfe726-25c5-43e0-9e0b-a0d01b049508','出成都西郊','孫應時','宋','宋诗','song-poetry','','[]','笑指西山去，縈紆傍水行。',48,'全唐诗/poet.song.172000.json','["笑指西山去，縈紆傍水行。", "寒灘瀉清淺，古木映疎明。", "雪意垂垂合，川光莽莽平。", "蹔將塵事隔，已復動詩情。"]'),
('cd51f500-31d3-474c-b385-fd11344a4943','自益昌爲武興之行','孫應時','宋','宋诗','song-poetry','','[]','獨客行愈遠，此兒真自癡。',48,'全唐诗/poet.song.172000.json','["獨客行愈遠，此兒真自癡。", "江流浩呼洶，棧路凜欹危。", "好鳥迎人處，凉風拂面時。", "山頭破茅驛，索筆又題詩。"]'),
('49cab6c2-6dc3-4a29-81f6-7f9cc86ca466','益昌僧寺靜境軒','孫應時','宋','宋诗','song-poetry','','[]','落照久未夕，斷雲低不飛。',48,'全唐诗/poet.song.172000.json','["落照久未夕，斷雲低不飛。", "孤舟上水急，歸鳥度山微。", "蕭颯天涯鬢，淋浪醉後衣。", "憑欄一笑去，客夢轉頭非。"]'),
('25bc0296-bdfc-42ae-be75-8a0b22bcd907','武擔山  其一','孫應時','宋','宋诗','song-poetry','','[]','北上武擔寺，南臨蜀錦園。',48,'全唐诗/poet.song.172000.json','["北上武擔寺，南臨蜀錦園。", "風煙带城郭，禾黍半江村。", "今古本同夢，廢興那復論。", "惟應一坡竹，可共洗心言。"]'),
('b303c204-a2cb-4791-bd31-25247259cc4f','武擔山  其二','孫應時','宋','宋诗','song-poetry','','[]','小飲不成醉，清談多所欣。',48,'全唐诗/poet.song.172000.json','["小飲不成醉，清談多所欣。", "秋聲摇落日，野色亂寒雲。", "心事長千載，腰圍更幾分。", "西風叢桂發，倚檻得相聞。"]'),
('93279e75-cf25-4a51-9ec8-8a02070e0f0d','武擔西臺和師文作','孫應時','宋','宋诗','song-poetry','','[]','西臺在何許，秋草暮雲間。',48,'全唐诗/poet.song.172000.json','["西臺在何許，秋草暮雲間。", "十畝有餘竹，一窗無數山。", "望遠足離思，憂時多苦顔。", "相看終惜醉，更挈酒缾還。"]'),
('84cfb2b3-42cf-46c4-bc9b-ce57289dfe78','武擔山感事  其一','孫應時','宋','宋诗','song-poetry','','[]','歸心極江海，秋夢著丘園。',48,'全唐诗/poet.song.172000.json','["歸心極江海，秋夢著丘園。", "鷗鷺白蘋渚，牛羊黄葉村。", "古人真已遠，世事渺難論。", "想見陶元亮，觴來不得言。"]'),
('a7fe33d2-e24d-42e1-8837-2077b84d359b','武擔山感事  其二','孫應時','宋','宋诗','song-poetry','','[]','客裏愁如積，朝來意亦欣。',48,'全唐诗/poet.song.172000.json','["客裏愁如積，朝來意亦欣。", "鳴階無宿雨，度隙有歸雲。", "且免泥盈尺，猶祈歲十分。", "中原念淮浙，不忍話傳聞。"]'),
('962f4c32-6d8e-40e5-86a0-32602928b6c3','武擔山感事  其三','孫應時','宋','宋诗','song-poetry','','[]','身不入蓮社，意非同漆園。',48,'全唐诗/poet.song.172000.json','["身不入蓮社，意非同漆園。", "閒來閲風物，歸去老山村。", "氣味故相許，淵源須細論。", "燈前秋夜永，未可付忘言。"]'),
('e603dea9-0c94-471a-942e-35784b42a041','武擔山感事  其四','孫應時','宋','宋诗','song-poetry','','[]','襟懷能坦坦，色笑更欣欣。',48,'全唐诗/poet.song.172000.json','["襟懷能坦坦，色笑更欣欣。", "似道黄叔度，草玄揚子雲。", "歸舟真已具，別袂不能分。", "歲月愁邊鴈，飛鳴報客聞。"]'),
('b7397182-9ef1-4362-ac2d-9786477dca5e','冷副端招西郊賞櫻桃','孫應時','宋','宋诗','song-poetry','','[]','喜趁林泉約，來同櫻笋厨。',48,'全唐诗/poet.song.172000.json','["喜趁林泉約，來同櫻笋厨。", "綠陰濃欲滴，高竹靜相扶。", "山晚月先上，人歸鳥自呼。", "不辭拚一醉，此會兩年無。"]'),
('ec460f5f-fdde-4ca4-849f-4cedb1ee04a9','新灘見桃杏書事','孫應時','宋','宋诗','song-poetry','','[]','今晨明客眼，桃杏照江紅。',48,'全唐诗/poet.song.172000.json','["今晨明客眼，桃杏照江紅。", "鳥哢蒼山曲，人聲翠竹中。", "獨遊空遠思，一笑負春風。", "便想荆州道，簪花醉渚宮。"]'),
('be33980e-b130-48e6-995c-a9a7e7f26a18','萬景樓三首用韵  其一','孫應時','宋','宋诗','song-poetry','','[]','皛皛三江水，岹岹百尺樓。',48,'全唐诗/poet.song.172000.json','["皛皛三江水，岹岹百尺樓。", "雲山接南詔，風景冠西州。", "徙倚乾坤大，徘徊歲月流。", "明朝悵回首，湖海一歸舟。"]'),
('3b234d22-f5f5-498d-82d4-2ef006dc55a7','萬景樓三首用韵  其二','孫應時','宋','宋诗','song-poetry','','[]','德潤連城璧，文工五鳳樓。',48,'全唐诗/poet.song.172000.json','["德潤連城璧，文工五鳳樓。", "不愁來蜀徼，政喜識荆州。", "世久欺儒素，人當問品流。", "平生郭有道，得共李公舟。"]'),
('88ab6175-ea52-4440-9118-c08bd14fb9fa','萬景樓三首用韵  其三','孫應時','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','阮籍少青眼，元龍思卧樓。',48,'全唐诗/poet.song.172000.json','["阮籍少青眼，元龍思卧樓。", "與君非俗士，爲我望神州。", "明月不可問，長江空自流。", "悠悠復何道，行止一虛舟。"]'),
('17afcd83-80f5-4316-947e-3304ec530658','自東屯夜還舟中','孫應時','宋','宋诗','song-poetry','','[]','白帝水雲暗，東屯燈火歸。',48,'全唐诗/poet.song.172000.json','["白帝水雲暗，東屯燈火歸。", "春泥慳弊屐，山雨濕征衣。", "遠役諒難踐，勝情那得違。", "關城吏相笑，癡絕似君稀。"]'),
('5be4f874-0a3a-4074-a13a-2a2122c8d908','舟宿莫城','孫應時','宋','宋诗','song-poetry','','[]','澤國寒初重，霜天晚自溫。',48,'全唐诗/poet.song.172000.json','["澤國寒初重，霜天晚自溫。", "孤舟一杯酒，斜月數家村。", "美睡聊相補，勞生得更論。", "燭湖疑在眼，燈火閉柴門。"]'),
('4d76a7be-7bf9-4a74-b5e5-bcd2e84549fb','阻風泊歸舟游浄衆寺','孫應時','宋','宋诗','song-poetry','','[]','日落風更起，江頭船不行。',48,'全唐诗/poet.song.172000.json','["日落風更起，江頭船不行。", "淒涼大夫宅，蕭瑟故王城。", "一醉重樓晚，千秋萬古情。", "愁邊動寒角，夜久意難平。"]'),
('a45ad94f-2a13-4f50-aa7e-1c02fb6f0a8d','道中寄同舍  其一','孫應時','宋','宋诗','song-poetry','','[]','風聲捲蘆竹，雪意滿江天。',48,'全唐诗/poet.song.172000.json','["風聲捲蘆竹，雪意滿江天。", "水落石可數，沙寒鷗自眠。", "回頭渺城郭，留眼寄山川。", "老去重來否，吟餘一惘然。"]'),
('2c1ef6f2-c9d1-4a60-8f40-2f52e8cbcc96','道中寄同舍  其二','孫應時','宋','宋诗','song-poetry','','[]','山色忽相送，江流不作聲。',48,'全唐诗/poet.song.172000.json','["山色忽相送，江流不作聲。", "別懷初酒醒，病骨更寒侵。", "一笑已昨夢，百年明此心。", "故人應念我，數肯寄嘉音。"]'),
('9a11be21-2059-43ef-bcf9-e8ad315ea5e1','寄李允蹈','孫應時','宋','宋诗','song-poetry','','[]','相遇吳陵日，如登單父臺。',48,'全唐诗/poet.song.172000.json','["相遇吳陵日，如登單父臺。", "了知心尚在，不忍首重回。", "明月人千里，春風酒一杯。", "緘詩憑驛使，持當嶺頭梅。"]'),
('048c45ee-a703-4c33-9b01-8f6ce73f8f41','舟中晚思','孫應時','宋','宋诗','song-poetry','','[]','山郡寒仍少，江村晚易昏。',48,'全唐诗/poet.song.172000.json','["山郡寒仍少，江村晚易昏。", "梅花渾雪色，樹影半雲根。", "遠役竟何事，壯懷誰與論。", "布帆無恙在，長嘯下荆門。"]'),
('9dbfbd05-0646-41a0-8d87-5c87cfd2676d','寄王明叔提幹  其一','孫應時','宋','宋诗','song-poetry','','[]','萬里錦官城，經年託友生。',48,'全唐诗/poet.song.172000.json','["萬里錦官城，經年託友生。", "笑談元不數，心迹故難并。", "別酒梅花粲，追途江月明。", "書來猶繾綣，三歎故人情。"]'),
('6ab6d820-7478-4886-a543-18a159a98595','寄王明叔提幹  其二','孫應時','宋','宋诗','song-poetry','','[]','我去日以遠，君留誰與居。',48,'全唐诗/poet.song.172000.json','["我去日以遠，君留誰與居。", "難忘疇昔意，故有聖賢書。", "窗几深瀟洒，塵埃痛掃除。", "入官紛萬事，濠上有游魚。"]'),
('c4eec0df-6e5c-417c-ac22-ab89d4cf77fa','三月八日挈家赴官常熟','孫應時','宋','宋诗','song-poetry','','[]','又別吾廬去，從今復幾回。',48,'全唐诗/poet.song.172000.json','["又別吾廬去，從今復幾回。", "宦情真漫爾，世路亦悠哉。", "事業魚千里，文章水一不。", "公田定難必，早擬賦歸來。"]'),
('5abf71cc-6432-4455-ac1b-ba7dff8fadfa','九日偕同寮至破山還飲誓清亭是日早雨尋霽自余至官三見菊花節常會於誓清因成二詩志之  其一','孫應時','宋','宋诗','song-poetry','','[]','佳節强人意，清樽洗俗愁。',48,'全唐诗/poet.song.172000.json','["佳節强人意，清樽洗俗愁。", "乍收桐葉雨，放出菊花秋。", "眼底山川勝，吟邊草樹幽。", "西風還正帽，一笑憶荆州。"]'),
('0f726710-d885-474a-8e4a-1a1de55b0afe','九日偕同寮至破山還飲誓清亭是日早雨尋霽自余至官三見菊花節常會於誓清因成二詩志之  其二','孫應時','宋','宋诗','song-poetry','','[]','九日仍良宴，三年記此亭。',48,'全唐诗/poet.song.172000.json','["九日仍良宴，三年記此亭。", "寒花還粲粲，衰鬢轉星星。", "薄宦驚離合，浮生任醉醒。", "明年應話我，千里越山青。"]'),
('a9089ced-ca05-4bb3-b546-c5fcdfc89253','送別舜卿少府  其一','孫應時','宋','宋诗','song-poetry','','[]','官似南昌隠，人傳東野詩。',48,'全唐诗/poet.song.172000.json','["官似南昌隠，人傳東野詩。", "才優解牛刃，筆妙畫沙錐。", "談笑千人敵，飛勝萬里期。", "大門香一炷，他日看揚眉。"]'),
('ef6ef82e-0731-494f-a18c-df8514c8da7e','送別舜卿少府  其二','孫應時','宋','宋诗','song-poetry','','[]','人道琴川上，年來聚德星。',48,'全唐诗/poet.song.172000.json','["人道琴川上，年來聚德星。", "端能幾日月，已復散雲萍。", "老我頭先白，期君眼最青。", "時能遣佳句，千時慰林坰。"]'),
('f0e7d6d3-f7f0-4887-babc-ec339f9857eb','送蘇贊府梵滿秩','孫應時','宋','宋诗','song-poetry','','[]','今日崔斯立，先門蘇少公。',48,'全唐诗/poet.song.172000.json','["今日崔斯立，先門蘇少公。", "九流清似鏡，一坐凜生風。", "傾蓋難爲別，揮毫記所蒙。", "琳琅誰具薦，早獻大明宮。"]'),
('d0d50727-10de-486e-b6c5-86238790a901','寄孫正字','孫應時','宋','宋诗','song-poetry','','[]','萬里來還去，能忘問啟居。',48,'全唐诗/poet.song.172000.json','["萬里來還去，能忘問啟居。", "休尋弔湘賦，早就過江書。", "身健何妨晚，名高勿苦疎。", "房湖風雨榻，獨夜意何如。"]'),
('9cbfa561-a381-4d82-ad31-63689bce3abe','春日書事','孫應時','宋','宋诗','song-poetry','','[]','老與春無分，慵於世轉疎。',48,'全唐诗/poet.song.172000.json','["老與春無分，慵於世轉疎。", "不陪年少飲，久絕故人書。", "筆研蛛絲底，家山蝶夢餘。", "海棠花正發，風雨定何如。"]'),
('5ad82faa-ca36-4b11-b08f-190fa4c42e67','新毗陵守王立之書來以詩答之蜀中同寮也','孫應時','宋','宋诗','song-poetry','','[]','俯仰三年夢，差池萬里歸。',48,'全唐诗/poet.song.172000.json','["俯仰三年夢，差池萬里歸。", "雙魚蒙記憶，五馬慶光輝。", "且說還家樂，休論與世違。", "平生歲寒約，搔首重依依。"]'),
('c29fcb01-f5e2-4111-8df9-da872a37c00f','和答周次山送行  其一','孫應時','宋','宋诗','song-poetry','','[]','衡宇歸來後，缾儲不願餘。',48,'全唐诗/poet.song.172000.json','["衡宇歸來後，缾儲不願餘。", "興公遂初賦，叔夜絕交書。", "已怯傷弓翼，猶歡涸澈魚。", "春風到蘭室，隠几正如如。"]'),
('c51fc7ee-5ea3-4341-9660-582a7d8d3175','和答周次山送行  其二','孫應時','宋','宋诗','song-poetry','','[]','我失從君別，君應話我歸。',48,'全唐诗/poet.song.172000.json','["我失從君別，君應話我歸。", "親年渾鶴髮，家具只牛衣。", "耳不關時論，心知悟昨非。", "晨羞何所欠，菜甲雨新肥。"]'),
('ba816922-ebdf-4260-8b47-7d6675004c51','和答周次山送行  其三','孫應時','宋','宋诗','song-poetry','','[]','籍甚多聞友，非徒一字師。',48,'全唐诗/poet.song.172000.json','["籍甚多聞友，非徒一字師。", "可人徐孺子，愛客鄭當時。", "苦意頻携酒，相過共話詩。", "瓊瑶何日報，松竹歲寒期。"]'),
('9c525102-0d90-45a8-9785-23022fb5b7b4','挽徐居厚寺簿  其一','孫應時','宋','宋诗','song-poetry','','[]','海內標元禮，毫端跨子長。',48,'全唐诗/poet.song.172000.json','["海內標元禮，毫端跨子長。", "學如開武庫，材可壯明堂。", "憂患雙蓬鬢，功名一郡章。", "汗青須好傳，公死未應亡。"]'),
('745d82cb-2f1a-4aed-a16e-e77d376c7571','挽徐居厚寺簿  其二','孫應時','宋','宋诗','song-poetry','','[]','始見偏何晚，新知不太深。',48,'全唐诗/poet.song.172000.json','["始見偏何晚，新知不太深。", "書來渾一束，情厚有兼金。", "悄悄中宵別，哀哀萬古心。", "有懷終掛剣，雪涕獨難禁。"]'),
('48c104eb-985c-4e84-badc-b9305f31ebf4','挽周南夫寺簿  其一','孫應時','宋','宋诗','song-poetry','','[]','越絕佳巖壑，由來說剡中。',48,'全唐诗/poet.song.172000.json','["越絕佳巖壑，由來說剡中。", "風流應未遠，人物正推公。", "遽作辰龍夢，真疑冀馬空。", "慶源端有屬，列戟看西東。"]'),
('a7738081-0010-4954-afd6-772adf6dabb3','挽周南夫寺簿  其二','孫應時','宋','宋诗','song-poetry','','[]','袖手何淹久，神情愈澹然。',48,'全唐诗/poet.song.172000.json','["袖手何淹久，神情愈澹然。", "琴書消永日，齒髮任流年。", "落落平生事，區區九寺聯。", "時人空歎息，寧足盡公賢。"]'),
('2f19acd1-7984-4e3e-aacb-8fee8349473a','挽周南夫寺簿  其三','孫應時','宋','宋诗','song-poetry','','[]','早歲儒風唱，中年德望尊。',48,'全唐诗/poet.song.172000.json','["早歲儒風唱，中年德望尊。", "行藏真玉潔，容色自春溫。", "天與清名賸，人欽大雅存。", "寥寥今孰繼，積慶在于門。"]'),
('0b6ba1c2-7ef9-4d77-9175-046cb26c31aa','挽周南夫寺簿  其四','孫應時','宋','宋诗','song-poetry','','[]','獄寺平反助，儀曹簿正明。',48,'全唐诗/poet.song.172000.json','["獄寺平反助，儀曹簿正明。", "嘉猷新入告，天語重恩榮。", "起滯方如此，論功百未成。", "茫茫天理昧，歎惜恨難平。"]'),
('31f71452-045a-4a06-b214-5af13b3f9db9','挽方躬明運使  其一','孫應時','宋','宋诗','song-poetry','','[]','少學真山立，中年久陸沉。',48,'全唐诗/poet.song.172000.json','["少學真山立，中年久陸沉。", "斗牛光淡蕩，湖海氣雄深。", "晚節儲邊策，平生許國心。", "嗚呼死諸葛，松柏坐蕭森。"]'),
('99a8b84d-251b-4868-bb4c-13a7da2a51fd','挽方躬明運使  其二','孫應時','宋','宋诗','song-poetry','','[]','經濟書生意，功名世路難。',48,'全唐诗/poet.song.172000.json','["經濟書生意，功名世路難。", "三言能有虎，一簣不成山。", "春雨淮田沃，秋風楚塞單。", "空餘公論在，往事杳誰攀。"]'),
('5f234dd5-12aa-43c5-ba59-51e9a89743ad','挽錢仲耕運使  其一','孫應時','宋','宋诗','song-poetry','','[]','樂易無畦畛，寬平不細苛。',48,'全唐诗/poet.song.172000.json','["樂易無畦畛，寬平不細苛。", "人才隨世狹，時望獨公多。", "獻納開丹禁，風神照紫荷。", "誰令終遠外，百歲轉蓬科。"]'),
('9dab5c98-60f4-4c1f-b2b0-e16aafc511c2','挽錢仲耕運使  其二','孫應時','宋','宋诗','song-poetry','','[]','瀕海安鹽筴，潢池息盜兵。',48,'全唐诗/poet.song.172000.json','["瀕海安鹽筴，潢池息盜兵。", "上常高計畫，公不謂功名。", "惻怛憂民志，驅馳報國情。", "雙溪最遺愛，歌頌未收聲。"]'),
('7532ebde-1737-436d-88e5-508e371fae2f','挽錢仲耕運使  其三','孫應時','宋','宋诗','song-poetry','','[]','族廩規模大，鄉評德義尊。',48,'全唐诗/poet.song.172000.json','["族廩規模大，鄉評德義尊。", "家傳忠孝舊，國頼典刑存。", "曷不登三壽，嗟誰起九原。", "晚生長自恨，早失拜龍門。"]'),
('3dd20f22-9bb2-4dec-885b-fded7c028eb8','挽沈叔晦國錄  其一','孫應時','宋','宋诗','song-poetry','','[]','人物今能幾，公才誰不如。',48,'全唐诗/poet.song.172000.json','["人物今能幾，公才誰不如。", "時情容見嫉，天意亦成虛。", "千載格心學，平生流涕書。", "一言終不吐，寒日閉幽墟。"]'),
('3dd53909-5474-4326-8142-c26e41c3e67e','挽沈叔晦國錄  其二','孫應時','宋','宋诗','song-poetry','','[]','庭諍汲長孺，官師蕭望之。',48,'全唐诗/poet.song.172000.json','["庭諍汲長孺，官師蕭望之。", "士能令國重，吾意匪公誰。", "朱紱江湖遠，蒼顔疾病衰。", "堂堂竟如此，造物爾胡爲。"]'),
('624b5000-9b8a-4f4a-9b35-ca004cc0320f','挽沈叔晦國錄  其三','孫應時','宋','宋诗','song-poetry','','[]','請益從公久，忘年愛我深。',48,'全唐诗/poet.song.172000.json','["請益從公久，忘年愛我深。", "龍阿星斗氣，梅竹雪霜心。", "回首南湖侶，傷懷流水音。", "九原那可作，千里坐悲吟。"]'),
('2104e433-8ea7-41a8-b9f0-d4f49063670d','挽劉宣義  其一','孫應時','宋','宋诗','song-poetry','','[]','歎息經綸策，山林棄此翁。',48,'全唐诗/poet.song.172000.json','["歎息經綸策，山林棄此翁。", "獨餘平日事，全見古人風。", "蘭玉家庭美，詩書歲晚功。", "閭門他日過，人說漢于公。"]'),
('eabdfb49-599d-4ae7-9c5c-eb1ecae06ad8','挽劉宣義  其二','孫應時','宋','宋诗','song-poetry','','[]','令子論交重，三年爲此來。',48,'全唐诗/poet.song.172000.json','["令子論交重，三年爲此來。", "儀容親几杖，笑語侍尊罍。", "今日臨歸路，傷心哭夜臺。", "善人常罕見，寧獨爲公哀。"]'),
('f290adab-fc04-4647-a6d3-364b2cadc4a3','挽應宣義','孫應時','宋','宋诗','song-poetry','','[]','書史平生好，山林歲晚心。',48,'全唐诗/poet.song.172000.json','["書史平生好，山林歲晚心。", "逸才逢世偶，清譽服人深。", "有子能攀桂，傳家匪遺金。", "佳城合雙劍，松柏舊蕭森。"]'),
('4a1921bf-77e0-4a00-ac85-19ddbe010b25','上皇八十慶壽赦書至海陵敬成三十二韵','孫應時','宋','宋诗','song-poetry','','[]','禹跡乾坤舊，堯天日月新。',288,'全唐诗/poet.song.172000.json','["禹跡乾坤舊，堯天日月新。", "龍躔臨丙午，鳳曆首庚辰。", "卦直三陽泰，時通萬物屯。", "暖音鳴嶰律，淑氣鼓鴻鈞。", "奕葉炎精旺，重光帝位真。", "昌期周一紀，正統接千春。", "盛事當今最，閎休受命申。", "慈皇躋八秩，天子壽雙親。", "寶冊尊名衍，璇霄慶典陳。", "昕朝移警蹕，法仗翼簪紳。", "晴日明黄道，和風度紫宸。", "歡聲擁都市，喜色動君臣。", "陛戟三呼迥，簫韶九奏均。", "玉巵前肅穆，天語聽溫淳。", "拜舞班行退，郵傳詔令諄。", "豐章加等列，曠澤浹兵民。", "三殿承顔邃，重孫奉酒頻。", "歡娛留晷景，跪起用家人。", "禮樂清都表，輝華率土濱。", "儀刑知子職，命賜侈君仁。", "即事論今昔，儲祥軼混淪。", "陶姚非與子，文武尚臣辛。", "笑樂徒夸漢，規爲陋襲秦。", "大安慙養志，西內益傷神。"]'),
('d6e7e7f1-dc1c-462d-a445-06a4d2a56108','送朱仲微使君赴闕','孫應時','宋','宋诗','song-poetry','','[]','聲迹周行舊，人門漢相延。',264,'全唐诗/poet.song.172000.json','["聲迹周行舊，人門漢相延。", "謝宗康樂在，阮姪仲容賢。", "文獻羣公側，風流晚輩先。", "天資超瑑玉，心量極澄淵。", "世故雖遊刃，榮途獨緩鞭。", "風霜飽經歷，歲月起聯翩。", "奏牘留天聽，鳴鑣拜日邊。", "一麾紆郡組，兩地冠淮壖。", "巢塢江湖會，吳陵海澤偏。", "陽公優撫字，山甫重蕃宣。", "秋月滄浪底，春風草木前。", "近名辭赫赫，直道守平平。", "襦袴歌千里，絲綸錫九天。", "別帆催入覲，祖席歎登仙。", "詳試諳馮翊，深褒屬潁川。", "徑須持紫橐，應不墜青氈。", "世道千齡遠，人情百慮牽。", "關心眷河雒，努力補陶甄。", "窶迹來蓬篳，微芳託蕙荃。", "一枝容吏隠，三鬴慰親年。", "借寇知難請，依劉敢自憐。", "鑪錘思舊物，倘問及林泉。"]'),
('7a7c70b8-6001-494a-a3af-bf11482b5c93','挽汪克之給事母程夫人','孫應時','宋','宋诗','song-poetry','','[]','黟水衣冠盛，汪程甲一州。',168,'全唐诗/poet.song.172000.json','["黟水衣冠盛，汪程甲一州。", "世賢鍾上壽，家範襲芳休。", "右府尊章重，嬪閨法度修。", "蘋蘩祗祀事，枌堇媚肴羞。", "勤約饒經理，慈祥徧撫柔。", "齊眉友琴瑟，斷織戒箕裘。", "郗桂遇輝赫，潘輿飽宦游。", "金章嚴侍膝，綵服稱遨頭。", "疊嶂雙溪曉，千巖萬壑秋。", "平反間笑語，燕喜溢歌謳。", "九秩童顔在，三朝寵渥稠。", "一毫寧復憾，五福更誰儔。", "鸞影合塵鑑，龍藏樂故丘。", "高門餘善慶，衮衮正公侯。"]'),
('42c2717c-5c17-4718-b8ec-7d535b6a00c7','趙仲禮示達菴唱酬次韵','孫應時','宋','宋诗','song-poetry','','[]','旭旦羣陰豁，春陽萬壑融。',168,'全唐诗/poet.song.172000.json','["旭旦羣陰豁，春陽萬壑融。", "八荒雙眼界，千聖一家風。", "不必尋玄妙，寧須泥苦空。", "本來無見解，何處覓神通。", "穀粟饑爲藥，雷霆聽或聾。", "鳶魚均自適，虎鼠竟誰雄。", "軒冕因時貴，簞瓢有命窮。", "詩書休發冢，談笑任關弓。", "陶令琴三弄，徐公酒一中。", "浮雲容易改，明月古今同。", "上達真無累，纖瑕早自攻。", "論心逢益友，刮目慶新功。", "臺閣須公子，山林付老翁。", "歲寒尋此話，一笑燭湖東。"]'),
('4378c96e-ee41-42a4-abcd-c1ffac1347c7','陪戎州范守閻倅飲涪翁溪紀事','孫應時','宋','宋诗','song-poetry','','[]','元祐人何負，黄郎昔此居。',216,'全唐诗/poet.song.172000.json','["元祐人何負，黄郎昔此居。", "江山愁思裏，風景醉吟餘。", "問俗夸遺事，開荒想舊廬。", "巖姿自奇怪，谷響故清虛。", "鳥語傳沽酒，猿吟憶荷鋤。", "文章喧宇宙，談笑狎樵漁。", "小德長携杖，元明闕寄書。", "生涯竟流落，謗譽久乘除。", "士固難逃世，天寧獨困渠。", "朝廷重日月，河雒痛丘墟。", "事往真云已，神遊信所於。", "溪名雖發越，林影尚蕭疎。", "佳致歸商畧，成規易補苴。", "春堤要楊柳，夏渚待芙蕖。", "名勝新開府，風流得貳車。", "追遊方自此，雅尚不愁予。", "天際歸舟遠，江干摻袂初。", "明年記狂客，萬里報何如。"]'),
('82118348-6ff7-4dfc-bde8-21dd8a6a9627','祐姪初赴鄉舉吾家讀書三世至此姪纔七人作十八韵誨之','孫應時','宋','宋诗','song-poetry','','[]','家學今三世，儒流甫七人。',216,'全唐诗/poet.song.172000.json','["家學今三世，儒流甫七人。", "生涯元窶悴，存沒幾酸辛。", "父幹真吾責，孫枝見汝新。", "提携從總丱，成長及冠巾。", "幸有源流正，應先器質醇。", "緒餘雖耳染，緣飾匪天真。", "黄卷心懷古，青燈坐達晨。", "定無錢使鬼，當見筆如神。", "科目誠沿襲，朝家重選掄。", "桂分清夜月，花趁曲江春。", "此日雲霄路，他年柱石臣。", "成功期濟世，私喜固榮親。", "俗薄堪長笑，才輕不自珍。", "胮肛誇小技，屑窣較微塵。", "努力初濡翰，馳心謹問津。", "利名卑汲汲，教誨實諄諄。", "莫濫齊庭吹，空慙越里顰。", "裁詩不盡意，持付合書紳。"]'),
('80cbd37e-9952-45f0-8b4b-24b3dfe3a29f','恭和家大人鬻田訓子詩韵','孫應時','宋','宋诗','song-poetry','','[]','凶年滿目竈無烟，糴貴家貧且鬻田。',64,'全唐诗/poet.song.172000.json','["凶年滿目竈無烟，糴貴家貧且鬻田。", "雖暫憂饑茅屋下，終期射策玉墀前。", "文辭華實宜撐腹，際運窮通一任天。", "有志會須能卒事，豈令久困握空拳。"]'),
('84ee03dd-1699-4647-b1b6-b7a753ec44bc','二月二十五日同趙景孟胡晉遠遊四明山','孫應時','宋','宋诗','song-poetry','','[]','乍晴天宇瑩無塵，短策輕衫發興新。',64,'全唐诗/poet.song.172000.json','["乍晴天宇瑩無塵，短策輕衫發興新。", "過鳥一聲如勸客，青山萬疊總迎人。", "回頭便與氛埃隔，入眼真於水石親。", "盡意登臨休計日，此行端不負芳春。"]'),
('216442b8-bd69-4d38-ad9d-bb288207325f','杖錫山','孫應時','宋','宋诗','song-poetry','','[]','萬杉夾道磴千盤，巖水溪風徹骨寒。',64,'全唐诗/poet.song.172000.json','["萬杉夾道磴千盤，巖水溪風徹骨寒。", "坐久雲煙過庭角，睡餘星斗轉闌干。", "登臨不盡山川險，景物無窮世界寬。", "會得人生安樂法，不須禪板與蒲團。"]'),
('ccea16c2-848a-4014-a562-a0a9a1272d71','和景孟宿山中','孫應時','宋','宋诗','song-poetry','','[]','倦行白雨翠雲中，投宿禪房聽曉鐘。',64,'全唐诗/poet.song.172000.json','["倦行白雨翠雲中，投宿禪房聽曉鐘。", "彈壓山川詩未老，留連巖壑興何濃。", "回看塵世頻三歎，上徹天關更幾重。", "徑欲乘風此仙去，時時笙鶴下前峰。"]'),
('a6765e94-1df3-48a6-9a3f-ed0170c15bbc','登仙木','孫應時','宋','宋诗','song-poetry','','[]','劉樊蟬蛻此登仙，老木當年已插天。',64,'全唐诗/poet.song.172000.json','["劉樊蟬蛻此登仙，老木當年已插天。", "玉骨半枯猶秀潤，蒼皮新長已榮鮮。", "蟠桃時熟三千歲，銅狄重摩五百年。", "化鶴未歸山寂寂，徘徊誰與問因緣。"]'),
('56863275-0f04-4ca4-a963-ada5a04206a5','和景孟山行','孫應時','宋','宋诗','song-poetry','','[]','翛然身在妙高峰，下有雷霆走白龍。',64,'全唐诗/poet.song.172000.json','["翛然身在妙高峰，下有雷霆走白龍。", "已覺仙風換肌骨，更無塵土到心胸。", "悠悠今古三千劫，莽莽山川幾萬重。", "雲北雲南一長嘯，爲留餘響振巖松。"]'),
('9cefcd6f-0c92-4d46-a85b-0ef5c3553efe','雪竇妙高峰詩','孫應時','宋','宋诗','song-poetry','','[]','絕壑高崖面面雄，一峰孤起白雲中。',64,'全唐诗/poet.song.172000.json','["絕壑高崖面面雄，一峰孤起白雲中。", "山連飛瀑斜通寺，人在危亭半倚空。", "把酒登臨非易得，題詩摹寫最難工。", "誰知妙意無窮盡，都在幽人一笛風。"]'),
('2e481954-8b84-4b68-b2c0-cd3bd8bb9fd0','尉黄巖任滿家大人先歸作詩以示恭次元韵','孫應時','宋','宋诗','song-poetry','','[]','瓜熟青門好去官，此身如繫欲行難。',64,'全唐诗/poet.song.172000.json','["瓜熟青門好去官，此身如繫欲行難。", "望隨鴻鴈春風北，夢繞庭闈夜月寒。", "即是抱琴歸栗里，未能騎馬向長安。", "蕭條甘旨應無計，好在藜羹日厭餐。"]'),
('f48fa393-0ea8-45b2-afab-19c92d4f0044','恭次家大人初抵海陵官舍元韵  其一','孫應時','宋','宋诗','song-poetry','','[]','扁舟祖餞出西陵，千里經行小作程。',64,'全唐诗/poet.song.172000.json','["扁舟祖餞出西陵，千里經行小作程。", "樽俎笑談多雅故，江湖霜日久晴明。", "只今斗室寒廳夜，任聽回風急雪聲。", "天報雙親占後福，絕交何畏孔方兄。"]'),
('71abe564-ed9e-4f69-b94c-043c647fd686','恭次家大人初抵海陵官舍元韵  其二','孫應時','宋','宋诗','song-poetry','','[]','灌園何必學於陵，吾事胸中有準程。',64,'全唐诗/poet.song.172000.json','["灌園何必學於陵，吾事胸中有準程。", "三鬴宦游甘寂寞，百年心迹定分明。", "逍遥朱墨塵埃外，娛戲文章金石聲。", "侍奉親闈有餘樂，不慙宜弟更宜兄。"]'),
('55bd823e-351d-4c5e-8dbe-ab39fe8c1773','恭次家大人初抵海陵官舍元韵  其三','孫應時','宋','宋诗','song-poetry','','[]','風饕雪虐苦侵陵，已免寒舟問水程。',64,'全唐诗/poet.song.172000.json','["風饕雪虐苦侵陵，已免寒舟問水程。", "葦屋虛簷交夜氣，邊城疎鼓逗天明。", "囊空尚可充饑色，官冷何妨遠市聲。", "且辦新篘供一笑，竹君清絕對梅兄。"]'),
('7c072697-33a1-40cd-b609-e052f7707dac','仲兄生日家大人作詩恭次元韵','孫應時','宋','宋诗','song-poetry','','[]','恭承弧矢射芳晨，三紀風光又一春。',64,'全唐诗/poet.song.172000.json','["恭承弧矢射芳晨，三紀風光又一春。", "深喜團圞娛父母，何當合沓燕賓親。", "百年好共成門戶，千萬寧憂欠宅鄰。", "滿酌期兄增壯志，相携平步上星辰。"]'),
('e74f5038-3a3c-4359-8cd8-daef6973791b','邑人李子寬公綽以所著十說及論孟解相示極有可敬而老且貧只一子又喪之遂爲無告之民復以詩見投覽之悽然贈以八句','孫應時','宋','宋诗','song-poetry','','[]','少日胸中萬丈虹，著書老尚有新功。',64,'全唐诗/poet.song.172000.json','["少日胸中萬丈虹，著書老尚有新功。", "同鄉我惜知君晚，善士天胡賦此窮。", "無槨去年悲孔鯉，有家何地客梁鴻。", "秋風蕭瑟行吟裏，應有中郎識爨桐。"]'),
('1d2041cf-7eb8-42ff-82bf-a5268bf917db','用韵贈李恭父','孫應時','宋','宋诗','song-poetry','','[]','浮雲富貴適堪憐，烈士襟期定不然。',64,'全唐诗/poet.song.172000.json','["浮雲富貴適堪憐，烈士襟期定不然。", "拭目去爲三島客，此心莫負九重天。", "雖云小草容同味，敢與昌陽較引年。", "下直如尋故人夢，書來同我釣魚船。"]'),
('470c994d-cd97-489a-9eab-44d247d488bc','贈策選軍將張仲舉其父故居吾鄉與先君游也','孫應時','宋','宋诗','song-poetry','','[]','鐵馬橫戈三十秋，天涯肯忘舊交遊。',64,'全唐诗/poet.song.172000.json','["鐵馬橫戈三十秋，天涯肯忘舊交遊。", "看君材氣萬人敵，何日關河一戰收。", "判把身心專報國，不憂骨相晚封侯。", "尊前感動書生恨，聽說當年下宿州。"]'),
('0a6bc064-4353-46ba-96e2-d7080c73731f','贈杜子真','孫應時','宋','宋诗','song-poetry','','[]','軒然意氣决浮雲，見子真堪辟楚氛。',64,'全唐诗/poet.song.172000.json','["軒然意氣决浮雲，見子真堪辟楚氛。", "未許坐馳能萬里，故應守約對三軍。", "磨礲心事須經歷，斟酌人情有見聞。", "且辦工夫成郢質，可無老手爲揮斤。"]'),
('7cb0a92a-5af4-48c3-b2bf-a02e4cf49c13','送趙舜臣知溫州','孫應時','宋','宋诗','song-poetry','','[]','閩嶺淮堧憶細侯，更煩東作謝公州。',64,'全唐诗/poet.song.172000.json','["閩嶺淮堧憶細侯，更煩東作謝公州。", "清規已出百城上，仁氣便銷千里愁。", "好去綵衣娛壽斚，歸來紫橐奉宸旒。", "馬前鴈蕩風煙裏，幾許新詩答素秋。"]'),
('8b0b6001-21e7-4d4c-83ae-e861695029a3','黄巖鄭瀛子仙弱冠入太學五上書論時事以直聞於時老猶不衰客游海陵館於余一月乃去作詩送之鄭方謀少官田故有章末之戲','孫應時','宋','宋诗','song-poetry','','[]','分手三年不易逢，一觴淮海酹西風。',64,'全唐诗/poet.song.172000.json','["分手三年不易逢，一觴淮海酹西風。", "書生君獨憂當世，末路人誰識此翁。", "故國青山愁夜鶴，孤舟白髮映秋蓬。", "歸歟束縛公車疏，努力豚蹄祝歲豐。"]'),
('08ae00e9-528c-4dd3-9f2d-0997fb67a117','和答吳尉俞灝商卿見贈因用韵送行','孫應時','宋','宋诗','song-poetry','','[]','去去瀛洲蛻骨仙，舊游還似九江傳。',64,'全唐诗/poet.song.172000.json','["去去瀛洲蛻骨仙，舊游還似九江傳。", "塵埃下視三千界，文字勤追二百年。", "宦達有時聊爾耳，才難自古不其然。", "臨分更吐平生話，有底閒愁到酒邊。"]'),
('a495219d-89a4-4af4-8e47-624db2e2b686','送池子文','孫應時','宋','宋诗','song-poetry','','[]','巾山秋思俯晴江，樽酒懷人惜異邦。',64,'全唐诗/poet.song.172000.json','["巾山秋思俯晴江，樽酒懷人惜異邦。", "千里誰能携客枕，一燈還此對寒窗。", "聖門莫忘心期遠，文鼎何妨筆力扛。", "去去成名深自警，白雲飛處倚門雙。"]'),
('68373093-edd4-4650-9810-215d0c787751','再和商卿','孫應時','宋','宋诗','song-poetry','','[]','近識城南吳市仙，千巖活句得真傳。',64,'全唐诗/poet.song.172000.json','["近識城南吳市仙，千巖活句得真傳。", "令人向壁卧三日，悔我讀書空十年。", "樽酒細論還得否，風帆欲去獨依然。", "從今千里清秋夢，長在高山流水邊。"]'),
('96f4c149-c348-4463-9f91-d236e0b8e6eb','九日與沈叔晦季文王仲舉登鄞城','孫應時','宋','宋诗','song-poetry','','[]','城上西風草欲霜，登臨聊不負重陽。',64,'全唐诗/poet.song.172000.json','["城上西風草欲霜，登臨聊不負重陽。", "江山遠近秋容老，雲樹參差野意長。", "一笑四人真莫逆，百年此會定難忘。", "不妨小學陶公醉，籬下寒花恰半香。"]'),
('ab449674-88d4-4f38-a32d-94f0f177c90e','送李文授知括蒼','孫應時','宋','宋诗','song-poetry','','[]','中興尚有名臣子，江表能餘正始音。',64,'全唐诗/poet.song.172000.json','["中興尚有名臣子，江表能餘正始音。", "擬贊經綸須老手，更分符竹此何心。", "麒麟閣上風雲舊，烟雨樓前山水深。", "世事由來偶然耳，公餘端不廢清吟。"]'),
('82c854a9-4a5f-4037-b24d-36c1e31f38a3','送別常叔度知縣  其一','孫應時','宋','宋诗','song-poetry','','[]','一廛誰問野人居，三徑重迂長者車。',64,'全唐诗/poet.song.172000.json','["一廛誰問野人居，三徑重迂長者車。", "不訝經年忘造請，應憐畏影正逃虛。", "舉頭鳬舄雙飛去，送目鵬霄萬里初。", "青瑣黄扉對宮燭，相思肯寄一行書。"]'),
('4e9999d4-d745-49e3-bf1a-f4a909826d02','送別常叔度知縣  其二','孫應時','宋','宋诗','song-poetry','','[]','一朝傾蓋更傾心，頗畏人驚語太深。',64,'全唐诗/poet.song.172000.json','["一朝傾蓋更傾心，頗畏人驚語太深。", "乍可陶廬煩送酒，難堪偃室傍鳴琴。", "君今此去班羣玉，我亦何言託斷金。", "啼鴂飛花春又了，蕭蕭風雨卧山林。"]'),
('bfe9eddd-b80f-4010-8846-6bb2112c42a4','送別常叔度知縣  其三','孫應時','宋','宋诗','song-poetry','','[]','世緣傷巧亦傷多，萬古浮雲瞬息過。',64,'全唐诗/poet.song.172000.json','["世緣傷巧亦傷多，萬古浮雲瞬息過。", "唯有平心供日用，妙於養氣發天和。", "細看局度兼諸老，誰道人才各一科。", "卓魯從來公輔器，攀轅卧轍奈君何。"]'),
('18593f2f-962d-4138-929c-704c36fce042','梅花','孫應時','宋','宋诗','song-poetry','','[]','眼明那得許精神，爲問凡花隔幾塵。',64,'全唐诗/poet.song.172000.json','["眼明那得許精神，爲問凡花隔幾塵。", "雪月故爲三益友，乾坤又付一番春。", "詩情消得吟成瘦，畫手終應苦未真。", "於我心期獨何事，小窗清夜絕相親。"]'),
('706e881b-8016-4f2b-a620-9eb69db487ff','陳傳朋和余梅花舊作余再賦此','孫應時','宋','宋诗','song-poetry','','[]','肌膚冰雪定何神，不用靈犀自辟塵。',64,'全唐诗/poet.song.172000.json','["肌膚冰雪定何神，不用靈犀自辟塵。", "一笑未妨娛獨夜，百花誰敢鬭先春。", "孤山詩侶須君復，吳市仙蹤只子真。", "此外紛紛莫相汙，風姨月姊故情親。"]'),
('bce0f226-c322-4eab-86cd-774ab735fb8d','鄞城通守廳和潘文叔梅花韵','孫應時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','未將春草貯鳴蛙，寂寞西湖處士家。',64,'全唐诗/poet.song.172000.json','["未將春草貯鳴蛙，寂寞西湖處士家。", "正喜數枝斜更好，聊沽一醉醒還賒。", "骨清是我氷霜侶，心賞從渠錦繡華。", "不厭相過娛夜永，摘芳和雪試煎茶。"]'),
('6d39fe9e-5b60-48a8-bbed-f79d90682100','鄞中和張世隆總管春曉即事','孫應時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春欲歸時豈得留，杜鵑聲裏翠陰稠。',64,'全唐诗/poet.song.172000.json','["春欲歸時豈得留，杜鵑聲裏翠陰稠。", "柳橋總是千絲恨，花徑真成萬點愁。", "東土雲山供我老，西湖風月稱公遊。", "相逢一笑難重覓，急趁餘芳醉玉舟。"]'),
('d46f4a3d-9e17-453b-8dbf-b81aa7e7f8cb','送明守黄子由尚書赴召','孫應時','宋','宋诗','song-poetry','','[]','燈火笙歌別海壖，詔書歸覲九重天。',64,'全唐诗/poet.song.172000.json','["燈火笙歌別海壖，詔書歸覲九重天。", "已將清浄安齊國，不使聲名減潁川。", "題品人才看贊贊，扶持皇極在平平。", "文星舊與文昌亞，今貫三台更炳然。"]'),
('3cab66d9-dccc-43d5-8d14-f3c454d6f3dd','石龜古梅','孫應時','宋','宋诗','song-poetry','','[]','妙絕人間獨此逢，石龜峰下野橋東。',64,'全唐诗/poet.song.172000.json','["妙絕人間獨此逢，石龜峰下野橋東。", "亭亭玉骨氷肌子，櫛櫛蒼髯綠髮翁。", "偃蹇生懷千古意，蕭疎元是一家風。", "何妨少入時人眼，鼎鼐終論第一功。"]'),
('61479764-3aba-4887-aebb-67c3f728ca3a','與趙伯藏信叟游天衣寺','孫應時','宋','宋诗','song-poetry','','[]','渺渺湖風引桂舟，竹輿沙徑晚山稠。',64,'全唐诗/poet.song.172000.json','["渺渺湖風引桂舟，竹輿沙徑晚山稠。", "千峰影底鳴雙澗，三伏日中含九秋。", "邂逅襟期俱洒落，等閒歸計少遲留。", "何時更約雲門路，踏破青鞋布襪休。"]'),
('4650b1bf-78eb-4ec1-9357-2517ec27d0bc','雪中早起偶作','孫應時','宋','宋诗','song-poetry','','[]','年來愛雪起清晨，已汙紛紛車馬塵。',64,'全唐诗/poet.song.172000.json','["年來愛雪起清晨，已汙紛紛車馬塵。", "何似柴扉終日閉，靜看玉宇一番新。", "孤吟豈必煩餘子，小酌仍先壽我親。", "更喜豐年報消息，力田甘作太平民。"]'),
('b79d3710-8e8a-4f63-ad46-295a487e3a7e','臘月二日雪霽與王君玉榮淳甫謁山陰陸放翁夜歸','孫應時','宋','宋诗','song-poetry','','[]','十日山陰雪塞門，曉來飛霰尚紛紛。',64,'全唐诗/poet.song.172000.json','["十日山陰雪塞門，曉來飛霰尚紛紛。", "扁舟忽憶尋安道，載酒還成訪子雲。", "便喜晴湖光璀璨，何妨歸路日黄曛。", "侯家燠館多良宴，此段風流恐未聞。"]'),
('186ea96b-05f7-464c-ad0a-bcee08339943','寄馬塘范叔剛','孫應時','宋','宋诗','song-poetry','','[]','海風吹月動蒼茫，欲往從君道路長。',64,'全唐诗/poet.song.172000.json','["海風吹月動蒼茫，欲往從君道路長。", "羈羽沈鱗徒影響，秋鴻社燕各炎凉。", "紛紛忍逐塵埃盡，落落猶期日月光。", "想得清吟散愁獨，書來金薤翦琳琅。"]'),
('7fcb496f-bdd3-43a9-84b1-779c735e6f8f','西溪會范叔剛用舊所寄韵','孫應時','宋','宋诗','song-poetry','','[]','出門煙水思微茫，客裏行吟晚興長。',64,'全唐诗/poet.song.172000.json','["出門煙水思微茫，客裏行吟晚興長。", "萬里雲霄自今古，百年毛髮幾暄凉。", "人間但有詩書樂，眼底何須印綬光。", "遥夜青燈耿霜月，非君誰共語琅琅。"]'),
('416b4742-b392-4303-8ce0-80b0521636d5','芙蕖','孫應時','宋','宋诗','song-poetry','','[]','生來不著塵泥涴，天下何妨名字多。',64,'全唐诗/poet.song.172000.json','["生來不著塵泥涴，天下何妨名字多。", "一世炎凉獨風月，四時榮落付煙波。", "自知根節全冰玉，人道丰姿照綺羅。", "濯濯晨光香十里，爲君敲槳叫吳歌。"]'),
('962b492b-a9d2-42f8-9e1f-848baf5fa8e7','陳正叔縣尉見示所著詩文以詩謝之','孫應時','宋','宋诗','song-poetry','','[]','文章千古一毫端，妙處工夫到底難。',64,'全唐诗/poet.song.172000.json','["文章千古一毫端，妙處工夫到底難。", "春色無邊知造化，海風不斷識波瀾。", "看君健筆凌霄漢，照我清窗醒肺肝。", "寶劍莫憂人未識，光芒須動斗牛寒。"]'),
('5f5f52fd-587d-4905-a342-1c538dac3448','送陸華父歸越','孫應時','宋','宋诗','song-poetry','','[]','四海桐江陸使君，阿咸詩律更通神。',64,'全唐诗/poet.song.172000.json','["四海桐江陸使君，阿咸詩律更通神。", "時無勢力能推轂，獨使文章老斲輪。", "萬卷詩書堪遺子，千巖風月未全貧。", "青鞋布襪雲門路，雞黍容吾叩主人。"]'),
('884321f9-0030-4802-b672-1f805285131c','七月十一日大雨次日又大雨','孫應時','宋','宋诗','song-poetry','','[]','秋來大火太焚如，惱得天公痛掃除。',64,'全唐诗/poet.song.172000.json','["秋來大火太焚如，惱得天公痛掃除。", "兩夕簷聲撼江海，一番凉意洗郊墟。", "眼明還我詩書樂，骨醒從渠枕簟疎。", "明日快晴應更好，莫妨千里薦嘉蔬。"]'),
('5a2b0996-feb7-4a7e-8b09-7a06fc71995b','贈篆字高光遠秀才','孫應時','宋','宋诗','song-poetry','','[]','書家千載得陽冰，想像規模亦眼明。',64,'全唐诗/poet.song.172000.json','["書家千載得陽冰，想像規模亦眼明。", "心手相忘容力到，風姿迥出自天成。", "屠龍絕技常難售，畫虎何人浪自名。", "良苦窮途說奇字，誰能載酒似西京。"]'),
('4dbbeadf-4bc3-4205-b229-c5be55629e75','九月二十七日夜大風雨頓凉偶作','孫應時','宋','宋诗','song-poetry','','[]','五更風雨洗驕陽，滿耳秋聲撼我牀。',64,'全唐诗/poet.song.172000.json','["五更風雨洗驕陽，滿耳秋聲撼我牀。", "夢裏忽知身化羽，覺來新免汗翻漿。", "可憐團扇辭人去，便有寒蟲語夜長。", "老大幸諳時節慣，可能隨世作炎凉。"]'),
('220dc814-271a-46ca-b1ca-274b274478ff','壬子元日遂安縣學講書齒飲前此四十三年錢建爲令嘗有此集題名在壁是日詹本仁有詩余和其韵','孫應時','宋','宋诗','song-poetry','','[]','壁字塵埃四十年，滿堂還喜會羣賢。',64,'全唐诗/poet.song.172000.json','["壁字塵埃四十年，滿堂還喜會羣賢。", "是非不用論今昨，禮樂從知有後先。", "酒外山川如動色，詩成金石迭相宣。", "分陽令尹强人意，鄉飲彬彬更可傳。"]'),
('cd16ba39-b347-4b0f-bc40-52d2b98007b1','贈桐廬孫令','孫應時','宋','宋诗','song-poetry','','[]','偶然姓字齒鄉評，若誤旁人問弟兄。',64,'全唐诗/poet.song.172000.json','["偶然姓字齒鄉評，若誤旁人問弟兄。", "五斗還來作鄰社，一杯真此定宗盟。", "公懷犖犖英雄事，我獨區區丘壑情。", "便看蛟龍擘雲起，何由鴻雁作行鳴。"]'),
('b34ec439-a00d-4eaf-9e5e-0bff521c3ad3','仲兄來爲母氏壽言歸有作','孫應時','宋','宋诗','song-poetry','','[]','瀟瀟雨作對牀聲，小語燈前睡不成。',64,'全唐诗/poet.song.172000.json','["瀟瀟雨作對牀聲，小語燈前睡不成。", "詩禮一庭真自樂，江山千里若爲情。", "遠來正覺親顔喜，別去其如心事驚。", "孟氏小園能辦否，徑須歸共白鷗盟。"]'),
('2e5b1e0d-5653-4191-95e9-b324ba8512d8','十一月二十六日南至天色佳甚','孫應時','宋','宋诗','song-poetry','','[]','天心應喜一陽來，萬里寒陰曉自開。',64,'全唐诗/poet.song.172000.json','["天心應喜一陽來，萬里寒陰曉自開。", "消息早傳從嶰竹，發生先合到江梅。", "遥瞻雙闕呈雲瑞，正想三宮舞壽杯。", "草木微情共時節，思親南望獨徘徊。"]'),
('ff409865-8761-45b2-bf3c-a2154acb6bde','周次山和立春詩答之','孫應時','宋','宋诗','song-poetry','','[]','不用文章作序棋，由來人事亦天時。',64,'全唐诗/poet.song.172000.json','["不用文章作序棋，由來人事亦天時。", "且須竹葉千鍾淥，莫問菱花兩鬢絲。", "社燕秋鴻無舊影，曉猿夜鶴有餘悲。", "春來只被奚奴笑，春日吳中更幾詩。"]'),
('0fd23096-2862-4fed-85c4-2e85c1f824fc','雨中過湖','孫應時','宋','宋诗','song-poetry','','[]','煙雨平湖短棹歸，清秋休作楚詞悲。',64,'全唐诗/poet.song.172000.json','["煙雨平湖短棹歸，清秋休作楚詞悲。", "關心千里蓴鱸興，轉眼一年橘柚時。", "好景何妨閒處得，勝懷應少俗人知。", "相過拊掌有奇事，添得錦囊無數詩。"]'),
('47de3ae4-1a9d-4afb-8195-4a4f9be94c86','和答吳斗南中秋見懷并約王子合見過  其一','孫應時','宋','宋诗','song-poetry','','[]','百里平湖一夜舟，跂予東望渺離愁。',64,'全唐诗/poet.song.172000.json','["百里平湖一夜舟，跂予東望渺離愁。", "可能無意山陰雪，空復相思楚澤秋。", "宣室待君今即召，草堂移我欲歸休。", "詩來已拜千金諾，得得開帆莫轉頭。"]'),
('ebb9ac38-9268-469b-b524-a2847220f7bc','和答吳斗南中秋見懷并約王子合見過  其二','孫應時','宋','宋诗','song-poetry','','[]','歸夢千巖萬壑東，起尋蓑笠喚漁童。',64,'全唐诗/poet.song.172000.json','["歸夢千巖萬壑東，起尋蓑笠喚漁童。", "塵忙憐我三年久，撥置期君一笑同。", "只恐令嚴詩債急，不愁夜短酒杯空。", "相携更得王文度，此段風流儘未窮。"]'),
('a626934c-0421-4f9d-a5ed-05f04d19eafc','送別惟肖贊府','孫應時','宋','宋诗','song-poetry','','[]','如椽老筆健文章，枉對槐間雁鶩行。',64,'全唐诗/poet.song.172000.json','["如椽老筆健文章，枉對槐間雁鶩行。", "只共低頭了官事，忽驚舉手勸離觴。", "百年可落塵埃夢，一瓣曾薰知見香。", "珍重平生安樂法，窮通何地不徜徉。"]');
